import React, { useState, useRef, useEffect } from 'react';
import { supabase } from '../../lib/supabase';
import { API_URL } from '../../lib/api';
import { useAuth } from '../../context/AuthContext';
import { X, Image as ImageIcon, Send, Loader2, Upload } from 'lucide-react';
import { motion } from 'framer-motion';
import toast from 'react-hot-toast';
import SecureImage from '../common/SecureImage';
import './MediaUpload.css';

interface MediaUploadProps {
    conversationId: string;
    onUploadComplete: (attachmentId: string, type: string, content: string) => void;
    onCancel: () => void;
}

export const MediaUpload: React.FC<MediaUploadProps> = ({ conversationId, onUploadComplete, onCancel }) => {
    const { session } = useAuth();
    const [file, setFile] = useState<File | null>(null);
    const [previewUrl, setPreviewUrl] = useState<string | null>(null);
    const [uploading, setUploading] = useState(false);
    const [uploadProgress, setUploadProgress] = useState(0);
    const fileInputRef = useRef<HTMLInputElement>(null);
    const touchStartRef = useRef<{ x: number, y: number } | null>(null);

    // Initial Trigger for file selection if nothing is selected
    useEffect(() => {
        if (!file && fileInputRef.current) {
            // timeout to allow animation to start
            setTimeout(() => {
                // fileInputRef.current?.click();
            }, 300);
        }
    }, [file]);

    // Cleanup preview URL
    useEffect(() => {
        return () => {
            if (previewUrl) URL.revokeObjectURL(previewUrl);
        };
    }, [previewUrl]);

    // Prevent background scroll
    useEffect(() => {
        document.body.style.overflow = 'hidden';
        return () => {
            document.body.style.overflow = '';
        };
    }, []);

    const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
        const selectedFile = e.target.files?.[0];
        if (!selectedFile) return;

        const isImage = selectedFile.type.startsWith('image/');
        const isVideo = selectedFile.type.startsWith('video/');

        if (!isImage && !isVideo) {
            toast.error('Please select an image or video file');
            return;
        }

        if (selectedFile.size > 50 * 1024 * 1024) {
            toast.error('File size too large (max 50MB)');
            return;
        }

        setFile(selectedFile);
        if (previewUrl) URL.revokeObjectURL(previewUrl);
        setPreviewUrl(URL.createObjectURL(selectedFile));
    };

    const handleUpload = async () => {
        if (!file || !session) return;

        setUploading(true);
        setUploadProgress(10);
        const fileExt = file.name.split('.').pop();
        const fileName = `${Math.random().toString(36).substring(2)}.${fileExt}`;
        const filePath = `${conversationId}/${fileName}`;

        try {
            setUploadProgress(30);
            const { error: uploadError, data } = await supabase.storage
                .from('chat-media')
                .upload(filePath, file, {
                    cacheControl: '3600',
                    upsert: false
                });

            if (uploadError) throw uploadError;
            setUploadProgress(70);

            const type = file.type.startsWith('image/') ? 'image' : 'video';
            
            const res = await fetch(`${API_URL}/api/media/attachments`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${session.access_token}`
                },
                body: JSON.stringify({
                    conversationId,
                    fileName: file.name,
                    fileType: file.type,
                    fileSize: file.size,
                    storagePath: data.path,
                    metadata: {}
                })
            });

            if (!res.ok) throw new Error('Failed to create attachment record');

            const attachment = await res.json();
            setUploadProgress(100);
            
            onUploadComplete(attachment.id, type, attachment.file_name);
            toast.success('Media sent');
        } catch (err: unknown) {
            const error = err as any;
            console.error('Upload failed:', error);
            toast.error(error.message || 'Upload failed');
        } finally {
            setUploading(false);
            setUploadProgress(0);
        }
    };

    const handleTouchStart = (e: React.TouchEvent) => {
        touchStartRef.current = {
            x: e.touches[0].clientX,
            y: e.touches[0].clientY
        };
    };

    const handleTouchEnd = (e: React.TouchEvent) => {
        if (!touchStartRef.current) return;
        const deltaY = e.changedTouches[0].clientY - touchStartRef.current.y;
        if (deltaY > 100 && !uploading) {
            onCancel();
        }
        touchStartRef.current = null;
    };

    return (
        <div 
            className="media-upload-overlay"
            onClick={(e) => {
                if (e.target === e.currentTarget && !uploading) onCancel();
            }}
        >
            <motion.div 
                className="media-upload-container"
                initial={{ scale: 0.9, opacity: 0, y: 20 }}
                animate={{ scale: 1, opacity: 1, y: 0 }}
                exit={{ scale: 0.9, opacity: 0, y: 20 }}
                transition={{ duration: 0.25, ease: "easeOut" }}
                onTouchStart={handleTouchStart}
                onTouchEnd={handleTouchEnd}
            >
                {/* Header */}
                <div className="media-upload-header">
                    <div className="header-left">
                        <span className="media-upload-title">
                            {file ? 'Preview Media' : 'Send Media'}
                        </span>
                    </div>
                    <button 
                        onClick={onCancel} 
                        className="media-close-btn"
                        disabled={uploading}
                    >
                        <X size={20} />
                    </button>
                </div>

                {/* Preview Area */}
                <div className="media-upload-preview">
                    {previewUrl ? (
                        <div className="preview-media-wrapper">
                            {file?.type.startsWith('image/') ? (
                                <SecureImage src={previewUrl} alt="Preview" className="media-preview-img" />
                            ) : (
                                <video src={previewUrl} controls className="media-preview-vid" />
                            )}
                        </div>
                    ) : (
                        <div 
                            className="upload-dropzone"
                            onClick={() => fileInputRef.current?.click()}
                        >
                            <div className="dropzone-content">
                                <div className="dropzone-icon">
                                    <Upload size={32} />
                                </div>
                                <p className="dropzone-text">Tap to select image or video</p>
                                <span className="dropzone-sub">Max size: 50MB</span>
                            </div>
                        </div>
                    )}
                    
                    {uploading && (
                        <div className="upload-progress-overlay">
                            <div className="progress-content">
                                <Loader2 className="animate-spin text-blue-500 mb-4" size={40} />
                                <span className="progress-text">Uploading {uploadProgress}%</span>
                                <div className="progress-bar-container">
                                    <motion.div 
                                        className="progress-bar-fill"
                                        initial={{ width: 0 }}
                                        animate={{ width: `${uploadProgress}%` }}
                                    />
                                </div>
                            </div>
                        </div>
                    )}
                </div>

                {/* Footer */}
                <div className="media-upload-footer">
                    <input
                        id="media-upload-input"
                        name="mediaFile"
                        type="file"
                        ref={fileInputRef}
                        onChange={handleFileSelect}
                        accept="image/*,video/*"
                        className="hidden"
                    />

                    {file ? (
                        <div className="footer-actions">
                            <button
                                onClick={() => fileInputRef.current?.click()}
                                disabled={uploading}
                                className="action-btn secondary"
                            >
                                <ImageIcon size={18} />
                                <span>Change</span>
                            </button>
                            <div className="flex-1" />
                            <button
                                onClick={handleUpload}
                                disabled={!file || uploading}
                                className="action-btn primary"
                            >
                                {uploading ? 'Sending...' : 'Send Media'}
                                {!uploading && <Send size={18} />}
                            </button>
                        </div>
                    ) : (
                        <button
                            onClick={() => fileInputRef.current?.click()}
                            className="action-btn primary full"
                        >
                            <Upload size={18} />
                            <span>Select Media</span>
                        </button>
                    )}
                </div>
            </motion.div>
        </div>
    );
};

import React, { useState } from 'react';
import { useChat } from '../../context/ChatContext';
import { X } from 'lucide-react';
import SecureImage from '../common/SecureImage';
import { supabase } from '../../lib/supabase';

interface NewChatModalProps {
    isOpen: boolean;
    onClose: () => void;
}

interface UserResult {
    id: string;
    username: string;
    full_name: string | null;
    avatar_url: string | null;
}

const NewChatModal: React.FC<NewChatModalProps> = ({ isOpen, onClose }) => {
    const [recipientId, setRecipientId] = useState(''); // Stores input text (username)
    const [error, setError] = useState('');
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [searchResults, setSearchResults] = useState<UserResult[]>([]);
    const [isSearching, setIsSearching] = useState(false);
    const { startConversation } = useChat();

    // Real-time search for users
    React.useEffect(() => {
        const timeoutId = setTimeout(async () => {
            if (!recipientId.trim()) {
                setSearchResults([]);
                return;
            }

            setIsSearching(true);
            try {
                const { data } = await supabase
                        .from('profiles')
                        .select('id, username, full_name, avatar_url')
                        .or(`username.ilike.%${recipientId}%,full_name.ilike.%${recipientId}%`)
                        .limit(5);

                if (data) setSearchResults(data);
            } catch (err) {
                console.error("Search failed", err);
            } finally {
                setIsSearching(false);
            }
        }, 300);

        return () => clearTimeout(timeoutId);
    }, [recipientId]);

    const handleStartChat = async (username: string) => {
        setError('');
        setIsSubmitting(true);
        try {
            await startConversation(username);
            onClose();
            setRecipientId('');
            setSearchResults([]);
        } catch (err: unknown) {
            const error = err as any;
            setError(error.message || 'Failed to start conversation');
            setIsSubmitting(false);
        }
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (recipientId) handleStartChat(recipientId);
    };

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
            <div className="bg-gray-900 border border-gray-800 rounded-xl w-full max-w-md p-5 md:p-6 relative shadow-2xl">
                <button
                    onClick={onClose}
                    className="absolute top-4 right-4 text-gray-400 hover:text-white"
                >
                    <X size={20} />
                </button>

                <h2 className="text-xl font-bold text-white mb-4">Start New Chat</h2>

                <form onSubmit={handleSubmit} className="space-y-4">
                    <div className="relative">
                        <label htmlFor="newChatUsername" className="block text-sm font-medium text-gray-400 mb-1">
                            Username
                        </label>
                        <input
                            id="newChatUsername"
                            type="text"
                            value={recipientId}
                            onChange={(e) => setRecipientId(e.target.value)}
                            placeholder="Type to search users..."
                            className="w-full bg-gray-800 border border-gray-700 rounded-lg px-4 py-2 text-white focus:ring-2 focus:ring-blue-500 outline-none"
                            required
                        />

                        {/* Search Results Dropdown */}
                        {recipientId && (
                            <div className="absolute top-full left-0 right-0 mt-2 bg-gray-800 border border-gray-700 rounded-lg shadow-xl overflow-hidden z-10 max-h-60 overflow-y-auto">
                                {isSearching ? (
                                    <div className="p-3 text-center text-gray-400 text-sm">Searching...</div>
                                ) : searchResults.length > 0 ? (
                                    searchResults.map(user => (
                                        <div
                                            key={user.id}
                                            onClick={() => handleStartChat(user.username)}
                                            className="p-3 hover:bg-gray-700 cursor-pointer flex items-center gap-3 transition-colors"
                                        >
                                            <div className="w-8 h-8 rounded-full bg-gray-600 flex items-center justify-center overflow-hidden flex-shrink-0">
                                                {user.avatar_url ? (
                                                    <SecureImage src={user.avatar_url} alt={user.username} className="w-full h-full object-cover" fallbackType="profile" />
                                                ) : (
                                                    <span className="text-xs font-bold text-white">
                                                        {(user.full_name?.[0] || user.username?.[0] || '?').toUpperCase()}
                                                    </span>
                                                )}
                                            </div>
                                            <div className="min-w-0">
                                                <div className="text-sm font-medium text-white truncate">
                                                    {user.full_name || user.username}
                                                </div>
                                                <div className="text-xs text-gray-400 truncate">
                                                    @{user.username}
                                                </div>
                                            </div>
                                        </div>
                                    ))
                                ) : (
                                    <div className="p-3 text-center text-gray-400 text-sm">No users found</div>
                                )}
                            </div>
                        )}
                    </div>

                    <p className="text-xs text-gray-500 mt-1">
                        Select a user from the list to start chatting.
                    </p>

                    {error && (
                        <div className="p-3 bg-red-500/10 border border-red-500/20 rounded-lg text-red-500 text-sm">
                            {error}
                        </div>
                    )}

                    <button
                        type="submit"
                        disabled={isSubmitting}
                        className="w-full bg-blue-600 hover:bg-blue-700 text-white font-medium py-2 rounded-lg transition-colors disabled:opacity-50"
                    >
                        {isSubmitting ? 'Starting...' : 'Start Chat'}
                    </button>
                </form>
            </div>
        </div>
    );
};

export default NewChatModal;

import React, { useEffect, useState, useRef } from 'react';
import { supabase } from '../../lib/supabase';
import { useAuth } from '../../context/AuthContext';
import { API_URL } from '../../lib/api';
import { Send, Loader2 } from 'lucide-react';
import toast from 'react-hot-toast';

interface Message {
    id: string;
    conversation_id: string;
    sender_id: string;
    content: string;
    created_at: string;
    type: string;
}

interface SupabaseRealtimeChatProps {
    conversationId: string;
}

export const SupabaseRealtimeChat: React.FC<SupabaseRealtimeChatProps> = ({ conversationId }) => {
    const { user, session } = useAuth();
    const [messages, setMessages] = useState<Message[]>([]);
    const [inputValue, setInputValue] = useState('');
    const [loading, setLoading] = useState(true);
    const [sending, setSending] = useState(false);
    const messagesEndRef = useRef<HTMLDivElement>(null);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    };

    // 1. Initial Load of Messages
    useEffect(() => {
        const fetchMessages = async () => {
            if (!conversationId) return;
            setLoading(true);
            try {
                const { data, error } = await supabase
                    .from('messages')
                    .select('*')
                    .eq('conversation_id', conversationId)
                    .order('created_at', { ascending: true });

                if (error) throw error;
                setMessages(data || []);
            } catch (err) {
                console.error('Error fetching messages:', err);
                toast.error('Failed to load messages');
            } finally {
                setLoading(false);
                scrollToBottom();
            }
        };

        fetchMessages();
    }, [conversationId]);

    // 2. Setup Realtime Subscription
    useEffect(() => {
        if (!conversationId) return;

        console.log(`[Realtime] Subscribing to conversation: ${conversationId}`);

        const channel = supabase
            .channel(`chat:${conversationId}`)
            .on(
                'postgres_changes',
                {
                    event: 'INSERT',
                    schema: 'public',
                    table: 'messages',
                    filter: `conversation_id=eq.${conversationId}`,
                },
                (payload) => {
                    const newMessage = payload.new as Message;
                    console.log('[Realtime] New message received:', newMessage);
                    setMessages((prev) => [...prev, newMessage]);
                    scrollToBottom();
                }
            )
            .subscribe((status) => {
                console.log(`[Realtime] Subscription status for ${conversationId}:`, status);
            });

        // Cleanup on unmount
        return () => {
            console.log(`[Realtime] Unsubscribing from ${conversationId}`);
            supabase.removeChannel(channel);
        };
    }, [conversationId]);

    // 3. Send Message via Netlify API
    const handleSend = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!inputValue.trim() || sending || !session) return;

        setSending(true);
        try {
            const response = await fetch(`${API_URL}/api/chat/conversations/${conversationId}/messages`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${session.access_token}`,
                },
                body: JSON.stringify({
                    content: inputValue,
                    type: 'text',
                }),
            });

            if (!response.ok) {
                const errData = await response.json();
                throw new Error(errData.error || 'Failed to send message');
            }

            setInputValue('');
        } catch (err: any) {
            console.error('Send error:', err);
            toast.error(err.message || 'Failed to send message');
        } finally {
            setSending(false);
        }
    };

    if (loading) {
        return (
            <div className="flex items-center justify-center p-10 text-gray-400">
                <Loader2 className="animate-spin mr-2" /> Loading chat...
            </div>
        );
    }

    return (
        <div className="flex flex-col h-[500px] w-full max-w-2xl mx-auto bg-gray-900 border border-gray-800 rounded-2xl shadow-2xl overflow-hidden">
            {/* Messages Area */}
            <div className="flex-1 overflow-y-auto p-4 space-y-4">
                {messages.length === 0 ? (
                    <p className="text-center text-gray-500 py-10">No messages yet. Start the conversation!</p>
                ) : (
                    messages.map((msg) => (
                        <div
                            key={msg.id}
                            className={`flex ${msg.sender_id === user?.id ? 'justify-end' : 'justify-start'}`}
                        >
                            <div
                                className={`max-w-[80%] p-3 rounded-2xl ${
                                    msg.sender_id === user?.id
                                        ? 'bg-blue-600 text-white rounded-br-sm'
                                        : 'bg-gray-800 text-gray-200 rounded-bl-sm'
                                }`}
                            >
                                <p className="text-sm break-words">{msg.content}</p>
                                <span className="text-[10px] opacity-50 block mt-1">
                                    {new Date(msg.created_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                                </span>
                            </div>
                        </div>
                    ))
                )}
                <div ref={messagesEndRef} />
            </div>

            {/* Input Area */}
            <form onSubmit={handleSend} className="p-4 bg-gray-900/50 border-t border-gray-800 flex gap-2">
                <input
                    id="realtime-chat-input"
                    name="message"
                    type="text"
                    value={inputValue}
                    onChange={(e) => setInputValue(e.target.value)}
                    placeholder="Type a message..."
                    className="flex-1 bg-gray-800 text-white border border-gray-700 rounded-xl px-4 py-2 focus:outline-none focus:border-blue-500 transition-all"
                />
                <button
                    type="submit"
                    disabled={!inputValue.trim() || sending}
                    className="bg-blue-600 hover:bg-blue-700 text-white p-2.5 rounded-xl disabled:opacity-50 transition-all active:scale-95"
                >
                    {sending ? <Loader2 className="animate-spin" size={18} /> : <Send size={18} />}
                </button>
            </form>
        </div>
    );
};

import { useState, useRef } from 'react';
import { toast } from 'react-hot-toast';
import { Mic, Square, Play, Pause, Trash2, Send } from 'lucide-react';
import { Button } from '../common/Button';

interface VoiceRecorderProps {
    onSend: (audioBlob: Blob) => void;
    onCancel: () => void;
}

export const VoiceRecorder: React.FC<VoiceRecorderProps> = ({ onSend, onCancel }) => {
    const [isRecording, setIsRecording] = useState(false);
    const [isPlaying, setIsPlaying] = useState(false);
    const [audioUrl, setAudioUrl] = useState<string | null>(null);
    const [recordingTime, setRecordingTime] = useState(0);

    const mediaRecorderRef = useRef<MediaRecorder | null>(null);
    const audioChunksRef = useRef<Blob[]>([]);
    const audioPlayerRef = useRef<HTMLAudioElement | null>(null);
    const timerRef = useRef<any>(null);

    const startRecording = async () => {
        try {
            const stream = await navigator.mediaDevices.getUserMedia({
                audio: {
                    echoCancellation: true,
                    noiseSuppression: true,
                    autoGainControl: true,
                    // @ts-ignore
                    googEchoCancellation: true,
                    googAutoGainControl: true,
                    googNoiseSuppression: true,
                    googHighpassFilter: true,
                    googTypingNoiseDetection: true,
                    sampleRate: 48000,
                    channelCount: 1
                }
            });
            
            // Choose the best supported mime type
            const types = [
                'audio/webm;codecs=opus',
                'audio/webm',
                'audio/mp4',
                'audio/ogg;codecs=opus',
            ];
            
            const mimeType = types.find(type => MediaRecorder.isTypeSupported(type));
            
            mediaRecorderRef.current = new MediaRecorder(stream, mimeType ? { mimeType } : undefined);
            audioChunksRef.current = [];

            mediaRecorderRef.current.ondataavailable = (event) => {
                if (event.data.size > 0) {
                    audioChunksRef.current.push(event.data);
                }
            };

            mediaRecorderRef.current.onstop = () => {
                const mime = mediaRecorderRef.current?.mimeType || 'audio/webm';
                const audioBlob = new Blob(audioChunksRef.current, { type: mime });
                const url = URL.createObjectURL(audioBlob);
                setAudioUrl(url);
            };

            mediaRecorderRef.current.start();
            setIsRecording(true);

            // Start Timer
            setRecordingTime(0);
            timerRef.current = setInterval(() => {
                setRecordingTime((prev) => prev + 1);
            }, 1000);

        } catch (error: any) {
            console.error('Error accessing microphone:', error.name, error.message);
            if (error.name === 'NotAllowedError' || error.name === 'SecurityError') {
                toast.error('Microphone access denied. Please enable permissions in your browser settings.');
            } else if (error.name === 'NotFoundError' || error.name === 'DevicesNotFoundError') {
                toast.error('Microphone not found. Please connect a microphone and try again.');
            } else {
                toast.error('Could not access microphone. Ensure permissions are granted.');
            }
        }
    };

    const stopRecording = () => {
        if (mediaRecorderRef.current && isRecording) {
            mediaRecorderRef.current.stop();
            if (timerRef.current) clearInterval(timerRef.current);
            setIsRecording(false);

            // Stop all tracks to release mic completely
            if (mediaRecorderRef.current.stream) {
                mediaRecorderRef.current.stream.getTracks().forEach(track => {
                    track.stop();
                    mediaRecorderRef.current?.stream.removeTrack(track); // Clean reference
                });
            }
            mediaRecorderRef.current = null;
        }
    };

    const togglePlayback = () => {
        if (audioPlayerRef.current) {
            if (isPlaying) {
                audioPlayerRef.current.pause();
            } else {
                audioPlayerRef.current.play();
            }
            setIsPlaying(!isPlaying);
        }
    };

    const formatTime = (seconds: number) => {
        const mins = Math.floor(seconds / 60);
        const secs = seconds % 60;
        return `${mins}:${secs.toString().padStart(2, '0')}`;
    };

    const handleSend = () => {
        if (audioChunksRef.current.length > 0) {
            const mime = mediaRecorderRef.current?.mimeType || 'audio/webm';
            const audioBlob = new Blob(audioChunksRef.current, { type: mime });
            onSend(audioBlob);
        }
    };

    return (
        <div className="flex items-center gap-3 bg-white/5 p-2 rounded-lg animate-in fade-in slide-in-from-bottom-2 duration-200">
            {audioUrl ? (
                // Preview Mode
                <>
                    <audio
                        ref={audioPlayerRef}
                        src={audioUrl}
                        onEnded={() => setIsPlaying(false)}
                        className="hidden"
                    />
                    <button onClick={togglePlayback} className="p-2 rounded-full bg-white/10 hover:bg-white/20 transition-colors">
                        {isPlaying ? <Pause size={18} /> : <Play size={18} />}
                    </button>
                    <div className="h-1 w-24 bg-white/10 rounded-full overflow-hidden">
                        <div className="h-full bg-primary animate-pulse" style={{ width: '100%' }}></div>
                    </div>
                    <button onClick={() => { setAudioUrl(null); audioChunksRef.current = []; }} className="p-2 text-red-400 hover:text-red-300">
                        <Trash2 size={18} />
                    </button>
                    <Button size="sm" onClick={handleSend} className="rounded-full px-4">
                        Send Voice <Send size={14} className="ml-2" />
                    </Button>
                </>
            ) : (
                // Recording Mode
                <>
                    {isRecording ? (
                        <>
                            <div className="flex items-center gap-2 mr-2">
                                <div className="w-2 h-2 rounded-full bg-red-500 animate-pulse"></div>
                                <span className="text-sm font-mono text-red-400">{formatTime(recordingTime)}</span>
                            </div>
                            <button onClick={stopRecording} className="p-2 rounded-full bg-red-500/20 text-red-500 hover:bg-red-500/30 transition-colors">
                                <Square size={18} fill="currentColor" />
                            </button>
                        </>
                    ) : (
                        <button onClick={startRecording} className="p-2 rounded-full bg-white/10 hover:bg-white/20 transition-colors text-primary">
                            <Mic size={20} />
                        </button>
                    )}
                    <Button variant="ghost" size="sm" onClick={onCancel}>
                        Cancel
                    </Button>
                </>
            )}
        </div>
    );
};

import React from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { AlertCircle, X } from 'lucide-react';
import { Button } from './Button';
import { Card } from './Card';

interface ConfirmationModalProps {
  isOpen: boolean;
  onClose: () => void;
  onConfirm: () => void;
  title: string;
  message: string;
  confirmText?: string;
  cancelText?: string;
  variant?: 'danger' | 'warning' | 'info';
  isLoading?: boolean;
}

export const ConfirmationModal: React.FC<ConfirmationModalProps> = ({
  isOpen,
  onClose,
  onConfirm,
  title,
  message,
  confirmText = 'Confirm',
  cancelText = 'Cancel',
  variant = 'danger',
  isLoading = false,
}) => {
  const getVariantStyles = () => {
    switch (variant) {
      case 'danger':
        return 'text-red-400 border-red-400/20 bg-red-400/10';
      case 'warning':
        return 'text-yellow-400 border-yellow-400/20 bg-yellow-400/10';
      default:
        return 'text-blue-400 border-blue-400/20 bg-blue-400/10';
    }
  };

  const getButtonVariant = () => {
    return variant === 'danger' ? 'danger' : 'primary';
  };

  return (
    <AnimatePresence>
      {isOpen && (
        <div className="fixed inset-0 z-[1000] flex items-center justify-center p-4">
          {/* Backdrop */}
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            onClick={onClose}
            className="absolute inset-0 bg-black/60 backdrop-blur-sm"
          />

          {/* Modal */}
          <motion.div
            initial={{ opacity: 0, scale: 0.9, y: 20 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.9, y: 20 }}
            transition={{ type: 'spring', damping: 25, stiffness: 300 }}
            className="relative w-full max-w-md"
          >
            <Card className="overflow-hidden border border-white/10 bg-gray-900/90 shadow-2xl backdrop-blur-xl">
              <div className="p-6">
                <div className="flex items-start justify-between mb-4">
                  <div className={`p-3 rounded-full ${getVariantStyles()}`}>
                    <AlertCircle size={24} />
                  </div>
                  <button
                    onClick={onClose}
                    className="p-1 text-gray-400 transition-colors hover:text-white"
                  >
                    <X size={20} />
                  </button>
                </div>

                <h2 className="text-xl font-bold text-white mb-2">{title}</h2>
                <p className="text-gray-400 leading-relaxed mb-8">{message}</p>

                <div className="flex items-center gap-3 justify-end">
                  <Button
                    variant="ghost"
                    onClick={onClose}
                    disabled={isLoading}
                  >
                    {cancelText}
                  </Button>
