                    variant={getButtonVariant() as any}
                    onClick={onConfirm}
                    loading={isLoading}
                  >
                    {confirmText}
                  </Button>
                </div>
              </div>
            </Card>
          </motion.div>
        </div>
      )}
    </AnimatePresence>
  );
};

import React, { useEffect, useRef, useState, useMemo } from 'react';
import { createPortal } from 'react-dom';
import { useTranslation } from 'react-i18next';
import { X, Check, Globe, Search } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import type { Variants } from 'framer-motion';

// Only including languages that have translation files and are registered in i18n.ts
const ALL_LANGUAGES = [
    { code: 'en', name: 'English', flag: '🇺🇸', native: 'English' },
    { code: 'es', name: 'Spanish', flag: '🇪🇸', native: 'Español' },
    { code: 'fr', name: 'French', flag: '🇫🇷', native: 'Français' },
    { code: 'zh', name: 'Chinese', flag: '🇨🇳', native: '中文' },
    { code: 'ro', name: 'Romanian', flag: '🇷🇴', native: 'Română' },
    { code: 'de', name: 'German', flag: '🇩🇪', native: 'Deutsch' },
    { code: 'it', name: 'Italian', flag: '🇮🇹', native: 'Italiano' },
    { code: 'pt', name: 'Portuguese', flag: '🇵🇹', native: 'Português' },
    { code: 'ja', name: 'Japanese', flag: '🇯🇵', native: '日本語' },
    { code: 'ko', name: 'Korean', flag: '🇰🇷', native: '한국어' },
    { code: 'ru', name: 'Russian', flag: '🇷🇺', native: 'Русский' },
    { code: 'ar', name: 'Arabic', flag: '🇸🇦', native: 'العربية', dir: 'rtl' },
];

interface LanguageModalProps {
    isOpen: boolean;
    onClose: () => void;
}

export const LanguageModal: React.FC<LanguageModalProps> = ({ isOpen, onClose }) => {
    const { i18n, t } = useTranslation();
    const [searchQuery, setSearchQuery] = useState('');
    const containerRef = useRef<HTMLDivElement>(null);

    // Get the base language code (e.g., 'en' from 'en-US')
    const currentLang = i18n.language?.split('-')[0] || 'en';

    // Filter languages based on search
    const filteredLanguages = useMemo(() => {
        return ALL_LANGUAGES.filter(lang => 
            lang.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
            lang.native.toLowerCase().includes(searchQuery.toLowerCase()) ||
            lang.code.toLowerCase().includes(searchQuery.toLowerCase())
        );
    }, [searchQuery]);

    // Close on ESC and handle body scroll
    useEffect(() => {
        const handleEsc = (e: KeyboardEvent) => {
            if (e.key === 'Escape') onClose();
        };
        
        if (isOpen) {
            window.addEventListener('keydown', handleEsc);
            document.body.style.overflow = 'hidden';
            
            // Prevent layout shift
            const scrollbarWidth = window.innerWidth - document.documentElement.clientWidth;
            if (scrollbarWidth > 0) {
                document.body.style.paddingRight = `${scrollbarWidth}px`;
            }
        } else {
            document.body.style.overflow = '';
            document.body.style.paddingRight = '';
        }

        return () => {
            window.removeEventListener('keydown', handleEsc);
            document.body.style.overflow = '';
            document.body.style.paddingRight = '';
        };
    }, [isOpen, onClose]);

    const changeLanguage = async (lng: string) => {
        try {
            await i18n.changeLanguage(lng);
            localStorage.setItem('i18nextLng', lng);
            onClose();
            // Optional: for some apps, a full reload ensures all translations are picked up
            // window.location.reload(); 
        } catch (error) {
            console.error('Failed to change language:', error);
        }
    };

    // Animation variants
    const overlayVariants: Variants = {
        hidden: { opacity: 0 },
        visible: { opacity: 1 },
    };

    const modalVariants: Variants = {
        hidden: { 
            y: '100dvh', // Start completely off-screen at the bottom
            opacity: 0,
        },
        visible: { 
            y: 0, 
            opacity: 1,
            transition: { 
                type: 'spring', 
                damping: 30, 
                stiffness: 350,
                mass: 0.8
            }
        },
        exit: {
            y: '100dvh',
            opacity: 0,
            transition: {
                duration: 0.2,
                ease: 'easeIn'
            }
        }
    };

    const modalContent = (
        <AnimatePresence>
            {isOpen && (
                <div 
                    className="fixed inset-0 z-[10000] flex items-end sm:items-center justify-center p-0"
                    role="dialog"
                    aria-modal="true"
                    aria-labelledby="language-modal-title"
                >
                    {/* Backdrop */}
                    <motion.div
                        variants={overlayVariants}
                        initial="hidden"
                        animate="visible"
                        exit="hidden"
                        onClick={onClose}
                        className="fixed inset-0 bg-black/80 backdrop-blur-md"
                    />

                    {/* Modal Content - Container for Mobile Bottom Sheet and Desktop Center Modal */}
                    <motion.div
                        ref={containerRef}
                        variants={modalVariants}
                        initial="hidden"
                        animate="visible"
                        exit="exit"
                        className="relative w-full sm:max-w-[480px] sm:mx-4 bg-[#0a0a0a] border-t sm:border border-white/10 rounded-t-[32px] sm:rounded-[24px] shadow-2xl overflow-hidden z-20 flex flex-col max-h-[92dvh] sm:max-h-[85dvh]"
                    >
                        {/* Interactive Pull Indicator for Mobile */}
                        <div className="sm:hidden w-full flex justify-center pt-4 pb-2 shrink-0 cursor-grab active:cursor-grabbing">
                            <div className="w-14 h-1.5 bg-white/20 rounded-full" />
                        </div>

                        {/* Header Section */}
                        <div className="px-6 py-6 sm:py-7 border-b border-white/5 flex items-center justify-between shrink-0">
                            <div className="flex items-center gap-4">
                                <div className="w-12 h-12 rounded-2xl bg-primary/15 flex items-center justify-center text-primary shadow-inner">
                                    <Globe size={24} />
                                </div>
                                <div className="flex flex-col">
                                    <h2 id="language-modal-title" className="text-xl font-bold text-white tracking-tight leading-none mb-1.5">
                                        {t('common.language')}
                                    </h2>
                                    <div className="flex items-center gap-2">
                                        <div className="w-1.5 h-1.5 rounded-full bg-primary animate-pulse" />
                                        <span className="text-[11px] text-gray-500 font-bold uppercase tracking-[0.1em]">
                                            {ALL_LANGUAGES.length} {t('common.available_languages', 'Available')}
                                        </span>
                                    </div>
                                </div>
                            </div>
                            <button
                                onClick={onClose}
                                className="w-10 h-10 flex items-center justify-center rounded-xl bg-white/5 hover:bg-white/10 text-gray-400 hover:text-white transition-all active:scale-90 border border-white/5"
                                aria-label="Close modal"
                            >
                                <X size={22} />
                            </button>
                        </div>

                        {/* Search Control */}
                        <div className="px-6 py-5 shrink-0 bg-white/[0.02]">
                            <div className="relative group">
                                <Search size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-600 group-focus-within:text-primary transition-colors" />
                                <input
                                    autoFocus
                                    type="text"
                                    placeholder={t('common.search_language', 'Search language...')}
                                    value={searchQuery}
                                    onChange={(e) => setSearchQuery(e.target.value)}
                                    className="w-full bg-black/40 border border-white/10 rounded-2xl h-[56px] pl-12 pr-5 text-white placeholder-gray-600 focus:outline-none focus:ring-2 focus:ring-primary/20 focus:border-primary/40 transition-all text-base"
                                />
                            </div>
                        </div>

                        {/* Language List - Optimized for mobile touch and desktop scroll */}
                        <div 
                            className="flex-1 overflow-y-auto px-4 pb-8 pt-2 scroll-smooth custom-scrollbar-visible overscroll-contain"
                            style={{ 
                                scrollbarWidth: 'thin',
                                scrollbarColor: 'rgba(255,255,255,0.2) transparent'
                            }}
                        >
                            <div className="grid gap-2">
                                {filteredLanguages.length > 0 ? (
                                    filteredLanguages.map((lang: any) => {
                                        const isActive = currentLang === lang.code;
                                        return (
                                            <button
                                                key={lang.code}
                                                onClick={() => changeLanguage(lang.code)}
                                                dir={lang.dir || 'ltr'}
                                                className={`
                                                    group w-full flex items-center justify-between px-4 py-4 rounded-2xl transition-all duration-300 relative overflow-hidden
                                                    ${isActive 
                                                        ? 'bg-primary/10 text-white ring-1 ring-primary/40' 
                                                        : 'hover:bg-white/[0.04] text-gray-400 hover:text-gray-100'
                                                    }
                                                `}
                                            >
                                                <div className={`flex items-center gap-4 relative z-10 ${lang.dir === 'rtl' ? 'flex-row-reverse' : ''}`}>
                                                    <span className="text-3xl filter drop-shadow-lg group-hover:scale-110 transition-transform duration-500">
                                                        {lang.flag}
                                                    </span>
                                                    <div className={lang.dir === 'rtl' ? 'text-right' : 'text-left'}>
                                                        <div className={`font-bold text-base leading-none mb-1.5 ${isActive ? 'text-primary' : 'text-gray-200'}`}>
                                                            {lang.native}
                                                        </div>
                                                        <div className="text-[12px] opacity-40 uppercase tracking-widest leading-none font-bold">
                                                            {lang.name}
                                                        </div>
                                                    </div>
                                                </div>
                                                
                                                {isActive && (
                                                    <motion.div
                                                        initial={{ scale: 0.5, opacity: 0 }}
                                                        animate={{ scale: 1, opacity: 1 }}
                                                        className="w-7 h-7 rounded-full bg-primary flex items-center justify-center shadow-lg shadow-primary/30 relative z-10"
                                                    >
                                                        <Check size={16} className="text-white stroke-[4]" />
                                                    </motion.div>
                                                )}

                                                {/* Background hover effect */}
                                                {!isActive && (
                                                    <div className="absolute inset-0 bg-gradient-to-r from-primary/0 via-primary/5 to-primary/0 translate-x-[-100%] group-hover:translate-x-[100%] transition-transform duration-700 pointer-events-none" />
                                                )}
                                            </button>
                                        );
                                    })
                                ) : (
                                    <div className="py-16 text-center">
                                        <div className="w-16 h-16 rounded-full bg-white/5 flex items-center justify-center mx-auto mb-4">
                                            <Search size={24} className="text-gray-600" />
                                        </div>
                                        <p className="text-gray-500 font-medium">No results for "{searchQuery}"</p>
                                    </div>
                                )}
                            </div>
                        </div>

                        {/* Footer / Info Section */}
                        <div className="px-6 py-5 bg-black/60 border-t border-white/5 text-center shrink-0">
                            <p className="text-[10px] text-gray-600 uppercase tracking-[0.3em] font-black">
                                {t('common.auto_save', 'Preference saved automatically')}
                            </p>
                        </div>
                    </motion.div>
                </div>
            )}
        </AnimatePresence>
    );

    return createPortal(modalContent, document.body);
};

import { useState, useEffect, useCallback } from 'react';
import { Card } from '../../components/common/Card';
import { Button } from '../../components/common/Button';
import { X, Send } from 'lucide-react';
import { supabase } from '../../lib/supabase';
import { useAuth } from '../../context/AuthContext';
import { toast } from 'react-hot-toast';

import { API_URL, getAuthHeader } from '../../lib/api';

interface Comment {
    id: string;
    content: string;
    created_at: string;
    user_id: string;
    profile?: {
        username: string;
        email: string;
        avatar_url?: string;
    };
}

interface CommentModalProps {
    isOpen: boolean;
    onClose: () => void;
    note: any | null;
}

export const CommentModal = ({ isOpen, onClose, note }: CommentModalProps) => {
    const { user, session } = useAuth();
    const [comments, setComments] = useState<Comment[]>([]);
    const [newComment, setNewComment] = useState('');
    const [loading, setLoading] = useState(false);
    const [submitting, setSubmitting] = useState(false);
    const noteId = note?.id;

    const fetchComments = useCallback(async () => {
        if (!noteId) return;
        setLoading(true);
        try {
            const { data, error } = await supabase
                .from('comments')
                .select(`
                    *,
                    profile:profiles!user_id (username, email, avatar_url)
                `)
                .eq('note_id', noteId)
                .order('created_at', { ascending: true });

            if (error) throw error;
            setComments(data as any || []);
        } catch (error) {
            console.error('Error fetching comments:', error);
            // toast.error('Failed to load comments');
        } finally {
            setLoading(false);
        }
    }, [noteId]);

    useEffect(() => {
        if (isOpen && noteId) {
            fetchComments();

            // Setup Realtime Subscription
            const channel = supabase
                .channel(`note-comments-${noteId}`)
                .on(
                    'postgres_changes',
                    {
                        event: '*',
                        schema: 'public',
                        table: 'comments',
                        filter: `note_id=eq.${noteId}`
                    },
                    (payload) => {
                        console.log('Comment change detected:', payload);
                        fetchComments(); // Refetch to get profile details and updated list
                    }
                )
                .subscribe();

            return () => {
                supabase.removeChannel(channel);
            };
        } else {
            setComments([]);
            setNewComment('');
        }
    }, [isOpen, noteId, fetchComments]);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!newComment.trim() || !user || !noteId || !session) return;

        setSubmitting(true);
        try {
            const res = await fetch(`${API_URL}/api/community/comment`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    ...(await getAuthHeader())
                },
                body: JSON.stringify({
                    noteId,
                    content: newComment.trim()
                })
            });

            if (!res.ok) throw new Error('Failed to post comment');

            setNewComment('');
            fetchComments();
            toast.success('Comment added');
        } catch (error) {
            console.error('Error adding comment:', error);
            toast.error('Failed to add comment');
        } finally {
            setSubmitting(false);
        }
    };

    const handleDelete = async (commentId: string) => {
        if (!user) return;
        try {
            const { error } = await supabase
                .from('comments')
                .delete()
                .eq('id', commentId)
                .eq('user_id', user.id);

            if (error) throw error;

            setComments(prev => prev.filter(c => c.id !== commentId));
            toast.success('Comment deleted');
        } catch (error) {
            console.error('Error deleting comment:', error);
            toast.error('Failed to delete comment');
        }
    };

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
            <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={onClose} />

            <Card className="w-full max-w-lg relative z-10 flex flex-col max-h-[80vh]" variant="glass">
                <div className="p-4 border-b border-white/10 flex items-center justify-between">
                    <h3 className="font-bold text-lg">Comments</h3>
                    <button onClick={onClose} className="p-1 hover:bg-white/10 rounded-full transition-colors">
                        <X size={20} />
                    </button>
                </div>

                <div className="flex-1 overflow-y-auto p-4 space-y-4">
                    {note && (
                        <div className="mb-6 pb-6 border-b border-white/10">
                            <h2 className="text-xl font-bold text-white mb-2">{note.title || 'Untitled'}</h2>
                            <p className="text-gray-300 text-sm whitespace-pre-wrap leading-relaxed">
                                {note.content || 'No content...'}
                            </p>
                            {note.tags && note.tags.length > 0 && (
                                <div className="flex gap-2 mt-4 flex-wrap">
                                    {note.tags.map((tag: string) => (
                                        <span key={tag} className="text-[10px] px-2 py-0.5 bg-white/5 text-gray-400 rounded-full border border-white/5">
                                            #{tag}
                                        </span>
                                    ))}
                                </div>
                            )}
                        </div>
                    )}

                    <h4 className="text-sm font-semibold text-gray-400 uppercase tracking-wider">Comments</h4>
                    {loading ? (
                        <div className="text-center text-gray-500 py-8">Loading comments...</div>
                    ) : comments.length === 0 ? (
                        <div className="text-center text-gray-500 py-8">No comments yet. Be the first!</div>
                    ) : (
                        comments.map(comment => (
                            <div key={comment.id} className="group flex gap-3">
                                <div className="w-8 h-8 rounded-full bg-primary/20 flex items-center justify-center text-primary font-bold text-xs shrink-0">
                                    {(comment.profile?.username?.[0] || comment.profile?.email?.[0] || '?').toUpperCase()}
                                </div>
                                <div className="flex-1">
                                    <div className="bg-white/5 rounded-2xl rounded-tl-none p-3">
                                        <div className="flex items-center justify-between mb-1">
                                            <span className="text-xs font-bold text-gray-300">
                                                {comment.profile?.username || 'User'}
                                            </span>
                                            <span className="text-[10px] text-gray-500">
                                                {new Date(comment.created_at).toLocaleDateString()}
                                            </span>
                                        </div>
                                        <p className="text-sm text-gray-200">{comment.content}</p>
                                    </div>
                                    {(user?.id === comment.user_id) && (
                                        <button
                                            onClick={() => handleDelete(comment.id)}
                                            className="text-xs text-red-400 hover:text-red-300 ml-2 mt-1 opacity-0 group-hover:opacity-100 transition-opacity"
                                        >
                                            Delete
                                        </button>
                                    )}
                                </div>
                            </div>
                        ))
                    )}
                </div>

                <form onSubmit={handleSubmit} className="p-4 border-t border-white/10 flex gap-2">
                    <input
                        id="comment-input"
                        name="comment"
                        type="text"
                        value={newComment}
                        onChange={(e) => setNewComment(e.target.value)}
                        placeholder="Write a comment..."
                        className="flex-1 bg-white/5 border border-white/10 rounded-full px-4 py-2 text-sm focus:outline-none focus:border-primary/50"
                    />
                    <Button type="submit" size="sm" disabled={!newComment.trim() || submitting} loading={submitting}>
                        <Send size={16} />
                    </Button>
                </form>
            </Card>
        </div>
    );
};

import { useState } from 'react';
import { X, Save, Zap, ArrowRight } from 'lucide-react';
import { supabase } from '../../lib/supabase';
import { ensureProfile } from '../../lib/supabaseSafe'; // Import ensureProfile
import { useAuth } from '../../context/AuthContext';
import { useNotes } from '../../context/NotesContext';
import { Button } from '../common/Button';
import { Input } from '../common/Input';
import { Card } from '../common/Card';
import { useNavigate } from 'react-router-dom';

interface CreateNoteModalProps {
    isOpen: boolean;
    onClose: () => void;
    onSuccess?: () => void;
}

export const CreateNoteModal = ({ isOpen, onClose, onSuccess }: CreateNoteModalProps) => {
    const { user } = useAuth();
    const { canCreateNote } = useNotes();
    const navigate = useNavigate();
    const [title, setTitle] = useState('');
    const [content, setContent] = useState('');
    const [tags, setTags] = useState('');
    const [isPrivate, setIsPrivate] = useState(true);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');

    if (!isOpen) return null;

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!user) return;

        setLoading(true);
        setError('');

        try {
            // Ensure profile exists before creating note (fixes FK error)
            const hasProfile = await ensureProfile(user);
            if (!hasProfile) {
                throw new Error('User profile could not be verified. Please try again.');
            }

            // Parse tags: split by comma, trim, filter empty
            const tagArray = tags.split(',').map(t => t.trim()).filter(t => t.length > 0);

            const { error } = await supabase // Changed variable name from insertError to error
                .from('notes')
                .insert({
                    title,
                    content,
                    tags: tagArray,
                    owner_id: user.id, // Kept user.id as per original, but user?.id was in snippet. Sticking to original for minimal change.
                    is_private: isPrivate // Added is_private
                });

            if (error) throw error; // Used new error variable

            // Reset and close
            setTitle('');
            setContent('');
            setTags('');
            setIsPrivate(true); // Reset isPrivate state
            onSuccess?.();
            onClose();
        } catch (err: any) {
            setError(err.message);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
            <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={onClose} />

            <Card className="w-full max-w-2xl relative z-10 p-6 animate-in fade-in zoom-in-95 duration-200" variant="glass">
                <div className="flex items-center justify-between mb-6">
                    <h2 className="text-xl font-bold">
                        {canCreateNote ? 'Create New Note' : 'Note Limit Reached'}
                    </h2>
                    <button onClick={onClose} className="text-gray-400 hover:text-white transition-colors">
                        <X size={20} />
                    </button>
                </div>

                {!canCreateNote ? (
                    <div className="py-8 text-center space-y-6">
                        <div className="w-16 h-16 bg-yellow-500/10 rounded-full flex items-center justify-center mx-auto border border-yellow-500/20">
                            <Zap size={32} className="text-yellow-500 fill-yellow-500" />
                        </div>
                        <div className="space-y-2">
                            <h3 className="text-lg font-bold">You've reached the 100 note limit</h3>
                            <p className="text-gray-400 text-sm max-w-sm mx-auto">
                                Upgrade to Note Standard Pro for unlimited notes, 0.5% crypto spreads, and priority support.
                            </p>
                        </div>
                        <div className="pt-4 flex flex-col sm:flex-row gap-3 justify-center">
                            <Button variant="ghost" onClick={onClose}>
                                Maybe Later
                            </Button>
                            <Button 
                                onClick={() => {
                                    onClose();
                                    navigate('/dashboard/billing');
                                }}
                                className="bg-gradient-to-r from-blue-600 to-purple-600 hover:from-blue-700 hover:to-purple-700 border-none px-8"
                            >
                                Upgrade Now
                                <ArrowRight size={16} />
                            </Button>
                        </div>
                    </div>
                ) : (
                    <form onSubmit={handleSubmit} className="space-y-4">
                        {error && (
                            <div className="bg-red-500/10 border border-red-500/20 text-red-500 px-4 py-2 rounded-lg text-sm">
                                {error}
                            </div>
                        )}

                        <div>
                            <label htmlFor="noteTitle" className="sr-only">Note Title</label>
                            <input
                                id="noteTitle"
                                name="title"
                                type="text"
                                placeholder="Note Title"
                                value={title}
                                onChange={(e) => setTitle(e.target.value)}
                                className="w-full bg-transparent text-2xl font-bold placeholder-gray-500 focus:outline-none border-none p-0"
                                required
                                autoComplete="off"
                            />
                        </div>

                        <div className="h-[1px] bg-white/10 w-full" />

                        <div>
                            <label htmlFor="noteContent" className="sr-only">Note Content</label>
                            <textarea
                                id="noteContent"
                                name="content"
                                placeholder="Start typing your note..."
                                value={content}
                                onChange={(e) => setContent(e.target.value)}
                                className="w-full h-64 bg-transparent text-gray-300 placeholder-gray-600 focus:outline-none resize-none"
                                autoComplete="off"
                            />
                        </div>

                        <div>
                            <Input
                                id="noteTags"
                                name="tags"
                                label="Tags (comma separated)"
                                value={tags}
                                onChange={(e) => setTags(e.target.value)}
                                placeholder="work, ideas, important"
                                className="bg-[#121212]"
                                autoComplete="off"
                            />
                        </div>

                        <div className="flex items-center gap-2">
                            <input
                                type="checkbox"
                                id="isPrivate"
                                name="isPrivate"
                                checked={!isPrivate}
                                onChange={(e) => setIsPrivate(!e.target.checked)}
                                className="w-4 h-4 rounded border-gray-600 bg-[#121212] text-primary focus:ring-primary"
                            />
                            <label htmlFor="isPrivate" className="text-sm text-gray-300">
                                Make this note public (visible in Community Feed)
                            </label>
                        </div>
                        <div className="flex justify-end gap-3 pt-4">
                            <Button type="button" variant="ghost" onClick={onClose}>
                                Cancel
                            </Button>
                            <Button type="submit" loading={loading}>
                                <Save size={16} />
                                Save Note
                            </Button>
                        </div>
                    </form>
                )}
            </Card>
        </div>
    );
};

import { useState } from 'react';
import { Card } from '../../components/common/Card';
import SecureImage from '../../components/common/SecureImage';
import { Heart, MessageCircle } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { toast } from 'react-hot-toast';
import { UserBadge } from '../../components/common/UserBadge';

import { API_URL, getAuthHeader } from '../../lib/api';

interface FeedNoteCardProps {
    note: {
        id: string;
        title: string;
        content: string;
        created_at: string;
        tags: string[];
        owner_id: string;
        likes_count?: number;
        comments_count?: number;
        user_has_liked?: boolean;
        owner?: {
            username: string;
            email: string;
            avatar_url?: string;
            plan_tier?: string;
            is_verified?: boolean;
        };
    };
    onCommentClick: (note: any) => void;
}

export const FeedNoteCard = ({ note, onCommentClick }: FeedNoteCardProps) => {
    const { user, session } = useAuth();
    const [liked, setLiked] = useState(note.user_has_liked || false);
    const [likesCount, setLikesCount] = useState(note.likes_count || 0);
    const [loadingLike, setLoadingLike] = useState(false);

    const handleLike = async (e: React.MouseEvent) => {
        e.stopPropagation();
        if (!user || !session || loadingLike) return;

        setLoadingLike(true);
        // Optimistic update
        const previousLiked = liked;
        const previousCount = likesCount;
        
        const newLikedState = !liked;
        setLiked(newLikedState);
        setLikesCount(prev => newLikedState ? prev + 1 : prev - 1);

        try {
            const res = await fetch(`${API_URL}/api/community/like`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    ...(await getAuthHeader())
                },
                body: JSON.stringify({
                    noteId: note.id
                })
            });

            if(!res.ok) throw new Error('Failed to toggle like');
            
            const data = await res.json();
            // Ensure state matches server response exactly
            setLiked(data.liked);
        } catch (error) {
            console.error('Error toggling like:', error);
            // Revert on error
            setLiked(previousLiked);
            setLikesCount(previousCount);
            toast.error('Failed to update like');
        } finally {
            setLoadingLike(false);
        }
    };

    return (
        <Card className="p-0 overflow-hidden group border-white/5 hover:border-white/10 transition-all">
            <div className="p-5">
                <div className="flex items-center justify-between mb-4">
                    <div className="flex items-center gap-3">
                        <div className="w-8 h-8 rounded-full bg-gradient-to-br from-primary/20 to-secondary/20 flex items-center justify-center text-primary font-bold text-xs overflow-hidden">
                            {note.owner?.avatar_url ? (
                                <SecureImage src={note.owner.avatar_url} alt={note.owner.username} className="w-full h-full object-cover" fallbackType="profile" />
                            ) : (
                                (note.owner?.username?.[0] || note.owner?.email?.[0] || '?').toUpperCase()
                            )}
                        </div>
                        <div>
                            <div className="text-sm font-semibold text-white flex items-center gap-1">
                                {note.owner?.username || 'Unknown User'}
                                <UserBadge 
                                    planTier={note.owner?.plan_tier as any}
                                    isVerified={note.owner?.is_verified}
                                />
                            </div>
                            <div className="text-[10px] text-gray-500">
                                {new Date(note.created_at).toLocaleDateString()}
                            </div>
                        </div>
                    </div>
                </div>

                <div
                    onClick={() => onCommentClick(note)}
                    className="cursor-pointer"
                >
                    <h3 className="font-bold text-xl mb-2 group-hover:text-primary transition-colors">
                        {note.title || 'Untitled'}
                    </h3>
                    <p className="text-gray-400 text-sm line-clamp-6 mb-4 leading-relaxed group-hover:text-gray-300 transition-colors">
                        {note.content || 'No content...'}
                    </p>
                    {note.content?.length > 300 && (
                        <div className="text-primary text-xs font-semibold mb-4">Read more...</div>
                    )}

                    <div className="flex gap-2 mb-4 flex-wrap">
                        {note.tags && note.tags.slice(0, 3).map(tag => (
                            <span key={tag} className="text-[10px] px-2 py-0.5 bg-white/5 text-gray-400 rounded-full border border-white/5">
                                #{tag}
                            </span>
                        ))}
                    </div>
                </div>

                <div className="flex items-center gap-4 pt-4 border-t border-white/5">
                    <button
                        onClick={handleLike}
                        className={`flex items-center gap-1.5 text-sm transition-colors ${liked ? 'text-red-500' : 'text-gray-500 hover:text-red-400'}`}
                    >
                        <Heart size={18} fill={liked ? "currentColor" : "none"} />
                        <span>{likesCount}</span>
                    </button>

                    <button
                        onClick={() => onCommentClick(note)}
                        className="flex items-center gap-1.5 text-sm text-gray-500 hover:text-primary transition-colors"
                    >
                        <MessageCircle size={18} />
                        <span>{note.comments_count || 0}</span>
                    </button>
                </div>
            </div>
        </Card>
    );
};

