        </motion.div>
    </div>
    );
};

import React, { useState, useEffect } from 'react';
import { X, Copy, Share2, AlertTriangle, CheckCircle2, QrCode, Loader2 } from 'lucide-react';
import { Button } from '../common/Button';
import { useWallet } from '../../hooks/useWallet';
import { useAuth } from '../../context/AuthContext';
import { QRCodeSVG } from 'qrcode.react';
import toast from 'react-hot-toast';
import walletApi from '../../api/walletApi';
import { motion, AnimatePresence } from 'framer-motion';

interface ReceiveModalProps {
    isOpen: boolean;
    onClose: () => void;
    initialCurrency?: string;
    initialNetwork?: string;
}

export const ReceiveModal: React.FC<ReceiveModalProps> = ({ isOpen, onClose, initialCurrency = 'BTC', initialNetwork = 'native' }) => {
    const { wallets, createWallet, loading: walletLoading } = useWallet();
    const { user } = useAuth();
    const [selectedCurrency, setSelectedCurrency] = useState(initialCurrency);
    const [selectedNetwork, setSelectedNetwork] = useState(initialNetwork);
    const [copied, setCopied] = useState(false);
    const [hdAddress, setHdAddress] = useState<string | null>(null);
    const [hdLoading, setHdLoading] = useState(false);

    const isCrypto = ['BTC', 'ETH', 'USDT', 'USDC'].includes(selectedCurrency);
    const currentWallet = wallets.find(w => w.currency === selectedCurrency && w.network === selectedNetwork);
    // For fiat currencies, show user's email (what senders use) instead of internal wallet UUID
    const displayAddress = isCrypto
        ? (hdAddress || currentWallet?.address || '')
        : (user?.email || currentWallet?.address || '');

    useEffect(() => {
        if (isOpen) {
            setSelectedCurrency(initialCurrency);
            setSelectedNetwork(initialNetwork);
            if (['BTC', 'ETH', 'USDT', 'USDC'].includes(initialCurrency)) {
                fetchCurrentHdAddress(initialCurrency, initialNetwork);
            } else {
                setHdAddress(null);
            }
        }
    }, [isOpen, initialCurrency, initialNetwork]);

    const fetchCurrentHdAddress = async (asset: string, network: string) => {
        try {
            setHdLoading(true);
            const result = await walletApi.getCurrentAddress(asset, network);
            setHdAddress(result.address);
        } catch (error) {
            console.error('Failed to fetch address:', error);
        } finally {
            setHdLoading(false);
        }
    };

    const handleGenerateNew = async () => {
        if (!isCrypto) return;
        
        try {
            setHdLoading(true);
            const result = await walletApi.generateNewAddress(selectedCurrency, selectedNetwork);
            setHdAddress(result.address);
            toast.success('New address generated');
        } catch (error: any) {
            toast.error(error.message || 'Failed to generate new address');
        } finally {
            setHdLoading(false);
        }
    };

    const handleCopy = () => {
        if (displayAddress) {
            navigator.clipboard.writeText(displayAddress);
            setCopied(true);
            toast.success(`${isCrypto ? 'Address' : 'ID'} copied to clipboard`);
            setTimeout(() => setCopied(false), 2000);
        }
    };

    const handleShare = async () => {
        if (displayAddress && navigator.share) {
            try {
                await navigator.share({
                    title: `Receive ${selectedCurrency}`,
                    text: `My ${selectedCurrency} ${isCrypto ? 'address' : 'ID'}: ${displayAddress}`,
                });
            } catch (err) {
                console.error('Share failed:', err);
            }
        } else {
             handleCopy();
        }
    };
    
    // Auto-create wallet if it doesn't exist for selected currency/network
    const handleCurrencyChange = async (currency: string, network: string) => {
        setSelectedCurrency(currency);
        setSelectedNetwork(network);
        if (['BTC', 'ETH', 'USDT', 'USDC'].includes(currency)) {
            fetchCurrentHdAddress(currency, network);
        } else {
            setHdAddress(null);
        }
        const exists = wallets.find(w => w.currency === currency && w.network === network);
        if (!exists) {
            try {
                toast.loading(`Creating ${currency} ${network !== 'native' ? `(${network})` : ''} service...`, { id: 'create-wallet' });
                await createWallet(currency, network);
                toast.success(`${currency} service ready`, { id: 'create-wallet' });
            } catch {
                toast.error(`Failed to create ${currency} wallet`, { id: 'create-wallet' });
            }
        }
    };

    if (!isOpen) return null;

    return (
        <div className="modal-overlay">
            <motion.div 
                initial={{ opacity: 0, scale: 0.95 }}
                animate={{ opacity: 1, scale: 1 }}
                exit={{ opacity: 0, scale: 0.95 }}
                className="modal-content"
            >
                <button onClick={onClose} className="modal-close">
                    <X size={20} />
                </button>

                <h2 className="modal-header">
                    <QrCode className="text-purple-500" size={24} />
                    Receive Interactions
                </h2>

                <div className="modal-body">
                    {/* Currency Selector */}
                    <div className="flex gap-2 overflow-x-auto pb-4 mb-2 scrollbar-hide">
                        {wallets.map(w => (
                            <button
                                key={`${w.currency}_${w.network}`}
                                onClick={() => handleCurrencyChange(w.currency, w.network)}
                                className={`px-4 py-2 rounded-xl text-sm font-bold border transition-all whitespace-nowrap flex flex-col items-center ${
                                    selectedCurrency === w.currency && selectedNetwork === w.network
                                    ? 'bg-purple-600 border-purple-500 text-white shadow-lg shadow-purple-500/20' 
                                    : 'bg-gray-800 border-gray-700 text-gray-400 hover:border-gray-600 hover:text-white'
                                }`}
                            >
                                <span>{w.currency}</span>
                                {w.network !== 'native' && <span className="text-[10px] opacity-70 uppercase">{w.network}</span>}
                            </button>
                        ))}
                    </div>

                    <AnimatePresence mode="wait">
                        {currentWallet || hdAddress ? (
                            <motion.div 
                                key={selectedCurrency}
                                initial={{ opacity: 0, y: 10 }}
                                animate={{ opacity: 1, y: 0 }}
                                exit={{ opacity: 0, y: -10 }}
                                className="space-y-6"
                            >
                                {/* QR Code Card */}
                                <div className="bg-white p-6 rounded-2xl mx-auto w-max shadow-xl ring-4 ring-white/10 relative">
                                    {hdLoading ? (
                                        <div className="absolute inset-0 flex items-center justify-center bg-white/80 rounded-2xl backdrop-blur-sm z-10">
                                             <Loader2 className="animate-spin text-purple-600" size={40} />
                                        </div>
                                    ) : null}
                                    <QRCodeSVG 
                                        value={displayAddress} 
                                        size={200}
                                        level="H"
                                        includeMargin={false}
                                    />
                                </div>

                                {/* Address Display */}
                                <div className="space-y-2">
                                    <div className="flex justify-between items-end ml-1">
                                        <span className="text-xs font-medium text-gray-500 uppercase tracking-wider">
                                            {isCrypto ? `Your ${selectedCurrency} Address` : `Your Email / User ID (${selectedCurrency})`}
                                        </span>
                                        {isCrypto && (
                                            <button 
                                                onClick={handleGenerateNew}
                                                disabled={hdLoading}
                                                className="text-[10px] text-purple-400 hover:text-purple-300 font-bold uppercase tracking-tighter transition-colors disabled:opacity-50"
                                            >
                                                {hdLoading ? 'Generating...' : 'Regenerate New'}
                                            </button>
                                        )}
                                    </div>
                                    <div 
                                        onClick={handleCopy}
                                        className="group relative bg-gray-800/50 border border-gray-700/50 hover:border-purple-500/50 rounded-xl p-4 cursor-pointer transition-all active:scale-[0.99]"
                                    >
                                        <p className="font-mono text-sm text-gray-300 break-all text-center select-all">
                                            {hdLoading ? '••••••••••••••••••••••••••••••••••••' : displayAddress}
                                        </p>
                                        <div className="absolute inset-0 flex items-center justify-center bg-black/60 opacity-0 group-hover:opacity-100 transition-opacity rounded-xl backdrop-blur-[1px]">
                                            <span className="text-white font-medium flex items-center gap-2">
                                                <Copy size={16} /> Click to Copy
                                            </span>
                                        </div>
                                    </div>
                                </div>

                                {/* Action Buttons */}
                                <div className="grid grid-cols-2 gap-3">
                                    <Button 
                                        onClick={handleCopy} 
                                        variant="secondary" 
                                        className={copied ? "bg-green-500/20 text-green-400 border-green-500/50" : ""}
                                    >
                                        {copied ? <CheckCircle2 size={18} className="mr-2" /> : <Copy size={18} className="mr-2" />}
                                        {copied ? 'Copied' : 'Copy'}
                                    </Button>
                                    <Button onClick={handleShare} variant="outline">
                                        <Share2 size={18} className="mr-2" />
                                        Share
                                    </Button>
                                </div>

                                {/* Security Notice */}
                                <div className="bg-orange-500/10 border border-orange-500/20 rounded-xl p-4 flex gap-3 text-orange-200/90 text-sm">
                                    <AlertTriangle size={20} className="shrink-0 text-orange-500" />
                                    <div>
                                        <p className="font-bold text-orange-400 mb-1">
                                            {isCrypto ? `Send only ${selectedCurrency} to this address.` : `Receive ${selectedCurrency} via Internal Transfer.`}
                                        </p>
                                        <p className="text-xs opacity-80 leading-relaxed">
                                            {isCrypto 
                                                ? `Allocating any other asset to this address may result in the permanent loss of your funds. Ensure you are on the correct network.`
                                                : `Provide your Email or User ID above to the sender. This ${selectedCurrency} will be credited to your account instantly once sent internally.`
                                            }
                                        </p>
                                    </div>
                                </div>

                            </motion.div>
                        ) : (
                            <div className="py-12 flex flex-col items-center justify-center text-center space-y-4">
                                <div className="w-16 h-16 rounded-full bg-gray-800 flex items-center justify-center">
                                    {walletLoading ? (
                                        <Loader2 className="animate-spin text-purple-500" size={32} />
                                    ) : (
                                        <AlertTriangle className="text-gray-500" size={32} />
                                    )}
                                </div>
                                <div>
                                    <h3 className="text-lg font-bold text-white">
                                        {walletLoading ? 'Activating Service...' : 'Service Not Active'}
                                    </h3>
                                    <p className="text-gray-400 text-sm mt-1 max-w-xs mx-auto">
                                        {walletLoading 
                                            ? `Setting up your secure ${selectedCurrency} endpoint.` 
                                            : `You don't have a ${selectedCurrency} service active yet.`}
                                    </p>
                                </div>
                                {!walletLoading && (
                                    <Button onClick={() => handleCurrencyChange(selectedCurrency, selectedNetwork)} className="bg-purple-600 hover:bg-purple-500">
                                        Create {selectedCurrency} Service
                                    </Button>
                                )}
                            </div>
                        )}
                    </AnimatePresence>
                </div>
            </motion.div>
        </div>
    );
};

import React, { useMemo } from 'react';
import { Doughnut } from 'react-chartjs-2';
import { Chart as ChartJS, ArcElement, Tooltip, Legend } from 'chart.js';
import type { Wallet } from '@/types/wallet';
import { formatCurrency } from '../../lib/CurrencyFormatter';

ChartJS.register(ArcElement, Tooltip, Legend);

interface WalletAllocationChartProps {
    wallets: Wallet[];
    rates: Record<string, number>;
}

export const WalletAllocationChart: React.FC<WalletAllocationChartProps> = ({ wallets, rates }) => {
    
    const data = useMemo(() => {
        const labels: string[] = [];
        const dataPoints: number[] = [];
        const backgroundColors: string[] = [];
        const borderColors: string[] = [];

        // Sort wallets by value (highest first)
        const safeWallets = Array.isArray(wallets) ? wallets : [];
        const sortedWallets = [...safeWallets].sort((a, b) => {
            const valA = a.balance * (rates[a.currency] || 0);
            const valB = b.balance * (rates[b.currency] || 0);
            return valB - valA;
        });

        const colorPalette = [
            '#8b5cf6', // purple-500
            '#3b82f6', // blue-500
            '#10b981', // emerald-500
            '#f59e0b', // amber-500
            '#ef4444', // red-500
            '#ec4899', // pink-500
            '#6366f1', // indigo-500
            '#14b8a6', // teal-500
        ];

        sortedWallets.forEach((wallet, index) => {
            const usdValue = wallet.balance * (rates[wallet.currency] || 0);
            if (usdValue > 0.01) { // Only show significant balances
                labels.push(wallet.currency);
                dataPoints.push(usdValue);
                backgroundColors.push(colorPalette[index % colorPalette.length]);
                borderColors.push('#111827'); // gray-900 border for separation
            }
        });

        // If no data, show placeholder
        if (dataPoints.length === 0) {
             return {
                labels: ['Empty'],
                datasets: [{
                    data: [1],
                    backgroundColor: ['#374151'], // gray-700
                    borderWidth: 0,
                }]
            };
        }

        return {
            labels,
            datasets: [
                {
                    data: dataPoints,
                    backgroundColor: backgroundColors,
                    borderColor: borderColors,
                    borderWidth: 2,
                    hoverOffset: 4
                },
            ],
        };
    }, [wallets, rates]);

    const options = {
        responsive: true,
        maintainAspectRatio: false,
        plugins: {
            legend: {
                position: 'bottom' as const,
                labels: {
                    color: '#9ca3af', // gray-400
                    font: {
                        family: "'Inter', sans-serif",
                        size: 11
                    },
                    padding: 20,
                    usePointStyle: true,
                    boxWidth: 8
                }
            },
            tooltip: {
                backgroundColor: 'rgba(17, 24, 39, 0.9)', // gray-900
                titleColor: '#fff',
                bodyColor: '#e5e7eb', // gray-200
                padding: 12,
                cornerRadius: 8,
                callbacks: {
                    label: function(context: any) {
                        let label = context.label || '';
                        if (label) {
                            label += ': ';
                        }
                        if (context.parsed !== null) {
                            label += formatCurrency(context.parsed, 'USD');
                        }
                        return label;
                    }
                }
            }
        },
        cutout: '70%', // Thinner doughnut
    };

    return (
        <div className="bg-gray-900 border border-gray-800 rounded-2xl p-6 shadow-lg flex flex-col items-center">
            <h3 className="text-gray-300 font-bold mb-6 w-full text-left flex items-center gap-2">
                Portfolio Allocation
                <span className="text-xs font-normal text-gray-500 bg-gray-800 px-2 py-0.5 rounded-full">USD Value</span>
            </h3>
            
            <div className="h-48 w-full relative">
                 {wallets.length === 0 || Object.keys(rates).length === 0 ? (
                    <div className="absolute inset-0 flex items-center justify-center text-gray-500 text-sm">
                        No Data
                    </div>
                 ) : null}
                <Doughnut data={data} options={options} />
                
                {data.datasets[0].data.length > 0 && data.labels[0] !== 'Empty' && (
                     <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                        <div className="text-center">
                            <p className="text-xs text-gray-500">Total Assets</p>
                            <p className="text-sm font-bold text-white">{wallets.length}</p>
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
};

import React, { createContext, useContext, useEffect, useRef, useState, useCallback } from 'react';
import { useAuth } from './AuthContext';
import { useSocket } from './SocketContext';
import { NotificationService } from '../services/NotificationService';
import { API_URL } from '../lib/api';

export interface Message {
    id: string;
    conversation_id: string;
    sender_id: string;
    content: string;
    created_at: string;
    type: 'text' | 'image' | 'video' | 'file' | 'audio' | 'call';
    isOwn?: boolean;
    original_language?: string;
    read_at?: string;
    is_edited?: boolean;
    updated_at?: string;
    sentiment?: {
        label: 'positive' | 'negative' | 'neutral';
        score: number;
    };
    attachment?: {
        id: string;
        file_name: string;
        file_type: string;
        file_size: number;
        storage_path: string;
        metadata: any;
    };
}

export interface Conversation {
    id: string;
    type: 'direct' | 'group';
    chat_type?: 'support' | 'general' | 'admin';
    support_status?: 'open' | 'pending' | 'resolved' | 'escalated';
    name: string;
    updated_at: string;
    lastMessage?: {
        content: string;
        sender_id: string;
        created_at: string;
        read_at?: string;
    };
    unreadCount?: number;
    is_muted?: boolean;
    members: {
        user_id: string;
        role: string;
        status: string;
        profile?: {
            username: string;
            full_name: string;
            avatar_url: string;
            is_online?: boolean;
            plan_tier?: 'free' | 'pro' | 'team' | 'business' | 'enterprise';
            is_verified?: boolean;
            show_online_status?: boolean;
            last_seen?: string;
        };
    }[];
}

export interface ChatContextValue {
    conversations: Conversation[];
    messages: Record<string, Message[]>;
    activeConversationId: string | null;
    loading: boolean;
    connected: boolean;
    setActiveConversationId: (id: string | null) => void;
    sendMessage: (content: string, type?: string, attachmentId?: string) => Promise<void>;
    loadMoreMessages: (conversationId: string) => Promise<void>;
    markMessageRead: (messageId: string) => Promise<void>;
    startConversation: (username: string) => Promise<void>; 
    acceptConversation: (id: string) => Promise<void>;
    deleteConversation: (id: string) => Promise<void>;
    deleteMessage: (messageId: string) => Promise<void>;
    editMessage: (messageId: string, content: string) => Promise<void>;
    muteConversation: (id: string, isMuted: boolean) => Promise<void>;
    clearChatHistory: (id: string) => Promise<void>;
    sendTypingStatus: (isTyping: boolean) => void;
    typingUsers: Record<string, string[]>;
    hasMore: Record<string, boolean>;
    sendMessageToConversation: (conversationId: string, content: string, type?: string, attachmentId?: string) => Promise<void>;
}

const ChatContext = createContext<ChatContextValue | null>(null);

export const useChat = () => {
    const context = useContext(ChatContext);
    if (!context) throw new Error('useChat must be used within a ChatProvider');
    return context;
};

export const ChatProvider = ({ children }: { children: React.ReactNode }) => {
    const { user, profile, session, authReady } = useAuth();
    const { socket, connected } = useSocket();
    const [conversations, setConversations] = useState<Conversation[]>([]);
    const [messages, setMessages] = useState<Record<string, Message[]>>({});
    const [activeConversationId, setActiveConversationId] = useState<string | null>(null);
    const [loading, setLoading] = useState(true);
    const [hasMore, setHasMore] = useState<Record<string, boolean>>({});
    const [typingUsers, setTypingUsers] = useState<Record<string, string[]>>({});

    const isMounted = useRef(true);
    const conversationsFetchRef = useRef(false);
    const hasInitialFetched = useRef(false);
    const conversationsRef = useRef<Conversation[]>([]);

    // Keep ref in sync
    useEffect(() => {
        conversationsRef.current = conversations;
    }, [conversations]);

    const loadConversations = useCallback(async () => {
        if (!session || conversationsFetchRef.current) return;
        
        conversationsFetchRef.current = true;
        
        try {
            console.log('[Chat] FETCH: Loading conversations', { userId: user?.id });
            const res = await fetch(`${API_URL}/api/chat/conversations`, {
                headers: { 'Authorization': `Bearer ${session.access_token}` }
            });
            
            if (!res.ok) throw new Error(`Failed to load conversations: ${res.status}`);
            
            const data = await res.json();
            
            if (isMounted.current) {
                // Map backend last_message object to lastMessage
                const mappedData = data.map((conv: any) => ({
                    ...conv,
                    lastMessage: conv.last_message 
                }));
                setConversations(mappedData);
                setLoading(false);
            }
        } catch (e) {
            console.error('[Chat] Failed to load conversations:', e);
            if (isMounted.current) setLoading(false);
        } finally {
            conversationsFetchRef.current = false;
        }
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [session?.access_token]);

    // Initial load
    useEffect(() => {
        isMounted.current = true;
        if (authReady) {
            if (session && !hasInitialFetched.current) {
                console.log('[Chat] Initial load triggered by authReady');
                hasInitialFetched.current = true;
                loadConversations();
            } else if (!session) {
                setLoading(false);
            }
        }
        return () => { isMounted.current = false; };
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [authReady, session?.access_token]);

    // Socket listeners
    useEffect(() => {
        if (!socket || !connected) return;

        const processIncomingMessage = (msg: any) => {
            if (!isMounted.current) return;
            
            const newMessage: Message = {
                id: msg.id,
                conversation_id: msg.conversation_id,
                sender_id: msg.sender_id,
                content: msg.content,
                created_at: msg.created_at,
                type: msg.type,
                isOwn: msg.sender_id === user?.id,
                original_language: msg.original_language,
                attachment: msg.attachment,
                read_at: msg.read_at
            };

            if (msg.sender_id !== user?.id) {
                const sender = conversationsRef.current.find(c => c.id === msg.conversation_id)?.members.find(m => m.user_id === msg.sender_id)?.profile?.username || 'Someone';
                NotificationService.notifyNewMessage(sender, msg.content, msg.conversation_id);
            }

            setMessages(prev => {
                const current = prev[msg.conversation_id] || [];
                // Deduplicate to avoid issues between optimistic update and socket
                if (current.some(m => m.id === msg.id)) return prev;
                return {
                    ...prev,
                    [msg.conversation_id]: [...current, newMessage]
                };
            });

            // Update conversation unread count and last message
            setConversations(prev => prev.map(conv => {
                if (conv.id === msg.conversation_id) {
                    const isOtherMsg = msg.sender_id !== user?.id;
                    const isActive = msg.conversation_id === activeConversationId;
                    return {
                        ...conv,
                        updated_at: msg.created_at,
                        lastMessage: {
                            content: msg.content,
                            sender_id: msg.sender_id,
                            created_at: msg.created_at
                        },
                        unreadCount: (conv.unreadCount || 0) + (isOtherMsg && !isActive ? 1 : 0)
                    };
                }
                return conv;
            }));

            // Auto-mark as read if active
            if (msg.conversation_id === activeConversationId && msg.sender_id !== user?.id) {
                markMessageRead(msg.id);
            }
        };

        const onMessageRead = ({ messageId, conversationId }: any) => {
            setMessages(prev => {
                const convMessages = prev[conversationId] || [];
                // If message already marked read later, don't overwrite with older timestamp
                return {
                    ...prev,
                    [conversationId]: convMessages.map(m => 
                        m.id === messageId ? { ...m, read_at: m.read_at || new Date().toISOString() } : m
                    )
                };
            });

            // Also update the unread count if we just read the last message
            setConversations(prev => prev.map(conv => {
                if (conv.id === conversationId && conv.lastMessage) {
                    return {
                        ...conv,
                        unreadCount: Math.max(0, (conv.unreadCount || 0) - 1),
                        lastMessage: { 
                            ...conv.lastMessage, 
                            read_at: new Date().toISOString() 
                        }
                    };
                }
                return conv;
            }));
        };

        const onNewConversation = (newConv?: any) => {
            loadConversations();
            if (newConv && newConv.id && socket && connected) {
                socket.emit('join_room', newConv.id);
            }
        };

        const onConversationDeleted = ({ conversationId }: { conversationId: string }) => {
            setConversations(prev => prev.filter(c => c.id !== conversationId));
            if (activeConversationId === conversationId) {
                setActiveConversationId(null);
            }
            // Cleanup messages
            setMessages(prev => {
                const next = { ...prev };
                delete next[conversationId];
                return next;
            });
        };

        socket.on('receive_message', processIncomingMessage);
        socket.on('new_conversation', onNewConversation);
        socket.on('conversation_updated', onNewConversation);
        socket.on('message_read', onMessageRead);
        socket.on('conversation_deleted', onConversationDeleted);
        socket.on('message_deleted', ({ messageId, conversationId }: { messageId: string, conversationId: string }) => {
            setMessages(prev => {
                const convMessages = prev[conversationId] || [];
                return {
                    ...prev,
                    [conversationId]: convMessages.filter(m => m.id !== messageId)
                };
            });

            // Update conversation last message if the deleted message was the preview
            setConversations(prev => prev.map(conv => {
                if (conv.id === conversationId && conv.lastMessage && (conv.lastMessage as any).id === messageId) {
                    return {
                        ...conv,
                        lastMessage: undefined
                    };
                }
                return conv;
            }));
        });

        socket.on('message_edited', (editedMsg: Message) => {
            if (!editedMsg || !editedMsg.id) return;
            const conversationId = editedMsg.conversation_id;
            
            setMessages(prev => {
                const convMessages = prev[conversationId] || [];
                return {
                    ...prev,
                    [conversationId]: convMessages.map(m => m.id === editedMsg.id ? { ...m, content: editedMsg.content, is_edited: true, updated_at: editedMsg.updated_at } : m)
                };
            });

            // Update conversation lastMessage preview if it was edited
            setConversations(prev => prev.map(conv => {
                if (conv.id === conversationId && conv.lastMessage && (conv.lastMessage as any).sender_id === editedMsg.sender_id) {
                    // It's tricky to know if it's the absolute last message without searching messages state
                    // We'll just optimistically update it if the created_at matches
                    if (conv.lastMessage.created_at === editedMsg.created_at) {
                        return {
                            ...conv,
                            lastMessage: {
                                ...conv.lastMessage,
                                content: editedMsg.content
                            }
                        };
                    }
                }
                return conv;
            }));
        });

        socket.on('user_typing', ({ conversationId, userId, username }: { conversationId: string, userId: string, username: string }) => {
            if (userId === user?.id) return;
            setTypingUsers(prev => {
                const current = prev[conversationId] || [];
                if (current.includes(username)) return prev;
                return { ...prev, [conversationId]: [...current, username] };
            });
        });

        socket.on('user_stop_typing', ({ conversationId, userId, username }: { conversationId: string, userId: string, username: string }) => {
            if (userId === user?.id) return;
            setTypingUsers(prev => {
                const current = prev[conversationId] || [];
                return { ...prev, [conversationId]: current.filter(u => u !== username) };
            });
        });

        // Join rooms for all current conversations
        const joinAllRooms = () => {
            console.log('[Chat] Joining rooms for', conversationsRef.current.length, 'conversations');
            conversationsRef.current.forEach(conv => {
                socket.emit('join_room', conv.id);
            });
        };

        joinAllRooms();

        return () => {
            socket.off('receive_message', processIncomingMessage);
            socket.off('new_conversation', onNewConversation);
            socket.off('conversation_updated', onNewConversation);
            socket.off('message_read', onMessageRead);
            socket.off('conversation_deleted', onConversationDeleted);
            socket.off('message_deleted');
            socket.off('message_edited');
            socket.off('user_typing');
            socket.off('user_stop_typing');
        };
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [socket, connected, user?.id, loadConversations, activeConversationId]);

    const sendMessage = async (content: string, type: string = 'text', attachmentId?: string) => {
        if (!activeConversationId) throw new Error('No active conversation');
        return sendMessageToConversation(activeConversationId, content, type, attachmentId);
    };

    const sendMessageToConversation = async (conversationId: string, content: string, type: string = 'text', attachmentId?: string) => {
        if (!session || !user) throw new Error('Cannot send message');
        
        // ── Optimistic Update ────────────────────────────────────
        const tempId = `temp-${Date.now()}`;
        const optimisticMessage: Message = {
            id: tempId,
            conversation_id: conversationId,
            sender_id: user.id,
            content,
            created_at: new Date().toISOString(),
            type: type as any,
            isOwn: true,
            attachment: attachmentId ? { id: attachmentId, file_name: 'File', file_type: '', file_size: 0, storage_path: '', metadata: {} } : undefined
        };

        setMessages(prev => ({
            ...prev,
            [conversationId]: [...(prev[conversationId] || []), optimisticMessage]
        }));

        // Update conversation last message preview
        setConversations(prev => prev.map(conv => {
            if (conv.id === conversationId) {
                return {
                    ...conv,
                    lastMessage: {
                        content,
                        sender_id: user.id,
                        created_at: optimisticMessage.created_at
                    }
                };
            }
            return conv;
        }));

        try {
            const res = await fetch(`${API_URL}/api/chat/conversations/${conversationId}/messages`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${session.access_token}`
                },
                body: JSON.stringify({ content, type, attachmentId })
            });

            if (!res.ok) {
                const error = await res.json().catch(() => ({ error: 'Failed to send message' }));
                throw new Error(error.error || 'Failed to send message');
            }

            const data = await res.json();
            
            // Replace optimistic message with real one
            setMessages(prev => {
                const current = prev[conversationId] || [];
                return {
                    ...prev,
                    [conversationId]: current.map(m => m.id === tempId ? {
                        ...m,
                        id: data.id,
                        created_at: data.created_at,
                        original_language: data.original_language,
                        attachment: data.attachment,
                        read_at: data.read_at
                    } : m)
                };
            });
        } catch (err) {
            // Rollback on failure
            setMessages(prev => ({
                ...prev,
                [conversationId]: (prev[conversationId] || []).filter(m => m.id !== tempId)
            }));
            throw err;
        }
    };

    const sendTypingStatus = useCallback((isTyping: boolean) => {
        if (!socket || !connected || !activeConversationId || !user) return;
        const event = isTyping ? 'typing' : 'stop_typing';
        socket.emit(event, { 
            conversationId: activeConversationId, 
            userId: user.id,
            username: profile?.username || 'User'
        });
    }, [socket, connected, activeConversationId, user, profile?.username]);

    const loadMoreMessages = async (conversationId: string) => {
        const currentM = messages[conversationId] || [];
        if (currentM.length === 0 || !session) return;

        const oldest = currentM[0].created_at;
        
        try {
            const res = await fetch(`${API_URL}/api/chat/conversations/${conversationId}/messages?before=${oldest}&limit=30`, {
                headers: { 'Authorization': `Bearer ${session.access_token}` }
            });
            
            if (res.ok) {
                const data = await res.json();
                if (data.length < 30) {
                    setHasMore(prev => ({ ...prev, [conversationId]: false }));
                } else {
                    setHasMore(prev => ({ ...prev, [conversationId]: true }));
                }
                setMessages(prev => ({
                    ...prev,
                    [conversationId]: [...data, ...(prev[conversationId] || [])]
                }));
            }
        } catch (err) {
            console.error('[Chat] Load more failed:', err);
        }
    };

    const markMessageRead = async (messageId: string) => {
        if (!session) return;
        try {
            await fetch(`${API_URL}/api/chat/messages/${messageId}/read`, {
                method: 'PUT',
                headers: { 'Authorization': `Bearer ${session.access_token}` }
            });
        } catch (err) {
            console.error('[Chat] Failed to mark read:', err);
        }
    };

    const startConversation = async (username: string) => {
        if (!user || !session) throw new Error('Must be logged in');

        const res = await fetch(`${API_URL}/api/chat/conversations`, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${session.access_token}`
            },
            body: JSON.stringify({
                type: 'direct',
                name: username,
                participants: [username]
            })
        });

        if (res.ok) {
            const data = await res.json();
            if (socket && connected) {
                socket.emit('join_room', data.conversation.id);
            }
            await loadConversations();
            setActiveConversationId(data.conversation.id);
        } else {
            const err = await res.json();
            throw new Error(err.error || 'Failed to start chat');
        }
    };

    const acceptConversation = async (conversationId: string) => {
        if (!session) throw new Error('No session');
        
        try {
            const res = await fetch(`${API_URL}/api/chat/conversations/${conversationId}/accept`, {
                method: 'PUT',
                headers: { 'Authorization': `Bearer ${session.access_token}` }
            });
            
            if (res.ok) {
                loadConversations();
            }
        } catch (err) {
            console.error('[Chat] Failed to accept conversation:', err);
            throw err;
        }
    };

    const deleteConversation = async (conversationId: string) => {
        if (!session) throw new Error('No session');

        try {
            const res = await fetch(`${API_URL}/api/chat/conversations/${conversationId}`, {
                method: 'DELETE',
                headers: { 'Authorization': `Bearer ${session.access_token}` }
            });

            if (res.ok) {
                // The socket listener 'conversation_deleted' will handle state update for everyone
                // but we can proactively clear it for the deleting user too.
                setConversations(prev => prev.filter(c => c.id !== conversationId));
                if (activeConversationId === conversationId) {
                    setActiveConversationId(null);
                }
            } else {
                const data = await res.json();
                throw new Error(data.error || 'Failed to delete conversation');
            }
        } catch (err) {
            console.error('[Chat] Failed to delete conversation:', err);
            throw err;
        }
    };

    const deleteMessage = async (messageId: string) => {
        if (!session || !activeConversationId) throw new Error('No session or active chat');

        // Optimistic update
        let deletedMessage: Message | undefined;
        setMessages(prev => {
            const current = prev[activeConversationId] || [];
            deletedMessage = current.find(m => m.id === messageId);
            return {
                ...prev,
                [activeConversationId]: current.filter(m => m.id !== messageId)
            };
        });

        // Update conversation last message optimistically
        setConversations(prev => prev.map(conv => {
            if (conv.id === activeConversationId && conv.lastMessage && (conv.lastMessage as any).id === messageId) {
                return { ...conv, lastMessage: undefined };
            }
            return conv;
        }));

        try {
            const res = await fetch(`${API_URL}/api/chat/messages/${messageId}`, {
                method: 'DELETE',
                headers: { 'Authorization': `Bearer ${session.access_token}` }
            });

            if (!res.ok) {
                const data = await res.json();
                throw new Error(data.error || 'Failed to delete message');
            }
        } catch (err) {
            // Rollback
            if (deletedMessage) {
                setMessages(prev => ({
                    ...prev,
                    [activeConversationId]: [...(prev[activeConversationId] || []), deletedMessage!]
                        .sort((a, b) => new Date(a.created_at).getTime() - new Date(b.created_at).getTime())
                }));
            }
            console.error('[Chat] Failed to delete message:', err);
            throw err;
        }
    };

    const editMessage = async (messageId: string, content: string) => {
        if (!session || !activeConversationId) throw new Error('No session or active chat');

        // Optimistic update
        let oldMessageContent = '';
        setMessages(prev => {
            const current = prev[activeConversationId] || [];
            const msg = current.find(m => m.id === messageId);
            if (msg) oldMessageContent = msg.content;
            
            return {
                ...prev,
                [activeConversationId]: current.map(m => m.id === messageId ? { ...m, content, is_edited: true } : m)
            };
        });

        // Update conversation last message optimistically
        setConversations(prev => prev.map(conv => {
            if (conv.id === activeConversationId && conv.lastMessage && (conv.lastMessage as any).id === messageId) {
                 // Or by checking created_at
                 return { ...conv, lastMessage: { ...conv.lastMessage, content } };
            }
            return conv;
        }));

        try {
            const res = await fetch(`${API_URL}/api/chat/messages/${messageId}`, {
                method: 'PATCH',
                headers: { 
                    'Authorization': `Bearer ${session.access_token}`,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({ content })
            });

            if (!res.ok) {
                const data = await res.json();
                throw new Error(data.error || 'Failed to edit message');
            }
        } catch (err) {
            // Rollback
            if (oldMessageContent) {
                setMessages(prev => {
                    const current = prev[activeConversationId] || [];
                    return {
                        ...prev,
                        [activeConversationId]: current.map(m => m.id === messageId ? { ...m, content: oldMessageContent, is_edited: false } : m)
                    };
                });
            }
            console.error('[Chat] Failed to edit message:', err);
            throw err;
        }
    };

    const muteConversation = async (conversationId: string, isMuted: boolean) => {
        if (!session) throw new Error('No session');

        try {
            const res = await fetch(`${API_URL}/api/chat/conversations/${conversationId}/mute`, {
                method: 'PUT',
                headers: { 
                    'Authorization': `Bearer ${session.access_token}`,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({ isMuted })
            });

            if (res.ok) {
                setConversations(prev => prev.map(c => 
                    c.id === conversationId ? { ...c, is_muted: isMuted } : c
                ));
            } else {
                throw new Error('Failed to mute conversation');
            }
        } catch (err) {
            console.error('[Chat] Failed to mute conversation:', err);
            throw err;
        }
    };

    const clearChatHistory = async (conversationId: string) => {
        if (!session) throw new Error('No session');

        try {
            const res = await fetch(`${API_URL}/api/chat/conversations/${conversationId}/messages`, {
                method: 'DELETE',
                headers: { 'Authorization': `Bearer ${session.access_token}` }
            });

            if (res.ok) {
                setMessages(prev => ({
                    ...prev,
                    [conversationId]: []
                }));
                // Reset pagination
                setHasMore(prev => ({ ...prev, [conversationId]: false }));
            } else {
                throw new Error('Failed to clear chat history');
            }
        } catch (err) {
            console.error('[Chat] Failed to clear chat history:', err);
            throw err;
        }
    };

    // Load messages for active conversation
    useEffect(() => {
        if (!activeConversationId || !session) return;

        const fetchMessages = async () => {
            try {
                const res = await fetch(`${API_URL}/api/chat/conversations/${activeConversationId}/messages`, {
                    headers: { 'Authorization': `Bearer ${session.access_token}` }
                });
                
                if (!res.ok) return;
                
                const rawMessages = await res.json();
                if (!isMounted.current) return;

                const messageList: Message[] = rawMessages.map((msg: any) => ({
                    id: msg.id,
                    conversation_id: msg.conversation_id,
                    sender_id: msg.sender_id,
                    content: msg.content,
                    created_at: msg.created_at,
                    type: msg.type,
                    isOwn: msg.sender_id === user?.id,
                    original_language: msg.original_language,
                    attachment: msg.attachment,
                    read_at: msg.read_at
                }));

                setMessages(prev => ({ ...prev, [activeConversationId]: messageList }));
                setHasMore(prev => ({ ...prev, [activeConversationId]: rawMessages.length >= 50 }));

                // Mark last message as read if not own
                const lastMsg = messageList[messageList.length - 1];
                if (lastMsg && !lastMsg.isOwn && !lastMsg.read_at) {
                    markMessageRead(lastMsg.id);
                }
            } catch (err) {
                console.error('[Chat] Failed to fetch messages:', err);
            }
        };

        fetchMessages();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [activeConversationId, session?.access_token, user?.id]);

    return (
        <ChatContext.Provider value={{ 
            conversations, 
            messages, 
            sendMessage, 
            startConversation, 
            acceptConversation, 
            deleteConversation,
            deleteMessage,
            editMessage,
            muteConversation,
            clearChatHistory,
            sendMessageToConversation,
            loading, 
            activeConversationId, 
            setActiveConversationId,
            connected,
            loadMoreMessages,
            markMessageRead,
            sendTypingStatus,
            typingUsers,
            hasMore
        }}>
            {children}
        </ChatContext.Provider>
    );
};

import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { supabase, supabaseSafe, resetRateLimiters } from '../lib/supabaseSafe';
import { useAuth } from './AuthContext';
import type { Note } from '../types/note';

interface NotesContextType {
    notes: Note[];
    stats: { totalBy: number; favorites: number };
    loading: boolean;
    canCreateNote: boolean;
    refreshNotes: (searchTerm?: string, sortBy?: string) => Promise<void>;
}

const NotesContext = createContext<NotesContextType | undefined>(undefined);

export const NotesProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const { user, isPro } = useAuth();
    const [notes, setNotes] = useState<Note[]>([]);
    const [stats, setStats] = useState({ totalBy: 0, favorites: 0 });
    const [loading, setLoading] = useState(true);
    const [hasFetched, setHasFetched] = useState(false);

    const canCreateNote = isPro || stats.totalBy < 100;

    /**
     * Fetch notes from the database with caching and rate-limiting.
     */
    const fetchNotes = useCallback(async (searchTerm = '', sortBy = 'latest') => {
        if (!user) return;
        
        try {
            // Using a unique key per user/search/sort configuration for the cache
            const results = await supabaseSafe<Note[]>(
                `notes-list-${user.id}-${searchTerm}-${sortBy}`,
                async () => {
                    let query = supabase
                        .from('notes')
                        .select('*')
                        .eq('owner_id', user.id);

                    if (sortBy === 'latest') query = query.order('updated_at', { ascending: false });
                    else if (sortBy === 'oldest') query = query.order('updated_at', { ascending: true });
                    else if (sortBy === 'title') query = query.order('title', { ascending: true });

                    if (searchTerm) {
                        query.ilike('title', `%${searchTerm}%`);
                    }
                    return query;
                },
                { fallback: [] }
            );
            
            setNotes(results || []);

            // Also update stats if it's the main list fetch
            if (!searchTerm) {
                const [totalRes, favRes] = await Promise.all([
                    supabase
                      .from('notes')
                      .select('id', { count: 'exact', head: true })
                      .eq('owner_id', user.id),
                    supabase
                      .from('notes')
                      .select('id', { count: 'exact', head: true })
                      .eq('owner_id', user.id)
                      .eq('is_favorite', true)
                ]);
                setStats({
                    totalBy: totalRes.count || 0,
                    favorites: favRes.count || 0
                });
            }
        } catch (error) {
            console.error('[NotesContext] Error fetching notes:', error);
        } finally {
            setLoading(false);
        }
    }, [user]);

    /**
     * Real-time Synchronization
     * Listens for changes to the 'notes' table for the current user.
     */
    useEffect(() => {
        if (!user) {
            setNotes([]);
            setLoading(false);
            return;
        }

        // Initial fetch - 🔥 Production-safe guard
        if (!hasFetched) {
            fetchNotes();
            setHasFetched(true);
        }

        // 1. Subscribe to changes for this user's notes
        const channel = supabase
            .channel(`notes-sync-${user.id}`)
            .on(
                'postgres_changes',
                {
                    event: '*',
                    schema: 'public',
                    table: 'notes',
                    filter: `owner_id=eq.${user.id}`
                },
                (payload) => {
                    console.log('[NotesContext] Real-time activity detected:', payload.eventType);
                    
                    // 2. Invalidate relevant caches in supabaseSafe
                    // This ensures the NEXT fetchNotes (e.g. after a search change) gets fresh data.
                    resetRateLimiters('notes-list-');

                    // 3. Update local state immediately (Optimistic UI)
                    if (payload.eventType === 'INSERT') {
                        const newNote = payload.new as Note;
                        setNotes(prev => {
                            if (prev.some(n => n.id === newNote.id)) return prev;
                            return [newNote, ...prev];
                        });
                        setStats(prev => ({ ...prev, totalBy: prev.totalBy + 1 }));
                    } else if (payload.eventType === 'UPDATE') {
                        const updatedNote = payload.new as Note;
                        setNotes(prev => prev.map(n => n.id === updatedNote.id ? updatedNote : n));
                        
                        // Recalculate favorites if changed
                        if (payload.old.is_favorite !== payload.new.is_favorite) {
                            setStats(prev => ({ 
                                ...prev, 
                                favorites: payload.new.is_favorite ? prev.favorites + 1 : prev.favorites - 1 
                            }));
                        }
                    } else if (payload.eventType === 'DELETE') {
                        const deletedId = payload.old.id;
                        setNotes(prev => {
                            const wasFavorite = prev.find(n => n.id === deletedId)?.is_favorite;
                            if (wasFavorite !== undefined) {
                                setStats(s => ({ 
                                    totalBy: Math.max(0, s.totalBy - 1),
                                    favorites: wasFavorite ? Math.max(0, s.favorites - 1) : s.favorites
                                }));
                            }
                            return prev.filter(n => n.id !== deletedId);
                        });
                    }
                }
            )
            .subscribe((status) => {
               if (status === 'SUBSCRIBED') {
                   console.log('[NotesContext] Real-time subscription active.');
               }
            });

        return () => {
            supabase.removeChannel(channel);
        };
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [user, fetchNotes, hasFetched]);

    return (
        <NotesContext.Provider value={{ notes, stats, loading, canCreateNote, refreshNotes: fetchNotes }}>
            {children}
        </NotesContext.Provider>
    );
};

export const useNotes = () => {
    const context = useContext(NotesContext);
    if (context === undefined) {
        throw new Error('useNotes must be used within a NotesProvider');
    }
    return context;
};

import React, { createContext, useContext, useEffect, useState, useRef } from 'react';
import { useSocket } from './SocketContext';
import { useAuth } from './AuthContext';

interface PresenceState {
    isOnline: boolean;
    lastSeen: string | null;
}

interface PresenceContextValue {
    presenceMap: Record<string, PresenceState>;
    isUserOnline: (userId: string) => boolean;
    getUserLastSeen: (userId: string) => string | null;
}

const PresenceContext = createContext<PresenceContextValue>({
    presenceMap: {},
    isUserOnline: () => false,
    getUserLastSeen: () => null
});

// Use named function for provider to help Fast Refresh
export function PresenceProvider({ children }: { children: React.ReactNode }) {
    const { socket, connected } = useSocket();
    const { user } = useAuth();
    const [presenceMap, setPresenceMap] = useState<Record<string, PresenceState>>({});
    const heartbeatTimer = useRef<any>(null);

    // Initial load and heartbeat
    useEffect(() => {
        if (!connected || !socket || !user) {
            if (heartbeatTimer.current) clearInterval(heartbeatTimer.current);
            return;
        }

        console.log('[Presence] Initializing presence tracking...');

        // Start heartbeat every 30 seconds
        heartbeatTimer.current = setInterval(() => {
            socket.emit('presence:heartbeat');
        }, 30000);

        // Immediate heartbeat on connect
        socket.emit('presence:heartbeat');

        // Clean up on unmount or logout
        const handleBeforeUnload = () => {
            socket.emit('presence:offline');
        };
        window.addEventListener('beforeunload', handleBeforeUnload);

        // Listen for new Privacy toggle changes from the UI
        const handleSettingsChange = (e: any) => {
            if (e.detail && 'show_online_status' in e.detail) {
                socket.emit('presence:settings_changed', { show_online_status: e.detail.show_online_status });
            }
        };
        window.addEventListener('presence:settings_changed', handleSettingsChange);

        return () => {
            if (heartbeatTimer.current) clearInterval(heartbeatTimer.current);
            window.removeEventListener('beforeunload', handleBeforeUnload);
            window.removeEventListener('presence:settings_changed', handleSettingsChange);
        };
    }, [connected, socket, user]);

    // Listen for presence updates from server
    useEffect(() => {
        if (!socket) return;

        const handleInitialPresence = (onlineIds: string[]) => {
            const initialMap: Record<string, PresenceState> = {};
            onlineIds.forEach(id => {
                initialMap[id] = { isOnline: true, lastSeen: null };
            });
            setPresenceMap(prev => ({ ...prev, ...initialMap }));
        };

        const handleUserOnline = ({ userId, online, lastSeen }: { userId: string, online: boolean, lastSeen?: string }) => {
            setPresenceMap(prev => ({
                ...prev,
                [userId]: {
                    isOnline: online,
                    lastSeen: lastSeen || prev[userId]?.lastSeen || null
                }
            }));
        };

        socket.on('presence:initial', handleInitialPresence);
        socket.on('user_online', handleUserOnline);

        return () => {
            socket.off('presence:initial', handleInitialPresence);
            socket.off('user_online', handleUserOnline);
        };
    }, [socket]);

    const isUserOnline = (userId: string) => {
        return presenceMap[userId]?.isOnline || false;
    };

    const getUserLastSeen = (userId: string) => {
        return presenceMap[userId]?.lastSeen || null;
    };

    return (
        <PresenceContext.Provider value={{ presenceMap, isUserOnline, getUserLastSeen }}>
            {children}
        </PresenceContext.Provider>
    );
}

export function usePresence() {
    return useContext(PresenceContext);
}

import React, { createContext, useContext, useEffect, useRef, useState } from 'react';
import { io, Socket } from 'socket.io-client';
import { useAuth } from './AuthContext';
import toast from 'react-hot-toast';

// ─── Config ──────────────────────────────────────────────────────
// Vite loads the correct URL from .env.development or .env.production
const SOCKET_URL = import.meta.env.VITE_SOCKET_URL;

if (!SOCKET_URL && import.meta.env.PROD) {
    console.error('❌ CRITICAL: VITE_SOCKET_URL is not defined in production environment!');
}


// ─── Types ───────────────────────────────────────────────────────
interface SocketContextValue {
    socket: Socket | null;
    connected: boolean;
    error: string | null;
}

const SocketContext = createContext<SocketContextValue>({
    socket: null,
    connected: false,
    error: null,
});

export const useSocket = () => useContext(SocketContext);

// ─── Provider ────────────────────────────────────────────────────
export const SocketProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const { session, authReady, user } = useAuth();
    const [connected, setConnected] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const socketRef = useRef<Socket | null>(null);
    const retryCount = useRef(0);
    const MAX_RETRIES = 10;

    useEffect(() => {
        // ── Gate: wait until auth is fully ready ──────────────
        if (!authReady || !session?.access_token || !user) {
            // Tear down existing socket if session is lost
            if (socketRef.current) {
                console.log('[Socket] Auth lost — disconnecting');
                socketRef.current.disconnect();
                socketRef.current = null;
                setConnected(false);
            }
            return;
        }

        // ── Guard: prevent double creation ───────────────────
        if (socketRef.current) return;

        console.log('[Socket] Connecting to', SOCKET_URL);

        const socket = io(SOCKET_URL, {
            auth: { token: session.access_token },
            withCredentials: true,
            // IMPORTANT: start with polling, then upgrade.
            // This avoids "WebSocket closed before established" errors.
            transports: ['polling', 'websocket'],
            reconnection: true,
            reconnectionAttempts: MAX_RETRIES,
            reconnectionDelay: 2000,
            timeout: 20000,
        });

        socket.on('connect', () => {
            const transport = socket.io.engine.transport.name;
            console.log(`[Socket] ✓ Connected via ${transport}`);
            setConnected(true);
            setError(null);
            retryCount.current = 0;

            // Log the upgrade when it happens
            socket.io.engine.on('upgrade', (t: any) => {
                console.log(`[Socket] ↑ Upgraded to ${t.name}`);
            });
        });

        socket.on('disconnect', (reason) => {
            console.log('[Socket] Disconnected:', reason);
            setConnected(false);
            // If the server kicked us, reconnect manually
            if (reason === 'io server disconnect') {
                socket.connect();
            }
        });

        socket.on('connect_error', (err) => {
            console.error('[Socket] Connection error:', err.message);
            setError(err.message);
            setConnected(false);

            if (retryCount.current < MAX_RETRIES) {
                retryCount.current++;
                console.log(`[Socket] Retrying (${retryCount.current}/${MAX_RETRIES})…`);
            } else {
                toast.error('Real-time connection failed. Please refresh.');
            }
        });

        socketRef.current = socket;

        // ── Cleanup on unmount or dependency change ──────────
        return () => {
            console.log('[Socket] Cleaning up…');
            socket.disconnect();
            socketRef.current = null;
            setConnected(false);
        };
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [authReady, session?.access_token, user?.id]);

    return (
        <SocketContext.Provider value={{ socket: socketRef.current, connected, error }}>
            {children}
        </SocketContext.Provider>
    );
};

// ====================================
// TEAM CHAT CONTEXT
// Real-time team collaboration with safety
// ====================================

import React, { createContext, useContext, useEffect, useRef, useState, useCallback } from 'react';
import { RealtimeChannel } from '@supabase/supabase-js';
import { supabase } from '../lib/supabaseSafe';
import { useAuth } from './AuthContext';
import toast from 'react-hot-toast';
import {
  getTeamMessages,
  sendMessage as apiSendMessage,
  markMessagesRead,
  getTeamMembers,
  shareNote as apiShareNote,
  getTeamStats,
  deleteTeamMessage,
  editTeamMessage,
  clearTeamChatHistory,
} from '../lib/teamsApi';
import type {
  TeamMessage,
  TeamMember,
  SendMessageRequest,
  ShareNoteRequest,
  RealtimePayload,
  TeamStats,
} from '../types/teams';

// ====================================
// CONTEXT TYPES
// ====================================

interface TeamChatContextValue {
  messages: TeamMessage[];
  members: TeamMember[];
  loading: boolean;
  connected: boolean;
  sendMessage: (content: string, metadata?: Record<string, any>, type?: import('../types/teams').MessageType) => Promise<void>;
  shareNote: (noteId: string, permission?: 'read' | 'edit') => Promise<void>;
  loadMoreMessages: () => Promise<void>;
  hasMore: boolean;
  deleteMessage: (messageId: string) => Promise<void>;
  editMessage: (messageId: string, content: string) => Promise<void>;
  clearChatHistory: () => Promise<void>;
  sendTypingStatus: (isTyping: boolean) => void;
  typingUsers: string[];
  teamStats: TeamStats | null;
  error: string | null;
}

const TeamChatContext = createContext<TeamChatContextValue>({
  messages: [],
  members: [],
  loading: true,
  connected: false,
  sendMessage: async () => { /* Default placeholder */ },
  shareNote: async () => { /* Default placeholder */ },
  loadMoreMessages: async () => { /* Default placeholder */ },
  hasMore: false,
  deleteMessage: async () => { /* Default placeholder */ },
  editMessage: async () => { /* Default placeholder */ },
  clearChatHistory: async () => { /* Default placeholder */ },
  sendTypingStatus: () => { /* Default placeholder */ },
  typingUsers: [],
  teamStats: null,
  error: null,
});

export const useTeamChat = () => useContext(TeamChatContext);

// ====================================
// PROVIDER PROPS
// ====================================

interface TeamChatProviderProps {
  teamId: string;
  children: React.ReactNode;
}

// ====================================
// EXPONENTIAL BACKOFF CONFIG
// ====================================

const BACKOFF_CONFIG = {
  initialDelay: 1000,
  maxDelay: 30000,
  maxRetries: 5,
};

// ====================================
// PROVIDER COMPONENT
// ====================================

export const TeamChatProvider: React.FC<TeamChatProviderProps> = ({ teamId, children }) => {
  const { user, profile, authReady } = useAuth();
  const [messages, setMessages] = useState<TeamMessage[]>([]);
  const [members, setMembers] = useState<TeamMember[]>([]);
  const [loading, setLoading] = useState(true);
  const [connected, setConnected] = useState(false);
  const [hasMore, setHasMore] = useState(true);
  const [typingUsers, setTypingUsers] = useState<string[]>([]);
  const [teamStats, setTeamStats] = useState<TeamStats | null>(null);
  const [error, setError] = useState<string | null>(null);

  // Refs for lifecycle and safety
  const isMounted = useRef(true);
  const channelRef = useRef<RealtimeChannel | null>(null);
  const loadingRef = useRef(false);
  const sendCooldownRef = useRef(false);
  const retryCountRef = useRef(0);
  const retryTimeoutRef = useRef<any>(null);
  const lastMessageIdRef = useRef<string | null>(null);

  // ====================================
  // LOAD INITIAL DATA
  // ====================================

  const lastLoadedTeamId = useRef<string | null>(null);
  const messagesCountRef = useRef(0);

  const loadInitialData = useCallback(async () => {
    if (loadingRef.current || !teamId || !user || !profile || !authReady) return;
    
    // If we already loaded this team and have data, only reload if forced or empty
    if (lastLoadedTeamId.current === teamId && messagesCountRef.current > 0) return;

    loadingRef.current = true;
    setLoading(true);
    setError(null);
    lastLoadedTeamId.current = teamId;

    try {
      // Load in parallel for speed
      const [messagesData, membersData, statsData] = await Promise.all([
        getTeamMessages(teamId, 50),
        getTeamMembers(teamId),
        getTeamStats(teamId)
      ]);

      if (!isMounted.current) return;

      messagesCountRef.current = messagesData.length;
      setMessages(messagesData);
      setMembers(membersData);
      setTeamStats(statsData);

      // Mark as read
      await markMessagesRead(teamId);

      if (messagesData.length < 50) {
        setHasMore(false);
      } else {
        setHasMore(true);
      }

      lastMessageIdRef.current =
        messagesData.length > 0 ? messagesData[messagesData.length - 1].id : null;
    } catch (err: any) {
      console.error('[TeamChat] Failed to load initial data:', err);
      if (isMounted.current) {
        setError('Failed to load chat. Please refresh.');
        toast.error('Failed to load chat');
      }
    } finally {
      loadingRef.current = false;
      if (isMounted.current) {
        setLoading(false);
      }
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [teamId, user, profile, authReady]);

  // ====================================
  // LOAD MORE MESSAGES (PAGINATION)
  // ====================================

  const loadMoreMessages = useCallback(async () => {
    if (loadingRef.current || !hasMore || messages.length === 0) return;

    loadingRef.current = true;

    try {
      const oldestMessage = messages[0];
      const olderMessages = await getTeamMessages(teamId, 50, oldestMessage.created_at);

      if (!isMounted.current) return;

      setMessages((prev) => [...olderMessages, ...prev]);

      if (olderMessages.length < 50) {
        setHasMore(false);
      }
    } catch (err) {
      console.error('[TeamChat] Failed to load more messages:', err);
      toast.error('Failed to load older messages');
    } finally {
      loadingRef.current = false;
    }
  }, [teamId, messages, hasMore]);

  // ====================================
  // DELETE MESSAGE
  // ====================================

  const deleteMessage = useCallback(async (messageId: string) => {
    if (!teamId) return;
    try {
      const success = await deleteTeamMessage(teamId, messageId);
      if (success && isMounted.current) {
        setMessages(prev => prev.filter(m => m.id !== messageId));
      }
    } catch (err) {
      console.error('[TeamChat] Failed to delete message:', err);
      toast.error('Failed to delete message');
    }
  }, [teamId]);

  const editMessage = useCallback(async (messageId: string, newContent: string) => {
    if (!teamId) return;
    
    // Optimistic update
    let oldContent = '';
    setMessages(prev => {
      const msg = prev.find(m => m.id === messageId);
      if (msg) oldContent = msg.content || '';
      return prev.map(m => m.id === messageId ? { ...m, content: newContent, is_edited: true, updated_at: new Date().toISOString() } : m);
    });

    try {
      const success = await editTeamMessage(teamId, messageId, newContent);
      if (!success) {
        throw new Error('Failed to edit team message');
      }
    } catch (err) {
      console.error('[TeamChat] Editing message failed:', err);
      // Rollback
      if (oldContent) {
        setMessages(prev => prev.map(m => m.id === messageId ? { ...m, content: oldContent, is_edited: false } : m));
      }
      toast.error('Failed to edit message');
    }
  }, [teamId]);

  const clearChatHistory = useCallback(async () => {
    if (!teamId) return;
    try {
      const success = await clearTeamChatHistory(teamId);
      if (success && isMounted.current) {
        setMessages([]);
        toast.success('Chat history cleared');
      }
    } catch (err) {
      console.error('[TeamChat] Failed to clear chat history:', err);
      toast.error('Failed to clear chat history');
    }
  }, [teamId]);

  // ====================================
  // SEND MESSAGE (WITH OPTIMISTIC UI)
  // ====================================

  const sendMessage = useCallback(
    async (content: string, metadata?: Record<string, any>, type: import('../types/teams').MessageType = 'text') => {
      if (!user || (!content.trim() && !metadata?.image_url && !metadata?.audio_url)) return;

      // Cooldown check (prevent spam)
      if (sendCooldownRef.current) {
        toast.error('Please wait before sending another message');
        return;
      }

      sendCooldownRef.current = true;
      setTimeout(() => {
        sendCooldownRef.current = false;
      }, 1000); // 1s cooldown

      // Optimistic message
      const optimisticId = `temp-${Date.now()}`;
      const optimisticMessage: TeamMessage = {
        id: optimisticId,
        team_id: teamId,
        sender_id: user.id,
        content,
        message_type: type,
        metadata: metadata ?? {},
        created_at: new Date().toISOString(),
        updated_at: new Date().toISOString(),
        is_deleted: false,
        isOwn: true,
        isOptimistic: true,
        sender: {
          id: user.id,
          email: user.email ?? '',
          username: user.user_metadata?.username,
          full_name: user.user_metadata?.full_name,
          avatar_url: user.user_metadata?.avatar_url,
        },
      };

      // Add optimistically
      setMessages((prev) => [...prev, optimisticMessage]);

      try {
        const req: SendMessageRequest = {
          content,
          message_type: type,
          metadata,
        };

        const result = await apiSendMessage(teamId, req);

        if (!result) throw new Error('Failed to send message');

        // Replace optimistic with real (realtime will handle this, but fallback)
        if (!isMounted.current) return;
        
        setMessages((prev) =>
          prev.map((msg) => (msg.id === optimisticId ? { ...result, isOwn: true } : msg))
        );
      } catch (err: any) {
        console.error('[TeamChat] Failed to send message:', err);

        // Mark optimistic message as failed
        if (isMounted.current) {
          setMessages((prev) =>
            prev.map((msg) => (msg.id === optimisticId ? { ...msg, failed: true } : msg))
          );
          toast.error('Failed to send message');
        }
      }
    },
    [teamId, user]
  );

  // ====================================
  // SHARE NOTE
  // ====================================

  const shareNote = useCallback(
    async (noteId: string, permission: 'read' | 'edit' = 'read') => {
      try {
        const req: ShareNoteRequest = {
          note_id: noteId,
          permission,
        };

        const result = await apiShareNote(teamId, req);

        if (!result) throw new Error('Failed to share note');

        toast.success('Note shared successfully');
      } catch (err: any) {
        console.error('[TeamChat] Failed to share note:', err);
        toast.error(err.message || 'Failed to share note');
      }
    },
    [teamId]
  );
  
  // ====================================
  // TYPING INDICATORS (BROADCAST)
  // ====================================
  
  const typingTimersRef = useRef<Record<string, any>>({});

  const sendTypingStatus = useCallback((isTyping: boolean) => {
    if (!channelRef.current || !user || !profile) return;
    
    channelRef.current.send({
      type: 'broadcast',
      event: 'user_typing',
      payload: { 
        userId: user.id, 
        userName: profile.full_name || profile.username || 'Someone',
        isTyping 
      }
    });
  }, [user, profile]);

  // Handler for typing events
  const handleTypingEvent = useCallback((payload: any) => {
    const { userId, userName, isTyping } = payload;
    if (userId === user?.id) return;

    if (isTyping) {
      setTypingUsers(prev => prev.includes(userName) ? prev : [...prev, userName]);
      
      // Auto-clear after 5 seconds if no 'stop' received
      if (typingTimersRef.current[userId]) {
        clearTimeout(typingTimersRef.current[userId]);
      }
      typingTimersRef.current[userId] = setTimeout(() => {
        setTypingUsers(prev => prev.filter(u => u !== userName));
      }, 5000);
    } else {
      if (typingTimersRef.current[userId]) {
        clearTimeout(typingTimersRef.current[userId]);
      }
      setTypingUsers(prev => prev.filter(u => u !== userName));
    }
  }, [user?.id]);

  // ====================================
  // REALTIME SUBSCRIPTION (WITH SAFETY)
  // ====================================

  const setupRealtime = useCallback(() => {
    if (!teamId || !user || !profile || !authReady) return;

    // Clean up existing channel
    if (channelRef.current) {
      console.log('[TeamChat] Cleaning up existing channel');
      supabase.removeChannel(channelRef.current);
      channelRef.current = null;
    }

    console.log('[TeamChat] Setting up realtime for team:', teamId);

    try {
      const channel = supabase.channel(`team:${teamId}`, {
        config: {
          broadcast: { self: false },
          presence: { key: user.id },
        },
      });

      // Listen for new messages
      channel.on(
        'postgres_changes' as any,
        {
          event: 'INSERT',
          schema: 'public',
          table: 'team_messages',
          filter: `team_id=eq.${teamId}`,
        },
        async (payload: RealtimePayload<TeamMessage>) => {
          if (!isMounted.current) return;

          console.log('[TeamChat] New message received:', payload.new);

          const newMessage = payload.new;

          // Prevent duplicates
          setMessages((prev) => {
            const exists = prev.some((m) => m.id === newMessage.id);
            if (exists) return prev;

            // Remove optimistic if exists
            const filtered = prev.filter((m) => !m.isOptimistic);

            return [...filtered, { ...newMessage, isOwn: newMessage.sender_id === user.id }];
          });

          // Mark as read
          if (newMessage.sender_id !== user.id) {
            await markMessagesRead(teamId);
          }
        }
      );

      // Listen for message updates (like soft deletion)
      channel.on(
        'postgres_changes' as any,
        {
          event: 'UPDATE',
          schema: 'public',
          table: 'team_messages',
          filter: `team_id=eq.${teamId}`,
        },
        async (payload: RealtimePayload<TeamMessage>) => {
          if (!isMounted.current) return;
          const updatedMsg = payload.new;
          if (updatedMsg.is_deleted) {
             setMessages(prev => prev.filter(m => m.id !== updatedMsg.id));
          } else if (updatedMsg.is_edited) {
             setMessages(prev => prev.map(m => m.id === updatedMsg.id ? { ...m, content: updatedMsg.content, is_edited: true, updated_at: updatedMsg.updated_at } : m));
          } else if (updatedMsg.content) {
             // Catch-all for other updates that change content
             setMessages(prev => prev.map(m => m.id === updatedMsg.id ? { ...m, content: updatedMsg.content, updated_at: updatedMsg.updated_at, is_edited: updatedMsg.is_edited } : m));
          }
        }
      );

      // Listen for member changes
      channel.on(
        'postgres_changes',
        {
          event: '*',
          schema: 'public',
          table: 'team_members',
          filter: `team_id=eq.${teamId}`,
        },
        async () => {
          if (!isMounted.current) return;
          console.log('[TeamChat] Member change detected, reloading members');
          const updatedMembers = await getTeamMembers(teamId);
          if (isMounted.current) {
            setMembers(updatedMembers);
          }
        }
      );

      // Subscribe with error handling
      channel
        .subscribe((status) => {
          console.log('[TeamChat] Subscription status:', status);

          if (status === 'SUBSCRIBED') {
            setConnected(true);
            retryCountRef.current = 0;
            toast.success('Connected to team chat', { duration: 2000, icon: '🟢' });
          } else if (status === 'CHANNEL_ERROR' || status === 'TIMED_OUT') {
            setConnected(false);
            handleReconnect();
          } else if (status === 'CLOSED') {
            setConnected(false);
          }
        });

      // Listen for typing broadcast
      channel.on('broadcast', { event: 'user_typing' }, ({ payload }) => {
        handleTypingEvent(payload);
      });

      channelRef.current = channel;
    } catch (err) {
      console.error('[TeamChat] Failed to setup realtime:', err);
      setConnected(false);
      handleReconnect();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [teamId, user, profile, authReady]);

  // ====================================
  // RECONNECTION WITH EXPONENTIAL BACKOFF
  // ====================================

  const handleReconnect = useCallback(() => {
    if (retryCountRef.current >= BACKOFF_CONFIG.maxRetries) {
      console.warn('[TeamChat] Max retries reached, switching to polling');
      toast.error('Real-time connection lost. Refresh to reconnect.', { duration: 5000 });
      setConnected(false);
      return;
    }

    retryCountRef.current += 1;
    const delay = Math.min(
      BACKOFF_CONFIG.initialDelay * Math.pow(2, retryCountRef.current - 1),
      BACKOFF_CONFIG.maxDelay
    );

    console.log(
      `[TeamChat] Reconnecting in ${delay}ms (attempt ${retryCountRef.current}/${BACKOFF_CONFIG.maxRetries})`
    );

    if (retryTimeoutRef.current) {
      clearTimeout(retryTimeoutRef.current);
    }

    retryTimeoutRef.current = setTimeout(() => {
      if (isMounted.current) {
        setupRealtime();
      }
    }, delay);
  }, [setupRealtime]);

  // ====================================
  // EFFECTS
  // ====================================

  // Load initial data on mount
  useEffect(() => {
    isMounted.current = true;
    loadInitialData();

    return () => {
      isMounted.current = false;
    };
  }, [loadInitialData]);

  // Setup realtime after initial load
  useEffect(() => {
    if (!loading && teamId && user && profile && authReady) {
      setupRealtime();
    }

    return () => {
      if (channelRef.current) {
        console.log('[TeamChat] Cleaning up channel on unmount');
        supabase.removeChannel(channelRef.current);
        channelRef.current = null;
      }
      if (retryTimeoutRef.current) {
        clearTimeout(retryTimeoutRef.current);
      }
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [loading, teamId, user, setupRealtime]);

  // ====================================
  // CONTEXT VALUE
  // ====================================

  const value: TeamChatContextValue = {
    messages,
    members,
    loading,
    connected,
    sendMessage,
    shareNote,
    loadMoreMessages,
    hasMore,
    deleteMessage,
    editMessage,
    clearChatHistory,
    sendTypingStatus,
    typingUsers,
    teamStats,
    error,
  };

  return <TeamChatContext.Provider value={value}>{children}</TeamChatContext.Provider>;
};

import React, { createContext, useEffect, useState, useCallback, useRef } from 'react';
import { supabase } from '../lib/supabaseSafe';
import walletApi from '../api/walletApi';
import type { Wallet, Transaction, InternalTransferRequest, WithdrawalRequest, CommissionSettings } from '@/types/wallet';
import { useAuth } from './AuthContext';
import toast from 'react-hot-toast';

export interface WalletContextValue {
    wallets: Wallet[];
    transactions: Transaction[];
    loading: boolean;
    error: string | null;
    refresh: () => Promise<void>;
    createWallet: (currency: string, network?: string) => Promise<Wallet>;
    sendFunds: (data: InternalTransferRequest) => Promise<void>;
    withdraw: (data: WithdrawalRequest) => Promise<void>;
    getCommissionRate: (type: string, currency: string) => Promise<CommissionSettings[]>;
}

export const WalletContext = createContext<WalletContextValue | null>(null);

export const WalletProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const { user, profile, authReady } = useAuth();
    const [wallets, setWallets] = useState<Wallet[]>([]);
    const [transactions, setTransactions] = useState<Transaction[]>([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    const fetchingRef = useRef(false);

    const fetchData = useCallback(async () => {
        if (!user || !profile || !authReady) return;
        if (fetchingRef.current) return;
        
        fetchingRef.current = true;
        setLoading(true);
        setError(null);

        try {
            const [walletsData, transactionsData] = await Promise.all([
                walletApi.getWallets(),
                walletApi.getTransactions()
            ]);

            // Defensive checks: API might return { error: "..." } instead of array
            setWallets(Array.isArray(walletsData) ? walletsData : []);
            setTransactions(Array.isArray(transactionsData?.transactions) ? transactionsData.transactions : []);
        } catch (err) {
            console.error('Error fetching wallet data:', err);
            setError(err instanceof Error ? err.message : 'Failed to load wallet data');
        } finally {
            setLoading(false);
            fetchingRef.current = false;
        }
    }, [user, profile, authReady]);

    // Initial Load
    useEffect(() => {
        if (authReady && user && profile) {
            fetchData();
        } else if (authReady && (!user || !profile)) {
            setWallets([]);
            setTransactions([]);
            setLoading(false);
        }
    }, [user, profile, authReady, fetchData]);

    // Real-time Updates (Listen to ledger and transaction changes)
    useEffect(() => {
        if (!user) return;

        // 1. Listen to Ledger Entries (Balance Source of Truth)
        const ledgerChannel = supabase.channel(`ledger_realtime:${user.id}`)
            .on(
                'postgres_changes',
                {
                    event: '*',
                    schema: 'public',
                    table: 'ledger_entries',
                    filter: `user_id=eq.${user.id}`
                },
                (payload) => {
                    console.log('Ledger update received (Balance Refresh):', payload.eventType);
                    fetchData(); // Recalculate balances
                }
            )
            .subscribe();

        // 2. Listen to Transactions (History Source of Truth)
        const txChannel = supabase.channel(`tx_realtime:${user.id}`)
             .on(
                'postgres_changes',
                {
                    event: '*',
                    schema: 'public',
                    table: 'transactions',
                    filter: `user_id=eq.${user.id}`
                },
                (payload) => {
                    console.log('Transaction update received:', payload.eventType);
                    fetchData(); // Refresh history and redundant balance check
                    
                    // Live Status Notifications
                    if (payload.eventType === 'UPDATE') {
                        const newTx = payload.new as any;
                        const oldTx = payload.old as any;

                        if (oldTx.status === 'PENDING' && (newTx.status === 'COMPLETED' || newTx.status === 'SUCCESSFUL')) {
                            toast.success(`${newTx.display_label || 'Transaction'} confirmed!`, { 
                                duration: 5000,
                                icon: '🟢',
                                style: {
                                    background: '#064e3b',
                                    color: '#ecfdf5',
                                    borderRadius: '12px',
                                    border: '1px solid #059669'
                                }
                            });
                        } else if (newTx.status === 'FAILED') {
                            toast.error(`Transaction failed: ${newTx.metadata?.failReason || 'Unknown error'}`, {
                                icon: '🔴'
                            });
                        }
                    }
                    
                    if (payload.eventType === 'INSERT') {
                        toast('New transaction initiated', { 
                            icon: '🟡',
                            style: {
                                background: '#451a03',
                                color: '#fef3c7',
                                borderRadius: '12px'
                            }
                        });
                    }
                }
             )
             .subscribe();

        return () => {
            supabase.removeChannel(ledgerChannel);
            supabase.removeChannel(txChannel);
        };
    }, [user, fetchData]);

    const createWallet = async (currency: string, network: string = 'native') => {
        try {
            const wallet = await walletApi.createWallet(currency, network);
            await fetchData();
            return wallet;
        } catch (err: unknown) {
            console.error('Create wallet error:', err);
            const message = err instanceof Error ? err.message : 'Failed to create wallet';
            toast.error(message);
            throw err;
        }
    };

    const sendFunds = async (data: InternalTransferRequest & { captchaToken?: string }) => {
        try {
            // Generate idempotency key if not provided
            const idempotencyKey = data.idempotencyKey || `transfer_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
            await walletApi.internalTransfer({ ...data, idempotencyKey });
            toast.success(`Successfully sent ${data.amount} ${data.currency}`);
            await fetchData(); // Refresh balances immediately
        } catch (err: unknown) {
            console.error('Send funds error:', err);
            const message = err instanceof Error ? err.message : 'Failed to send funds';
            toast.error(message);
            throw err;
        }
    };

    const withdraw = async (data: WithdrawalRequest) => {
        try {
            // Generate idempotency key if not provided
            const idempotencyKey = data.idempotencyKey || `withdraw_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
            await walletApi.withdraw({ ...data, idempotencyKey });
            toast.success(`Withdrawal request submitted for ${data.amount} ${data.currency}`);
            await fetchData();
        } catch (err: unknown) {
            console.error('Withdraw error:', err);
            const message = err instanceof Error ? err.message : 'Failed to withdraw funds';
            toast.error(message);
            throw err;
        }
    };

    const getCommissionRate = async (type: string, currency: string) => {
        return walletApi.getCommissionRate(type as any, currency);
    };

    return (
        <WalletContext.Provider value={{ wallets, transactions, loading, error, refresh: fetchData, createWallet, sendFunds, withdraw, getCommissionRate }}>
            {children}
        </WalletContext.Provider>
    );
};

import React, { createContext, useContext, useEffect, useRef, useState, useCallback } from 'react';
import Peer, { type MediaConnection } from 'peerjs';
import { useSocket } from './SocketContext';
import { useAuth } from './AuthContext';
import { useChat } from './ChatContext';
import { CallOverlay } from '../components/chat/CallOverlay';
import toast from 'react-hot-toast';

// ─── PeerJS signaling config ─────────────────────────────────────
// Uses local server in DEV, public PeerJS cloud in PROD

// ─── Types ───────────────────────────────────────────────────────
interface CallState {
    type: 'voice' | 'video' | null;
    status: 'idle' | 'calling' | 'incoming' | 'connecting' | 'connected';
    otherUser: string | null;
    otherUserName?: string;
    otherUserAvatar?: string;
    conversationId: string | null;
    connectedAt?: number | null;
}

interface WebRTCContextValue {
    callState: CallState;
    localStream: MediaStream | null;
    remoteStream: MediaStream | null;
    startCall: (userId: string, conversationId: string, type: 'voice' | 'video', name?: string, avatar?: string) => Promise<void>;
    acceptCall: () => Promise<void>;
    rejectCall: () => void;
    endCall: () => void;
    toggleMute: () => void;
    toggleVideo: () => void;
    isMuted: boolean;
    isVideoEnabled: boolean;
}

const WebRTCContext = createContext<WebRTCContextValue | null>(null);

export const useWebRTC = () => {
    const context = useContext(WebRTCContext);
    if (!context) throw new Error('useWebRTC must be used within a WebRTCProvider');
    return context;
};

function makePeerId(userId: string, suffix?: string): string {
    const base = `ns_${userId.replace(/-/g, '_')}`;
    return suffix ? `${base}_${suffix}` : base;
}

// ═════════════════════════════════════════════════════════════════
export const WebRTCProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const { socket, connected: socketConnected } = useSocket();
    const { user } = useAuth();
    const { sendMessage } = useChat();

    const [callState, setCallState] = useState<CallState>({
        type: null, status: 'idle', otherUser: null, conversationId: null, connectedAt: null,
    });
    const [localStream, setLocalStream] = useState<MediaStream | null>(null);
    const [remoteStream, setRemoteStream] = useState<MediaStream | null>(null);
    const [isMuted, setIsMuted] = useState(false);
    const [isVideoEnabled, setIsVideoEnabled] = useState(true);

    const peerRef = useRef<Peer | null>(null);
    const mediaConnectionRef = useRef<MediaConnection | null>(null);
    const localStreamRef = useRef<MediaStream | null>(null);
    const callTimeoutRef = useRef<any>(null);
    const currentCallStatus = useRef<CallState['status']>('idle');
    const pendingCallRef = useRef<{ from: string; peerId: string; type: 'voice' | 'video' } | null>(null);

    // Audio Refs for ringtones
    // dialToneRef = calm ring-ring sound the CALLER hears while waiting
    // incomingRingtoneRef = attention-grabbing sound the CALLEE hears for incoming call
    const dialToneRef = useRef<HTMLAudioElement | null>(null);
    const incomingRingtoneRef = useRef<HTMLAudioElement | null>(null);

    useEffect(() => {
        // Initialize audio objects
        // ringtone.wav = calm dial tone for caller
        // ringing.wav = attention-grabbing ringtone for callee
        dialToneRef.current = new Audio('/sounds/ringtone.wav');
        dialToneRef.current.loop = true;
        dialToneRef.current.volume = 0.5;
        incomingRingtoneRef.current = new Audio('/sounds/ringing.wav');
        incomingRingtoneRef.current.loop = true;
        incomingRingtoneRef.current.volume = 0.8;

        return () => {
            if (dialToneRef.current) { dialToneRef.current.pause(); dialToneRef.current = null; }
            if (incomingRingtoneRef.current) { incomingRingtoneRef.current.pause(); incomingRingtoneRef.current = null; }
        };
    }, []);

    useEffect(() => { currentCallStatus.current = callState.status; }, [callState.status]);

    // Robust audio playback — handles browser autoplay restrictions
    const playAudio = useCallback((audio: HTMLAudioElement | null, label: string) => {
        if (!audio) return;
        const playPromise = audio.play();
        if (playPromise) {
            playPromise.catch((err) => {
                console.warn(`[Audio] ${label} play blocked:`, err.message);
                // Show a toast so user knows to interact to enable sound
                toast(`🔇 Tap anywhere to enable ${label}`, {
                    duration: 3000,
                    id: `audio-unlock-${label}`,
                });
                // One-time click listener to retry audio
                const unlockAudio = () => {
                    audio.play().catch(() => { /* Ignore autoplay errors */ });
                    document.removeEventListener('click', unlockAudio);
                    document.removeEventListener('touchstart', unlockAudio);
                };
                document.addEventListener('click', unlockAudio, { once: true });
                document.addEventListener('touchstart', unlockAudio, { once: true });
            });
        }
    }, []);

    // Handle audio playback based on status
    useEffect(() => {
        const stopAll = () => {
            dialToneRef.current?.pause();
            if (dialToneRef.current) dialToneRef.current.currentTime = 0;
            incomingRingtoneRef.current?.pause();
            if (incomingRingtoneRef.current) incomingRingtoneRef.current.currentTime = 0;
        };

        if (callState.status === 'calling') {
            // I am the CALLER — play calm dial tone
            stopAll();
            playAudio(dialToneRef.current, 'dial tone');
        } else if (callState.status === 'incoming') {
            // I am the CALLEE — play attention-grabbing ringtone
            stopAll();
            playAudio(incomingRingtoneRef.current, 'ringtone');
        } else {
            stopAll();
        }
    }, [callState.status, playAudio]);

    // ─── Cleanup ─────────────────────────────────────────────────
    const cleanup = useCallback(() => {
        if (callTimeoutRef.current) { clearTimeout(callTimeoutRef.current); callTimeoutRef.current = null; }
        if (mediaConnectionRef.current) { mediaConnectionRef.current.close(); mediaConnectionRef.current = null; }
        if (localStreamRef.current) { localStreamRef.current.getTracks().forEach(t => t.stop()); localStreamRef.current = null; }
        
        // Stop audio
        dialToneRef.current?.pause();
        if (dialToneRef.current) dialToneRef.current.currentTime = 0;
        incomingRingtoneRef.current?.pause();
        if (incomingRingtoneRef.current) incomingRingtoneRef.current.currentTime = 0;

        setLocalStream(null);
        setRemoteStream(null);
        pendingCallRef.current = null;
        setCallState({ type: null, status: 'idle', otherUser: null, conversationId: null, connectedAt: null });
        setIsMuted(false);
        setIsVideoEnabled(true);
    }, []);

    // ─── PeerJS initialization ───────────────────────────────────
    useEffect(() => {
        if (!user?.id) return;
        if (peerRef.current) return;

        let destroyed = false;
        const MAX_RECONNECT = 3;

        function createPeer(suffix?: string) {
            if (destroyed) return;

            const peerId = makePeerId(user!.id, suffix || Math.random().toString(36).substring(7));
            let reconnectAttempts = 0;

            const peerConfig = import.meta.env.DEV 
                ? { host: import.meta.env.VITE_PEER_HOST || 'localhost', port: parseInt(import.meta.env.VITE_PEER_PORT || '9000'), path: '/peerjs', secure: false }
                : (import.meta.env.VITE_PEER_HOST ? { host: import.meta.env.VITE_PEER_HOST, port: parseInt(import.meta.env.VITE_PEER_PORT || '443'), path: '/peerjs', secure: true } : {}); 

            const peer = new Peer(peerId, {
                ...peerConfig,
                debug: import.meta.env.DEV ? 2 : 0,
                pingInterval: 3000, // Heartbeat every 3s to keep signaling alive
                config: {
                    iceServers: [
                        { urls: 'stun:stun.l.google.com:19302' },
                        { urls: 'stun:stun1.l.google.com:19302' },
                        // TURN servers for NAT traversal (ensures calls work behind firewalls)
                        { urls: 'turn:openrelay.metered.ca:80', username: 'openrelayproject', credential: 'openrelayproject' },
                        { urls: 'turn:openrelay.metered.ca:443', username: 'openrelayproject', credential: 'openrelayproject' },
                        { urls: 'turn:openrelay.metered.ca:443?transport=tcp', username: 'openrelayproject', credential: 'openrelayproject' },
                    ],
                },
            });

            peer.on('open', (id) => {
                console.log('[PeerJS] ✓ Connected:', id);
                reconnectAttempts = 0;
            });

            peer.on('call', (call) => {
                mediaConnectionRef.current = call;
                call.on('stream', (remote) => { 
                    setRemoteStream(remote); 
                    setCallState(p => ({ ...p, status: 'connected', connectedAt: p.connectedAt || Date.now() })); 
                });
                call.on('close', cleanup);
                call.on('error', () => { toast.error('Call error'); cleanup(); });
            });

            peer.on('error', (err: any) => {
                if (err.type === 'unavailable-id') {
                    console.warn('[PeerJS] ID taken — retrying…');
                    if (peerRef.current && !peerRef.current.destroyed) {
                        peerRef.current.destroy();
                    }
                    peerRef.current = null;
                    setTimeout(() => createPeer(Date.now().toString(36)), 800);
                    return;
                }
                if (err.type === 'network' || err.type === 'server-error') {
                    console.warn('[PeerJS] Signaling server unreachable. Calls unavailable.');
                }
            });

            peer.on('disconnected', () => {
                if (!destroyed && !peer.destroyed && reconnectAttempts < MAX_RECONNECT) {
                    reconnectAttempts++;
                    console.log(`[PeerJS] Reconnecting (${reconnectAttempts}/${MAX_RECONNECT})…`);
                    peer.reconnect();
                } else if (reconnectAttempts >= MAX_RECONNECT) {
                    console.warn('[PeerJS] Max reconnects reached. Calls unavailable.');
                }
            });

            peerRef.current = peer;
        }

        createPeer();

        return () => {
            destroyed = true;
            if (peerRef.current) {
                peerRef.current.destroy();
                peerRef.current = null;
            }
        };
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [user?.id]);

    // ─── Start Call ──────────────────────────────────────────────
    const startCall = async (otherUserId: string, conversationId: string, type: 'voice' | 'video', name?: string, avatar?: string) => {
        try {
            if (!peerRef.current) { toast.error('Connection not ready'); return; }
            setCallState({ type, status: 'calling', otherUser: otherUserId, otherUserName: name, otherUserAvatar: avatar, conversationId, connectedAt: null });

            const stream = await navigator.mediaDevices.getUserMedia({
                audio: { 
                    echoCancellation: true, 
                    noiseSuppression: true, 
                    autoGainControl: true,
                    // Advanced constraints (supported in Chromium)
                    // @ts-ignore
                    googEchoCancellation: true,
                    googAutoGainControl: true,
                    googNoiseSuppression: true,
                    googHighpassFilter: true,
                    googTypingNoiseDetection: true,
                    googAudioMirroring: false,
                },
                video: type === 'video' ? {
                    width: { ideal: 1280 },
                    height: { ideal: 720 },
                    frameRate: { ideal: 30 }
                } : false,
            });
            localStreamRef.current = stream;
            setLocalStream(stream);

            if (socket && user) {
                socket.emit('call:init', { to: otherUserId, type, conversationId, peerId: peerRef.current.id });
                sendMessage(`Started ${type} call`, 'call').catch(() => { /* Ignore logging errors */ });
            }

            callTimeoutRef.current = setTimeout(() => {
                if (currentCallStatus.current === 'calling') {
                    toast.error('No answer');
                    socket?.emit('call:end', { to: otherUserId, conversationId });
                    cleanup();
                }
            }, 45000);
        } catch {
            toast.error('Failed to access media');
            cleanup();
        }
    };

    // ─── Accept Call ─────────────────────────────────────────────
    const acceptCall = async () => {
        try {
            if (!peerRef.current || !pendingCallRef.current) { toast.error('Call data missing'); cleanup(); return; }
            const { type } = pendingCallRef.current;
            const stream = await navigator.mediaDevices.getUserMedia({
                audio: { 
                    echoCancellation: true, 
                    noiseSuppression: true, 
                    autoGainControl: true,
                    // @ts-ignore
                    googEchoCancellation: true,
                    googAutoGainControl: true,
                    googNoiseSuppression: true,
                    googHighpassFilter: true,
                    googTypingNoiseDetection: true,
                    googAudioMirroring: false,
                },
                video: type === 'video' ? {
                    width: { ideal: 1280 },
                    height: { ideal: 720 },
                    frameRate: { ideal: 30 }
                } : false,
            });
            localStreamRef.current = stream;
            setLocalStream(stream);

            if (mediaConnectionRef.current) {
                mediaConnectionRef.current.answer(stream);
                setCallState(p => ({ ...p, status: 'connecting' }));
            }
            socket?.emit('call:ready', { to: callState.otherUser, peerId: peerRef.current.id });
        } catch {
            toast.error('Failed to join call');
            cleanup();
        }
    };

    // ─── Reject / End ────────────────────────────────────────────
    const rejectCall = () => { socket?.emit('call:end', { to: callState.otherUser, conversationId: callState.conversationId }); cleanup(); };
    const endCall = () => { socket?.emit('call:end', { to: callState.otherUser, conversationId: callState.conversationId }); cleanup(); };

    // ─── Mute / Video ────────────────────────────────────────────
    const toggleMute = () => {
        localStreamRef.current?.getAudioTracks().forEach(t => { t.enabled = isMuted; });
        setIsMuted(!isMuted);
    };
    const toggleVideo = () => {
        localStreamRef.current?.getVideoTracks().forEach(t => { t.enabled = !isVideoEnabled; });
        setIsVideoEnabled(!isVideoEnabled);
    };

    // ─── Socket.IO call signaling ────────────────────────────────
    useEffect(() => {
        if (!socket || !socketConnected) return;

        const onIncoming = (data: any) => {
            if (currentCallStatus.current !== 'idle') {
                socket.emit('call:end', { to: data.from, conversationId: data.conversationId });
                return;
            }
            pendingCallRef.current = { from: data.from, peerId: data.peerId, type: data.type };
            setCallState({
                type: data.type, status: 'incoming', otherUser: data.from,
                otherUserName: data.fromName, otherUserAvatar: data.fromAvatar,
                conversationId: data.conversationId,
                connectedAt: null,
            });
        };

        const onReady = (data: any) => {
            if (currentCallStatus.current === 'calling' && peerRef.current && localStreamRef.current) {
                if (callTimeoutRef.current) clearTimeout(callTimeoutRef.current);
                const calleePeerId = data.peerId || makePeerId(data.from);
                const call = peerRef.current.call(calleePeerId, localStreamRef.current, {
                    // Set bandwidth to ensure high quality audio
                    // @ts-ignore
                    sdpTransform: (sdp: string) => {
                        // 1. Lower Application Specific (AS) bandwidth to prevent jitter
                        // Using 2000 (2Mbps) for video, and remove for voice
                        let newSdp = sdp;
                        if (callState.type === 'video') {
                            newSdp = sdp.replace(/AS:([0-9]+)/g, 'AS:2000');
                        } else {
                            newSdp = sdp.replace(/b=AS:([0-9]+).*\r\n/g, '');
                        }

                        // 2. Optimize OPUS audio quality (payload type 111)
                        // This adds stereo support and boosts the bit rate for high fidelity
                        if (newSdp.includes('a=fmtp:111')) {
                            newSdp = newSdp.replace(
                                /a=fmtp:111 .*/,
                                'a=fmtp:111 minptime=10;stereo=1;useinbandfec=1;maxaveragebitrate=128000;sprop-stereo=1'
                            );
                        }
                        
                        return newSdp;
                    }
                });
                if (!call) { toast.error('Failed to connect'); cleanup(); return; }

                mediaConnectionRef.current = call;
                setCallState(p => ({ ...p, status: 'connecting' }));
                call.on('stream', (remote) => { 
                    setRemoteStream(remote); 
                    setCallState(p => ({ ...p, status: 'connected', connectedAt: p.connectedAt || Date.now() })); 
                });
                call.on('close', cleanup);
                call.on('error', () => { toast.error('Call failed'); cleanup(); });
            }
        };

        const onEnded = () => cleanup();

        socket.on('call:incoming', onIncoming);
        socket.on('call:ready', onReady);
        socket.on('call:ended', onEnded);

        return () => {
            socket.off('call:incoming', onIncoming);
            socket.off('call:ready', onReady);
            socket.off('call:ended', onEnded);
        };
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [socket, socketConnected, cleanup]);

    return (
        <WebRTCContext.Provider value={{
            callState, localStream, remoteStream,
            startCall, acceptCall, rejectCall, endCall,
            toggleMute, toggleVideo, isMuted, isVideoEnabled,
        }}>
            {children}
            {callState.status !== 'idle' && (
                <CallOverlay
                    callState={callState}
                    acceptCall={acceptCall}
                    rejectCall={rejectCall}
                    endCall={endCall}
                    localStream={localStream}
                    remoteStream={remoteStream}
                    toggleMute={toggleMute}
                    toggleVideo={toggleVideo}
                    isMuted={isMuted}
                    isVideoEnabled={isVideoEnabled}
                    otherUserName={callState.otherUserName || 'User'}
                    otherUserAvatar={callState.otherUserAvatar}
                />
            )}
        </WebRTCContext.Provider>
    );
};

import { useState, useEffect, useRef, useCallback } from 'react';
import { getStoredAccounts } from '../utils/accountManager';
import { API_URL } from '../lib/api';
import { useAuth } from '../context/AuthContext';

export const useMultiAccountNotifications = () => {
  const { user } = useAuth();
  const [unreadCounts, setUnreadCounts] = useState<Record<string, number>>({});
  const accounts = getStoredAccounts();
  const intervalRef = useRef<any>(null);

  const fetchUnreadCounts = useCallback(async () => {
    // Dynamically retrieve to avoid stable-reference loops on every render
    const currentAccounts = getStoredAccounts();
    const otherAccounts = currentAccounts.filter(acc => acc.id !== user?.id);

    for (const acc of otherAccounts) {
      try {
        const res = await fetch(`${API_URL}/api/notifications/unread-count`, {
          headers: {
            'Authorization': `Bearer ${acc.session.access_token}`
          }
        });

        if (res.ok) {
          const { count } = await res.json();
          setUnreadCounts(prev => ({ ...prev, [acc.id]: count }));
        } else if (res.status === 401) {
          console.warn(`[MultiAccountAuth] Token expired for account ${acc.id}`);
        }
      } catch (err) {
        console.error(`[MultiAccountAuth] Failed to fetch count for ${acc.id}:`, err);
      }
    }
  }, [user?.id]);

  useEffect(() => {
    // Initial fetch
    fetchUnreadCounts();

    // Poll every 60 seconds
    intervalRef.current = setInterval(fetchUnreadCounts, 60000);

    return () => {
      if (intervalRef.current) clearInterval(intervalRef.current);
    };
  }, [fetchUnreadCounts, user?.id, accounts.length]);

  return { unreadCounts };
};

import { SupabaseClient, PostgrestError } from "@supabase/supabase-js";
import type { Session } from "@supabase/supabase-js";
import toast from "react-hot-toast";
import type { Wallet } from '@/types/wallet';
import type { Profile, Subscription } from '../types/auth';
import type { Note } from '../types/note';

// --------------------------
// Supabase Client
// --------------------------
import { supabase as supabaseClient } from './supabase';

// --------------------------
// Supabase Client
// --------------------------
export const supabase: SupabaseClient = supabaseClient;

// --------------------------
// RateLimiter per-call
// --------------------------
type RateLimiter = {
  lastCall: number;
  minDelay: number; // in ms
};

const rateLimiters: Record<string, RateLimiter> = {};
const inFlightPromises = new Map<string, Promise<any>>();

/**
 * Reset rate limiters - call on session change to avoid stale cooldowns
 */
export function resetRateLimiters(keyPrefix?: string) {
  if (keyPrefix) {
    Object.keys(rateLimiters)
      .filter(k => k.startsWith(keyPrefix))
      .forEach(k => delete rateLimiters[k]);
  } else {
    // Clear all
    Object.keys(rateLimiters).forEach(k => delete rateLimiters[k]);
  }
  inFlightPromises.clear();
  console.log('[Supabase] Rate limiters reset', keyPrefix ? `for prefix: ${keyPrefix}` : '(all)');
}

/**
 * Generic safe call wrapper with retries, timeout, and promise sharing
 */
export async function safeCall<T>(
  key: string,
  fn: () => Promise<T>,
  options: {
    minDelay?: number;
    retries?: number;
    timeout?: number;
    fallback?: T;
  } = {}
): Promise<T | null> {
  const { minDelay = 500, retries = 3, timeout = 15000, fallback } = options;

  // 1. Check if identical request is already in flight (Promise Sharing)
  if (inFlightPromises.has(key)) {
    console.log(`[Supabase] Sharing in-flight promise for '${key}'`);
    return inFlightPromises.get(key) as Promise<T>;
  }

  // Initialize limiter
  if (!rateLimiters[key]) {
    rateLimiters[key] = { lastCall: 0, minDelay };
  }

  const now = Date.now();
  const limiter = rateLimiters[key];

  // 2. Check cooldown (Throttle)
  const timeSinceLast = now - limiter.lastCall;
  if (timeSinceLast < limiter.minDelay) {
    console.warn(`[Supabase] Throttling '${key}' (${limiter.minDelay - timeSinceLast}ms remaining)`);
    await new Promise(resolve => setTimeout(resolve, limiter.minDelay - timeSinceLast));
  }

  // Helper to determine if error is transient
  const isRetryable = (err: any) => {
    // 1. Explicitly ignore Supabase initialization/internal states if possible
    // 2. Terminal Postgrest/Auth errors
    const terminalCodes = [
      '42501', // RLS Permission Denied
      '42P17', // Recursion
      'P0001', // Raise Exception
      '23505', // Unique Violation
      '23503', // FK Violation
      '42703', // Undefined Column (Postgres 42703)
      '406',   // Not Acceptable (Schema mismatch)
      '400',   // Bad Request
      '401',   // Unauthorized
      '403',   // Forbidden
      'BGR88', // Rate limit
    ];

    const errCode = err.code?.toString();
    const errStatus = err.status?.toString();

    if (terminalCodes.includes(errCode) || terminalCodes.includes(errStatus)) return false;

    // 3. Retry on timeouts, network failures, and 5xx errors
    const isTimeout = err.message?.includes('Timeout') || err.name === 'AbortError' || err.message?.includes('abort');
    const isNetwork = !err.code && (
      err.message?.toLowerCase().includes('fetch') || 
      err.message?.toLowerCase().includes('network') ||
      err.message?.toLowerCase().includes('failed to fetch') ||
      err.message?.toLowerCase().includes('load failed') ||
      err.message?.toLowerCase().includes('connection refused')
    );
    const is5xx = err.status >= 500;

    // DO NOT retry if we are still in a "recovering" state if identifiable
    if (err.message?.includes('_recoverAndRefresh')) return false;

    return isTimeout || isNetwork || is5xx;
  };

  // 3. Execute with retries and timeout
  const executeCall = async (): Promise<T | null> => {
    let attempt = 0;
    limiter.lastCall = Date.now();

    while (attempt <= retries) {
      try {
        const timeoutPromise = new Promise<never>((_, reject) => {
          setTimeout(() => reject(new Error(`Timeout after ${timeout}ms`)), timeout);
        });

        const result = await Promise.race([fn(), timeoutPromise]);
        
        // Handle Supabase error object inside result
        if (result && typeof result === 'object' && 'error' in result && (result as any).error) {
          throw (result as any).error;
        }

        return result;

      } catch (err: any) {
        attempt++;
        const canRetry = isRetryable(err);

        if (!canRetry || attempt > retries) {
          const tag = canRetry ? 'MAX_RETRIES' : 'TERMINAL';
          if (!navigator.onLine) {
            toast.error("You're offline. Please reconnect to continue.", { id: 'supabase-offline' });
          } else {
            console.error(`[Supabase ${tag}] '${key}' (Code: ${err.code || 'None'}):`, {
              message: err.message,
              attempt,
              status: err.status
            });
          }

          return fallback !== undefined ? fallback : null;
        }

        const backoff = 500 * Math.pow(2, attempt - 1); // Shorter backoff for start
        await new Promise(r => setTimeout(r, Math.min(backoff, 5000)));
      }
    }
    return fallback !== undefined ? fallback : null;
  };

  // Wrap in promise cache
  const resultPromise = executeCall().finally(() => {
    inFlightPromises.delete(key);
  });

  inFlightPromises.set(key, resultPromise);
  return resultPromise;
}

// --------------------------
// Safe Table Query with Fallback
// --------------------------

interface QueryResponse<T> {
  data: T | null;
  error: PostgrestError | null;
  count?: number | null;
}

/**
 * Generic helper for querying tables with automatic fallback.
 */
export async function safeTableQuery<T>(
  primaryTable: string,
  fallbackTable: string | null,
  // We use ReturnType<SupabaseClient['from']> for strict builder typing
  query: (table: ReturnType<SupabaseClient['from']>) => Promise<QueryResponse<T>>,
  defaultValue: T
): Promise<T> {
  try {
    // Try primary table
    const { data, error } = await query(supabase.from(primaryTable));
    
    if (error) {
      // Check if table doesn't exist (PostgreSQL error code 42P01)
      const isTableMissing = error.code === '42P01' || 
                            error.message?.includes('does not exist') ||
                            (error.message?.includes('relation') && error.message?.includes('does not exist'));
      
      if (isTableMissing && fallbackTable) {
        console.warn(`[Supabase] Table '${primaryTable}' not found, trying fallback '${fallbackTable}'`);
        toast(`Using fallback table: ${fallbackTable}`, { icon: '⚠️', duration: 2000 });
        
        // Try fallback table
        const { data: fallbackData, error: fallbackError } = await query(supabase.from(fallbackTable));
        
        if (fallbackError) {
          console.error(`[Supabase] Fallback table '${fallbackTable}' also failed:`, fallbackError);
          return defaultValue;
        }
        
        return (fallbackData as T) || defaultValue;
      }
      
      // Other errors or no fallback
      console.error(`[Supabase] Query error on '${primaryTable}':`, error);
      return defaultValue;
    }
    
    return (data as T) || defaultValue;
  } catch (err) {
    console.error(`[Supabase] Unexpected error querying '${primaryTable}':`, err);
    return defaultValue;
  }
}


// --------------------------
// Auth
// --------------------------
export async function safeAuth(): Promise<Session | null> {
  return safeCall<Session | null>("auth-session", async () => {
    // Use getSession for immediate check, it's faster than getUser which hits the DB
    const { data, error } = await supabase.auth.getSession();
    if (error) throw error;
    return data.session;
  }, { minDelay: 100, retries: 1, timeout: 10000 }); // More resilient timeout for auth
}

