import { formatCurrency } from '../lib/CurrencyFormatter';
import toast from 'react-hot-toast';

const SUPPORTED_CURRENCIES = ['BTC', 'ETH', 'USD', 'NGN', 'EUR', 'GBP', 'JPY'];

const WalletContent: React.FC = () => {
    const { wallets, transactions, loading, refresh, createWallet } = useWallet();
    const { socket } = useSocket();
    
    // Force-refresh service data on mount (ensures fresh data after activity redirect)
    useEffect(() => {
        refresh();
    }, []); // eslint-disable-line react-hooks/exhaustive-deps
    
    const safeTransactions = Array.isArray(transactions) ? transactions : [];
    
    const [rates, setRates] = useState<Record<string, number>>({}); // Rates in USD
    const [totalBalance, setTotalBalance] = useState(0);
    const [totalAvailableBalance, setTotalAvailableBalance] = useState(0);
    const [ratesLoading, setRatesLoading] = useState(true);
    const [refreshKey, setRefreshKey] = useState(0);
    const [showBalances, setShowBalances] = useState(true);
    const [searchParams, setSearchParams] = useSearchParams();

    // Instant Proactive Polling for external redirects (e.g. Flutterwave/Paystack)
    useEffect(() => {
        const txRef = searchParams.get('tx_ref');
        const reference = searchParams.get('reference');
        const transactionId = searchParams.get('transaction_id') || searchParams.get('flw_ref');
        const statusParam = searchParams.get('status');

        const refToVerify = txRef || reference;

        if (refToVerify && (statusParam || reference)) {
            let isActive = true;
            const verifyPayment = async () => {
                const toastId = toast.loading('Verifying your request...', { duration: 10000 });
                try {
                    const res = await walletApi.proactiveVerifyPayment(refToVerify, transactionId || undefined);
                    if (!isActive) return;

                    const upperStatus = (res.status || '').toUpperCase();
                    if (['COMPLETED', 'SUCCESS', 'SUCCESSFUL'].includes(upperStatus)) {
                        toast.success('Request processed successfully!', { id: toastId });
                        setSearchParams({});
                        await refresh();
                        setRefreshKey(k => k + 1);
                    } else if (['FAILED', 'CANCELLED'].includes(upperStatus)) {
                        toast.error('Request failed or was cancelled.', { id: toastId });
                        setSearchParams({});
                    } else {
                        toast.success('Request is pending. Tracking your activity...', { id: toastId });
                        setSearchParams({});
                        await refresh();
                    }
                } catch {
                    if (isActive) {
                        toast.error('Confirmation delayed. Status will update shortly.', { id: toastId });
                        setSearchParams({});
                    }
                }
            };
            verifyPayment();
            
            return () => { isActive = false; };
        }
    }, [searchParams, setSearchParams, refresh]);

    // Modals
    const [showFundModal, setShowFundModal] = useState(false);
    const [isBuyMode, setIsBuyMode] = useState(false);
    const [showTransferModal, setShowTransferModal] = useState(false);
    const [showWithdrawModal, setShowWithdrawModal] = useState(false);
    const [showReceiveModal, setShowReceiveModal] = useState(false);
    const [showCreateModal, setShowCreateModal] = useState(false);
    const [selectedAsset, setSelectedAsset] = useState<{ currency: string; network: string }>({ currency: 'BTC', network: 'native' });

    // Stats
    const swapCardRef = useRef<HTMLDivElement>(null);

    // Fetch Rates & Calculate Total
    useEffect(() => {
        const processExchangeRates = (exchangeRates: Record<string, any>) => {
            const usdRates: Record<string, number> = {};
            
            Object.keys(exchangeRates).forEach(curr => {
                let val = exchangeRates[curr];
                
                // Handle objects (old provider format)
                if (typeof val === 'object' && val !== null) {
                    val = val['USD'] || val[curr] || 0;
                }

                const numVal = typeof val === 'string' ? parseFloat(val) : val;
                
                if (typeof numVal === 'number' && !isNaN(numVal) && numVal > 0) {
                    // Convert "1 USD = X Currency" to "1 Currency = Y USD"
                    usdRates[curr] = 1 / numVal;
                }
            });

            usdRates['USD'] = 1;
            setRates(usdRates);
            setRatesLoading(false);
        };

        const fetchRates = async () => {
            setRatesLoading(true);
            try {
                const exchangeRates = await walletApi.getExchangeRates();
                processExchangeRates(exchangeRates);
            } catch (err) {
                console.error('Failed to fetch rates', err);
                setRatesLoading(false);
            }
        };

        // Initial fetch
        if (Array.isArray(wallets) && wallets.length > 0) {
            fetchRates();
        }

        // Socket.io Listener: Active Real-time Overwrite
        if (socket) {
            socket.on('rates_updated', (newRates: any) => {
                console.log('[Socket] Rates updated in real-time');
                processExchangeRates(newRates);
            });

            return () => {
                socket.off('rates_updated');
            };
        }
    }, [wallets, socket]);

    // Calculate Total Balance & Available Balance
    useEffect(() => {
        if (wallets.length > 0 && Object.keys(rates).length > 0) {
            let total = 0;
            let available = 0;
            const safeWallets = Array.isArray(wallets) ? wallets : [];
            
            safeWallets.forEach(w => {
                const rate = rates[w.currency] || 0;
                // Using a slightly more robust multiplication to reduce float noise
                const balValue = Number((w.balance * rate).toFixed(12));
                const availValue = Number(((w.available_balance ?? w.balance) * rate).toFixed(12));
                
                total += balValue;
                available += availValue;
            });

            setTotalBalance(Number(total.toFixed(8)));
            setTotalAvailableBalance(Number(available.toFixed(8)));
        }
    }, [wallets, rates]);

    const handleAction = (action: 'send' | 'receive' | 'fund' | 'withdraw' | 'swap' | 'buy') => {
        const safeWallets = Array.isArray(wallets) ? wallets : [];
        if (!selectedAsset.currency && safeWallets.length > 0) {
            // Prefer a fiat wallet as default for global actions (better feature discoverability)
            const fiatWallet = safeWallets.find(w => ['USD', 'EUR', 'NGN', 'GBP'].includes(w.currency));
            const defaultWallet = fiatWallet || safeWallets[0];
            setSelectedAsset({ currency: defaultWallet.currency, network: defaultWallet.network });
        }

        switch (action) {
            case 'fund':
                setShowFundModal(true);
                break;
            case 'buy':
                // For buy action, default to a crypto wallet to trigger direct purchase
                if (['USD', 'EUR', 'NGN', 'GBP'].includes(selectedAsset.currency)) {
                    const cryptoWallet = safeWallets.find(w => !['USD', 'EUR', 'NGN', 'GBP'].includes(w.currency));
                    if (cryptoWallet) {
                        setSelectedAsset({ currency: cryptoWallet.currency, network: cryptoWallet.network });
                    }
                }
                setIsBuyMode(true);
                setShowFundModal(true);
                break;
            case 'send':
                setShowTransferModal(true);
                break;
            case 'withdraw':
                setShowWithdrawModal(true);
                break;
            case 'swap':
                swapCardRef.current?.scrollIntoView({ behavior: 'smooth', block: 'center' });
                break;
            case 'receive':
                setShowReceiveModal(true);
                break;
        }
    };

    const handleCreateWallet = async (currency: string) => {
        try {
            await createWallet(currency);
            toast.success(`${currency} service activated!`);
            setShowCreateModal(false);
            refresh();
        } catch {
           // handled in context
        }
    };

    const handleRefresh = () => {
        refresh();
        setRefreshKey(k => k + 1); // Trigger ledger trail refresh
    };

    return (
        <div className="min-h-[100dvh] bg-gray-950 text-white p-4 sm:p-6 lg:p-8 overflow-x-clip w-full">
            <div className="max-w-7xl mx-auto space-y-8">
                
                {/* Market Price Ticker */}
                {!loading && Object.keys(rates).length > 0 && (
                    <div className="flex gap-4 overflow-x-auto pb-2 scrollbar-none no-scrollbar">
                        {['BTC', 'ETH'].map(curr => (
                            <div key={curr} className="flex items-center gap-2 bg-white/5 border border-white/10 px-3 py-1.5 rounded-full shrink-0">
                                <span className={`w-2 h-2 rounded-full bg-green-400 animate-pulse`} />
                                <span className="text-xs font-bold text-gray-300">{curr}/USD</span>
                                <span className="text-xs font-black text-white">
                                    { (rates[curr] || 0) < 0.01 
                                        ? `$${(rates[curr] || 0).toFixed((rates[curr] || 0) < 0.0001 ? 6 : 4)}` 
                                        : formatCurrency(rates[curr] || 0, 'USD') 
                                    }
                                </span>
                            </div>
                        ))}
                    </div>
                )}

                {/* Header */}
                <div className="flex justify-between items-center">
                    <div>
                        <h1 className="text-2xl sm:text-3xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-white to-gray-400">
                            Activity Overview
                        </h1>
                        <p className="text-gray-400 text-sm mt-1">Manage your digital activities and technology tools</p>
                    </div>
                    <div className="flex gap-3">
                         <Button onClick={() => setShowCreateModal(true)} variant="outline" size="sm" className="hidden sm:flex border-gray-700 hover:border-purple-500">
                            <Plus size={16} className="mr-2" /> Add Service
                        </Button>
                        <Button onClick={handleRefresh} variant="ghost" size="sm" className="bg-gray-800 hover:bg-gray-700">
                            <RefreshCw size={18} className={loading ? 'animate-spin' : ''} />
                        </Button>
                    </div>
                </div>

                {/* Top Section: Balance & Actions */}
                <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                    {/* Left: Balance Card */}
                    <div className="lg:col-span-2 space-y-6">
                        <WalletBalanceCard 
                            totalBalance={totalBalance} 
                            availableBalance={totalAvailableBalance}
                            currency="USD"
                            loading={ratesLoading || loading}
                            showBalance={showBalances}
                            onToggleBalance={() => setShowBalances(!showBalances)}
                        />

                        {/* Quick Actions */}
                        <ActionsGrid 
                            onSend={() => handleAction('send')}
                            onReceive={() => handleAction('receive')}
                            onSwap={() => handleAction('swap')}
                            onWithdraw={() => handleAction('withdraw')}
                            onDeposit={() => handleAction('fund')}
                            onBuy={() => handleAction('buy')}
                            disabledActions={
                                ['BTC', 'ETH', 'USDT', 'USDC'].some(c => selectedAsset.currency?.startsWith(c)) 
                                ? ['Move In'] 
                                : []
                            }
                        />
                         
                         {/* Wallet List (Breakdown) */}
                         <div>
                            <div className="flex justify-between items-center gap-4 mb-4 flex-wrap">
                                <h3 className="text-lg font-bold">Your Services</h3>
                                <button onClick={() => setShowCreateModal(true)} className="text-purple-400 text-sm hover:text-purple-300 sm:hidden">
                                    + Add New
                                </button>
                            </div>
                            {loading ? (
                                <div className="text-center py-10">
                                    <Loader2 className="animate-spin text-purple-500 mx-auto" size={32} />
                                </div>
                            ) : (
                                <CurrencyList 
                                    wallets={wallets} 
                                    rates={rates} 
                                    onSelect={(curr, net) => setSelectedAsset({ currency: curr, network: net || 'native' })}
                                    showBalances={showBalances}
                                />
                            )}
                        </div>
                    </div>

                    {/* Right: Swap Module + Allocation Chart + Ledger Trail */}
                    <div className="lg:col-span-1">
                        <div className="sticky top-6 space-y-6">
                           <div ref={swapCardRef}>
                                <SwapCard 
                                    initialFromCurrency={selectedAsset.currency} 
                                    initialFromNetwork={selectedAsset.network}
                                    onSuccess={() => {
                                        handleRefresh();
                                        toast.success('Balance updated');
                                    }}
                                />
                           </div>
                           
                           {/* Allocation Chart */}
                           <WalletAllocationChart wallets={wallets} rates={rates} />

                           {/* Ledger Audit Trail */}
                           <LedgerTrail refreshKey={refreshKey} />
                        </div>
                    </div>
                </div>

                {/* Bottom Section: Transaction History */}
                <div className="pb-12">
                     <TransactionHistory 
                        transactions={safeTransactions} 
                        loading={loading}
                     />
                </div>

            </div>

            {/* Modals */}
            {showFundModal && (
                <FundModal 
                    isOpen={showFundModal} 
                    onClose={() => {
                        setShowFundModal(false);
                        setIsBuyMode(false);
                    }} 
                    selectedCurrency={selectedAsset.currency}
                    selectedNetwork={selectedAsset.network}
                    onSuccess={handleRefresh}
                    initialIsPurchase={isBuyMode}
                />
            )}
            {showTransferModal && (
                <TransferModal
                    isOpen={showTransferModal}
                    onClose={() => setShowTransferModal(false)}
                    selectedCurrency={selectedAsset.currency}
                    selectedNetwork={selectedAsset.network}
                    onSuccess={() => {
                        handleRefresh();
                    }}
                />
            )}
            {showWithdrawModal && (
                <WithdrawModal
                    isOpen={showWithdrawModal}
                    onClose={() => setShowWithdrawModal(false)}
                    selectedCurrency={selectedAsset.currency}
                    selectedNetwork={selectedAsset.network}
                    onSuccess={() => {
                        handleRefresh();
                        toast.success('Withdrawal initiated');
                    }}
                />
            )}
            {showReceiveModal && (
                <ReceiveModal
                    isOpen={showReceiveModal}
                    onClose={() => setShowReceiveModal(false)}
                    initialCurrency={selectedAsset.currency}
                    initialNetwork={selectedAsset.network}
                />
            )}

            {/* Create Service Modal */}
             {showCreateModal && (
                <div className="modal-overlay p-4">
                  <div className="modal-content w-full max-w-lg">

                    <button className="modal-close" onClick={() => setShowCreateModal(false)}>
                      <X size={20} />
                    </button>
                    <h2 className="text-xl font-bold mb-6">Add New Service</h2>
                    
                    <div className="grid grid-cols-2 gap-4">
                      {(SUPPORTED_CURRENCIES ?? []).map((curr) => {
                        const exists = (wallets ?? []).some(w => w.currency === curr);
                        if (exists) return null;
                        
                        return (
                          <button
                            key={curr}
                            onClick={() => handleCreateWallet(curr)}
                            className="p-4 border border-gray-700 rounded-xl hover:border-purple-500 hover:bg-gray-800 transition-all flex flex-col items-center gap-2 group"
                          >
                            <span className="text-2xl group-hover:scale-110 transition-transform">{curr === 'BTC' ? '₿' : curr === 'ETH' ? 'Ξ' : '$'}</span>
                            <span className="font-bold text-gray-300 group-hover:text-white">{curr}</span>
                          </button>
                        );
                      })}
                      {wallets.length === SUPPORTED_CURRENCIES.length && (
                          <p className="col-span-2 text-center text-gray-500 py-4">All available services active.</p>
                      )}
                    </div>
                  </div>
                </div>
              )}
        </div>
    );
};

export const WalletPage: React.FC = () => (
    <ErrorBoundary fallback={<div className="p-8 text-center text-red-500 bg-red-500/5 rounded-xl border border-red-500/10">Something went wrong loading your wallet. <button onClick={() => window.location.reload()} className="underline ml-2">Try again</button></div>}>
        <WalletContent />
    </ErrorBoundary>
);

export default WalletPage;

import { useState, useEffect, useRef, useMemo } from 'react';
import { API_URL } from '../../lib/api';
import { useAuth } from '../../context/AuthContext';
import { useSocket } from '../../context/SocketContext';
import { NotificationService } from '../../services/NotificationService';
import { ExportButton } from '../../components/chat/ExportButton';
import {
    MessageSquare,
    Send,
    CheckCheck,
    Check,
    Search,
    Phone,
    Video
} from 'lucide-react';
import type { Message, Conversation } from '../../context/ChatContext';
import { useWebRTC } from '../../context/WebRTCContext';
import { AudioPlayer } from '../../components/chat/AudioPlayer';
import toast from 'react-hot-toast';
import SecureImage from '../../components/common/SecureImage';
import './AdminChat.css';

const getUserFromChat = (chat: Conversation) => {
    return chat.members.find(m => m.role !== 'admin');
};

export const AdminChat = () => {
    const { session, user, isAdmin } = useAuth();
    const { socket, connected } = useSocket();
    const { startCall } = useWebRTC();
    
    // State
    const [chats, setChats] = useState<Conversation[]>([]);
    const [activeChat, setActiveChat] = useState<Conversation | null>(null);
    const [messages, setMessages] = useState<Message[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [statusFilter, setStatusFilter] = useState('');
    const [newMessage, setNewMessage] = useState('');
    const [activeAdmins, setActiveAdmins] = useState<Record<string, string[]>>({});
    const [signedUrls, setSignedUrls] = useState<Record<string, string>>({});

    // Refs
    const messagesEndRef = useRef<HTMLDivElement>(null);

    // Register Admin Listeners
    useEffect(() => {
        if (!socket || !isAdmin || !connected) return;

        console.log('[AdminChat] Registering listeners on shared socket');

        const onReceiveMessage = (msg: Message) => {
            if (msg.sender_id !== user?.id) {
                NotificationService.notifyNewMessage('User', msg.content, msg.conversation_id);
            }
            setMessages(prev => {
                if (msg.conversation_id === activeChat?.id) {
                    return [...prev, msg];
                }
                return prev;
            });
            setChats(prev => prev.map(c =>
                c.id === msg.conversation_id
                    ? { ...c, lastMessage: { content: msg.content, created_at: msg.created_at, sender_id: msg.sender_id } }
                    : c
            ));
        };

        const onNewSupportChat = (chat: Conversation) => {
            NotificationService.notifyNewSupportChat('A User');
            setChats(prev => [chat, ...prev]);
        };

        const onPresenceUpdate = ({ conversationId, adminId, adminName, status }: any) => {
            if (adminId === user?.id) return;
            setActiveAdmins(prev => {
                const current = prev[conversationId] || [];
                if (status === 'viewing') {
                    if (!current.includes(adminName)) {
                        return { ...prev, [conversationId]: [...current, adminName] };
                    }
                } else if (status === 'left') {
                    return { ...prev, [conversationId]: current.filter(n => n !== adminName) };
                }
                return prev;
            });
        };

        const onMessageRead = ({ messageId }: any) => {
            setMessages(prev => prev.map(m => m.id === messageId ? { ...m, read_at: new Date().toISOString() } : m));
        };

        socket.on('receive_message', onReceiveMessage);
        socket.on('new_support_chat', onNewSupportChat);
        socket.on('admin_presence_update', onPresenceUpdate);
        socket.on('message_read', onMessageRead);

        return () => {
            socket.off('receive_message', onReceiveMessage);
            socket.off('new_support_chat', onNewSupportChat);
            socket.off('admin_presence_update', onPresenceUpdate);
            socket.off('message_read', onMessageRead);
        };
    }, [socket, connected, isAdmin, user?.id, activeChat?.id]);

    // Fetch messages when active chat changes
    useEffect(() => {
        if (!activeChat || !session?.access_token) return;

        const fetchMessages = async () => {
            try {
                const res = await fetch(`${API_URL}/api/chat/conversations/${activeChat.id}/messages`, {
                    headers: { 'Authorization': `Bearer ${session.access_token}` }
                });
                if (res.ok) {
                    const data = await res.json() || [];
                    setMessages(data);
                }
            } catch (err) {
                console.error('Failed to fetch messages:', err);
            }
        };

        fetchMessages();
        if (socket && connected) {
            socket.emit('join_room', activeChat.id);
            socket.emit('admin_viewing_chat', {
                conversationId: activeChat.id,
                adminName: user?.user_metadata?.username || user?.email || 'Admin'
            });
        }

        return () => {
            if (socket && connected) {
                socket.emit('admin_leaving_chat', { conversationId: activeChat.id });
            }
        };
    }, [activeChat, session?.access_token, socket, connected, user]);

    // Initial Fetch
    useEffect(() => {
        const fetchChats = async () => {
            if (!session?.access_token) return;
            setLoading(true);
            try {
                const params = new URLSearchParams();
                if (statusFilter) params.append('status', statusFilter);

                const res = await fetch(`${API_URL}/api/admin/support-chats?${params}`, {
                    headers: { 
                        'Authorization': `Bearer ${session.access_token}`,
                        'Accept': 'application/json'
                    }
                });

                if (res.ok) {
                    const data = await res.json() || [];
                    setChats(data);
                }
            } catch (err) {
                console.error('Failed to fetch chats:', err);
            } finally {
                setLoading(false);
            }
        };

        if (isAdmin && session) {
            fetchChats();
        }
    }, [isAdmin, session, statusFilter]);

    // Scroll to bottom
    useEffect(() => {
        messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }, [messages]);

    const sendMessage = async () => {
        if (!newMessage.trim() || !activeChat || !session?.access_token) return;

        const content = newMessage.trim();
        setNewMessage('');

        const tempId = `temp-${Date.now()}`;
        const optimisticMessage: Message = {
            id: tempId,
            conversation_id: activeChat.id,
            sender_id: user?.id || '',
            content,
            created_at: new Date().toISOString(),
            type: 'text'
        };
        setMessages(prev => [...prev, optimisticMessage]);

        try {
            const res = await fetch(`${API_URL}/api/chat/conversations/${activeChat.id}/messages`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${session.access_token}`
                },
                body: JSON.stringify({ content, type: 'text' })
            });

            if (!res.ok) {
                setMessages(prev => prev.filter(m => m.id !== tempId));
            } else {
                const serverMessage = await res.json();
                setMessages(prev => prev.map(m => m.id === tempId ? serverMessage : m));
            }
        } catch (err) {
            console.error('Failed to send message:', err);
            setMessages(prev => prev.filter(m => m.id !== tempId));
        }
    };

    const updateChatStatus = async (chatId: string, status: string) => {
        if (!session?.access_token) return;

        try {
            const res = await fetch(`${API_URL}/api/admin/support-chats/${chatId}/status`, {
                method: 'PUT',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${session.access_token}`
                },
                body: JSON.stringify({ support_status: status })
            });

            if (res.ok) {
                setChats(prev => prev.map(c =>
                    c.id === chatId ? { ...c, support_status: status as any } : c
                ));
                if (activeChat?.id === chatId) {
                    setActiveChat(prev => prev ? { ...prev, support_status: status as any } : null);
                }
            }
        } catch (err) {
            console.error('Failed to update status:', err);
        }
    };

    const handleChatSelect = async (chat: Conversation) => {
        if (!session?.access_token) return;
        try {
            await fetch(`${API_URL}/api/admin/support-chats/${chat.id}/join`, {
                method: 'POST',
                headers: { 'Authorization': `Bearer ${session.access_token}` }
            });
            setActiveChat(chat);
        } catch (err) {
            console.error('Failed to join chat:', err);
            setActiveChat(chat);
        }
    };

    const fetchSignedUrl = async (path: string) => {
        if (signedUrls[path]) return signedUrls[path];
        try {
            const res = await fetch(`${API_URL}/api/media/signed-url?path=${encodeURIComponent(path)}`, {
                headers: { 'Authorization': `Bearer ${session?.access_token}` }
            });
            if (res.ok) {
                const { url } = await res.json();
                setSignedUrls(prev => ({ ...prev, [path]: url }));
                return url;
            }
        } catch (err) {
            console.error('Failed to get signed URL:', err);
        }
        return null;
    };

    const handleCall = (type: 'voice' | 'video') => {
        if (!activeChat || !session?.access_token) return;
        const otherUser = getUserFromChat(activeChat);
        if (!otherUser) {
            toast.error('Could not find user to call');
            return;
        }
        toast.loading(`Starting ${type} call...`, { duration: 2000, id: 'call-start' });
        startCall(otherUser.user_id, activeChat.id, type, otherUser.profile?.username, otherUser.profile?.avatar_url)
            .catch(() => {
                toast.error('Failed to start call. Check camera/mic permissions.');
            });
    };

    const formatTime = (dateStr: string) => {
        return new Date(dateStr).toLocaleTimeString('en-US', {
            hour: '2-digit',
            minute: '2-digit'
        });
    };

    const getSentimentEmoji = (label?: string) => {
        switch (label) {
            case 'positive': return '😊';
            case 'negative': return '😟';
            case 'neutral': return '😐';
            default: return null;
        }
    };

    const filteredChats = useMemo(() => chats.filter(chat => {
        if (!searchTerm) return true;
        const chatMember = getUserFromChat(chat);
        const userProfile = chatMember?.profile;
        return (
            chat.name?.toLowerCase().includes(searchTerm.toLowerCase()) ||
            userProfile?.username?.toLowerCase().includes(searchTerm.toLowerCase())
        );
    }), [chats, searchTerm]);

    if (!isAdmin) return <div className="p-8">Access Denied</div>;

    return (
        <div className="admin-chat-container">
            <div className="admin-chat-sidebar">
                <div className="sidebar-header">
                    <h3>Support Chats</h3>
                    <div className="filters">
                        <select
                            id="support-status-filter"
                            name="statusFilter"
                            value={statusFilter}
                            onChange={(e) => setStatusFilter(e.target.value)}
                            aria-label="Filter chats"
                        >
                            <option value="">All</option>
                            <option value="open">Open</option>
                            <option value="pending">Pending</option>
                            <option value="resolved">Resolved</option>
                        </select>
                    </div>
                </div>

                <div className="search-bar">
                    <Search size={16} />
                    <input
                        id="chat-search-input"
                        name="chatSearch"
                        type="text"
                        placeholder="Search chats..."
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        aria-label="Search"
                    />
                </div>

                <div className="chat-list">
                    {loading ? (
                        <div className="p-4 text-center">Loading...</div>
                    ) : filteredChats.length === 0 ? (
                        <div className="p-8 text-center text-gray-400">
                            <MessageSquare size={32} className="mx-auto mb-2 opacity-20" />
                            <p>No chats found</p>
                        </div>
                    ) : (
                        filteredChats?.map(chat => {
                            const chatMember = getUserFromChat(chat);
                            const userProfile = chatMember?.profile;
                            return (
                                <div
                                    key={chat.id}
                                    className={`chat-item ${activeChat?.id === chat.id ? 'active' : ''}`}
                                    onClick={() => handleChatSelect(chat)}
                                >
                                    <div className="avatar">
                                        {userProfile?.avatar_url ? (
                                            <SecureImage src={userProfile.avatar_url} alt="" fallbackType="profile" />
                                        ) : (
                                            <div className="placeholder">
                                                {userProfile?.username?.[0]?.toUpperCase() || '?'}
                                            </div>
                                        )}
                                        {userProfile?.is_online && <span className="online-dot" />}
                                    </div>
                                    <div className="info">
                                        <div className="header">
                                            <span className="name">{userProfile?.username || chat.name}</span>
                                            <span className={`status-tag ${chat.support_status}`} />
                                        </div>
                                        <p className="preview">
                                            {chat.lastMessage?.content || 'No messages'}
                                        </p>
                                    </div>
                                    {chat.lastMessage && (
                                        <span className="time">{formatTime(chat.lastMessage.created_at)}</span>
                                    )}
                                </div>
                            );
                        })
                    )}
                </div>
            </div>

            <div className="admin-chat-main">
                {activeChat ? (
                    <>
                        <div className="main-header">
                            <div className="user-info">
                                {(() => {
                                    const chatMember = getUserFromChat(activeChat);
                                    const userProfile = chatMember?.profile;
                                    return (
                                        <>
                                            <div className="avatar">
                                                {userProfile?.avatar_url ? (
                                                    <SecureImage src={userProfile.avatar_url} alt="" fallbackType="profile" />
                                                ) : (
                                                    <div className="placeholder">
                                                        {userProfile?.username?.[0]?.toUpperCase() || '?'}
                                                    </div>
                                                )}
                                            </div>
                                            <div>
                                                <h4>{userProfile?.username || activeChat.name}</h4>
                                                <span className={userProfile?.is_online ? 'online' : 'offline'}>
                                                    {userProfile?.is_online ? 'Online' : 'Offline'}
                                                </span>
                                            </div>
                                        </>
                                    );
                                })()}
                            </div>
                            <div className="actions">
                                <div className="flex items-center gap-1 mr-4">
                                    <button 
                                        onClick={() => handleCall('voice')}
                                        className="p-2 text-gray-400 hover:text-green-500 hover:bg-green-500/10 rounded-full transition-all"
                                        title="Voice Call"
                                    >
                                        <Phone size={18} />
                                    </button>
                                    <button 
                                        onClick={() => handleCall('video')}
                                        className="p-2 text-gray-400 hover:text-blue-500 hover:bg-blue-500/10 rounded-full transition-all"
                                        title="Video Call"
                                    >
                                        <Video size={18} />
                                    </button>
                                </div>
                                <select
                                    id="support-status-select"
                                    name="supportStatus"
                                    value={activeChat.support_status}
                                    onChange={(e) => updateChatStatus(activeChat.id, e.target.value)}
                                    className={`status-select ${activeChat.support_status}`}
                                    aria-label="Status"
                                >
                                    <option value="open">Open</option>
                                    <option value="pending">Pending</option>
                                    <option value="resolved">Resolved</option>
                                </select>
                                <ExportButton conversationId={activeChat.id} />
                            </div>
                        </div>

                        {activeAdmins[activeChat.id]?.length > 0 && (
                            <div className="collaboration-banner">
                                <div className="admin-status">
                                    <span className="pulse-dot" />
                                    <span>{activeAdmins[activeChat.id].join(', ')} also viewing</span>
                                </div>
                            </div>
                        )}

                        <div className="chat-messages">
                            {messages?.map(msg => (
                                <div
                                    key={msg.id}
                                    className={`message ${msg.sender_id === user?.id ? 'own' : 'other'}`}
                                >
                                    <div className={`message-content ${msg.sentiment?.label || ''}`}>
                                        {msg.type === 'audio' ? (
                                            <div className="flex flex-col gap-2 min-w-[200px]">
                                                <AudioPlayer 
                                                    path={msg.attachment?.storage_path || ''} 
                                                    fetchUrl={fetchSignedUrl} 
                                                />
                                            </div>
                                        ) : (
                                            <p>{msg.content}</p>
                                        )}
                                        <div className="message-meta">
                                            {msg.sentiment && (
                                                <span className="sentiment-tag" title={msg.sentiment.label}>
                                                    {getSentimentEmoji(msg.sentiment.label)}
                                                </span>
                                            )}
                                            <span className="message-time">{formatTime(msg.created_at)}</span>
                                            {msg.sender_id === user?.id && (
                                                <span className="status ml-1 scale-90 inline-block">
                                                    {msg.read_at ? (
                                                        <CheckCheck size={14} className="text-blue-300" />
                                                    ) : (
                                                        <Check size={14} className="opacity-50" />
                                                    )}
                                                </span>
                                            )}
                                        </div>
                                    </div>
                                </div>
                            ))}
                            <div ref={messagesEndRef} />
                        </div>

                        <div className="chat-input">
                            <input
                                id="chat-reply-input"
                                name="chatReply"
                                type="text"
                                placeholder="Type a response..."
                                value={newMessage}
                                onChange={(e) => setNewMessage(e.target.value)}
                                onKeyPress={(e) => e.key === 'Enter' && sendMessage()}
                                aria-label="Input"
                            />
                            <button onClick={sendMessage} disabled={!newMessage.trim()} aria-label="Send">
                                <Send size={20} />
                            </button>
                        </div>
                    </>
                ) : (
                    <div className="empty-state">
                        <MessageSquare size={48} />
                        <h3>Select a conversation</h3>
                        <p>Pick a chat from the sidebar to start responding to users.</p>
                    </div>
                )}
            </div>


        </div>
    );
};

export default AdminChat;

import { useState, useEffect, useCallback } from 'react';
import { useAuth } from '../../context/AuthContext';
import { toast } from 'react-hot-toast';
import {
    History as HistoryIcon,
    Filter,
    Activity as ActivityIcon,
    ChevronLeft,
    ChevronRight
} from 'lucide-react';
import { API_URL } from '../../lib/api';
import SecureImage from '../../components/common/SecureImage';
import './AuditLogs.css';

interface AuditLog {
    id: string;
    admin_id: string;
    action: string;
    target_type: string;
    target_id: string;
    details: any;
    ip_address: string;
    created_at: string;
    admin: {
        username: string;
        full_name: string;
        avatar_url: string;
    };
}

interface Pagination {
    page: number;
    limit: number;
    total: number;
    totalPages: number;
}

export const AuditLogs = () => {
    const { session } = useAuth();
    const [logs, setLogs] = useState<AuditLog[]>([]);
    const [pagination, setPagination] = useState<Pagination>({
        page: 1,
        limit: 20,
        total: 0,
        totalPages: 0
    });
    const [loading, setLoading] = useState(true);
    const [actionFilter, setActionFilter] = useState('');
    const [targetFilter, setTargetFilter] = useState('');

    const fetchLogs = useCallback(async () => {
        if (!session?.access_token) return;
        setLoading(true);

        try {
            const params = new URLSearchParams({
                page: pagination.page.toString(),
                limit: pagination.limit.toString(),
                ...(actionFilter && { action: actionFilter }),
                ...(targetFilter && { target_type: targetFilter })
            });

            const res = await fetch(`${API_URL}/api/admin/audit-logs?${params}`, {
                headers: { 
                    'Authorization': `Bearer ${session.access_token}`,
                    'Accept': 'application/json'
                }
            });

            if (!res.ok) throw new Error('Failed to fetch audit logs');

            const data = await res.json() || {};
            setLogs(data.logs || []);
            setPagination(data.pagination || {
                page: 1,
                limit: 20,
                total: 0,
                totalPages: 0
            });
        } catch (err) {
            console.error('Failed to fetch audit logs:', err);
            toast.error('Failed to load audit logs');
        } finally {
            setLoading(false);
        }
    }, [session?.access_token, pagination.page, pagination.limit, actionFilter, targetFilter]);

    useEffect(() => {
        fetchLogs();
    }, [fetchLogs]);

    const formatDate = (dateStr: string) => {
        const date = new Date(dateStr);
        return {
            date: date.toLocaleDateString(),
            time: date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
        };
    };

    const getActionBadgeClass = (action: string) => {
        if (action.includes('suspend')) return 'danger';
        if (action.includes('update')) return 'warning';
        if (action.includes('broadcast')) return 'info';
        if (action.includes('join') || action.includes('resolve')) return 'success';
        return 'default';
    };

    const formatActionName = (action: string) => {
        return action.split('_').map(word => word.charAt(0).toUpperCase() + word.slice(1)).join(' ');
    };

    return (
        <div className="audit-logs">
            <div className="page-header">
                <div className="header-title">
                    <HistoryIcon className="header-icon" />
                    <div>
                        <h2>Admin Audit Logs</h2>
                        <p>Track all administrative actions and security events</p>
                    </div>
                </div>
                <div className="stats-mini">
                    <div className="stat-item">
                        <span className="label">Total Events</span>
                        <span className="value">{pagination.total}</span>
                    </div>
                </div>
            </div>

            <div className="filters-bar">
                <div className="filter-group">
                    <ActivityIcon size={18} />
                    <select
                        id="audit-action-filter"
                        name="actionFilter"
                        value={actionFilter}
                        onChange={(e) => {
                            setActionFilter(e.target.value);
                            setPagination(prev => ({ ...prev, page: 1 }));
                        }}
                    >
                        <option value="">All Actions</option>
                        <option value="update_user_status">User Status Updates</option>
                        <option value="update_support_status">Support Status Updates</option>
                        <option value="join_support_chat">Admin Joins</option>
                        <option value="broadcast">Broadcast Messages</option>
                    </select>
                </div>

                <div className="filter-group">
                    <Filter size={18} />
                    <select
                        id="audit-target-filter"
                        name="targetFilter"
                        value={targetFilter}
                        onChange={(e) => {
                            setTargetFilter(e.target.value);
                            setPagination(prev => ({ ...prev, page: 1 }));
                        }}
                    >
                        <option value="">All Targets</option>
                        <option value="user">Users</option>
                        <option value="conversation">Conversations</option>
                        <option value="broadcast">Broadcasts</option>
                    </select>
                </div>
            </div>

            <div className="logs-table-container">
                <table className="logs-table">
                    <thead>
                        <tr>
                            <th>Time</th>
                            <th>Admin</th>
                            <th>Action</th>
                            <th>Target</th>
                            <th>IP Address</th>
                            <th>Details</th>
                        </tr>
                    </thead>
                    <tbody>
                        {loading ? (
                            Array(5).fill(0).map((_, i) => (
                                <tr key={i} className="skeleton-row">
                                    <td colSpan={6}><div className="skeleton-line" /></td>
                                </tr>
                            ))
                        ) : logs.length === 0 ? (
                            <tr>
                                <td colSpan={6} className="empty-row">No audit logs found</td>
                            </tr>
                        ) : (
                            logs?.map(log => {
                                const { date, time } = formatDate(log.created_at);
                                return (
                                    <tr key={log.id}>
                                        <td className="time-cell">
                                            <div className="date">{date}</div>
                                            <div className="time">{time}</div>
                                        </td>
                                        <td className="admin-cell">
                                            <div className="admin-info">
                                                {log.admin?.avatar_url ? (
                                                    <SecureImage src={log.admin.avatar_url} alt="" fallbackType="profile" />
                                                ) : (
                                                    <div className="avatar-placeholder">
                                                        {log.admin?.username?.[0]?.toUpperCase() || 'A'}
                                                    </div>
                                                )}
                                                <span>{log.admin?.username || 'Unknown Admin'}</span>
                                            </div>
                                        </td>
                                        <td>
                                            <span className={`action-badge ${getActionBadgeClass(log.action)}`}>
                                                {formatActionName(log.action)}
                                            </span>
                                        </td>
                                        <td className="target-cell">
                                            <span className="target-type">{log.target_type}</span>
                                            <span className="target-id">{log.target_id.slice(0, 8)}...</span>
                                        </td>
                                        <td className="ip-cell">{log.ip_address || 'Internal'}</td>
                                        <td className="details-cell">
                                            <pre>{JSON.stringify(log.details, null, 2)}</pre>
                                        </td>
                                    </tr>
                                );
                            })
                        )}
                    </tbody>
                </table>
            </div>

            {pagination.totalPages > 1 && (
                <div className="pagination">
                    <button
                        disabled={pagination.page === 1}
                        onClick={() => setPagination(prev => ({ ...prev, page: prev.page - 1 }))}
                    >
                        <ChevronLeft size={18} /> Previous
                    </button>
                    <span>Page {pagination.page} of {pagination.totalPages}</span>
                    <button
                        disabled={pagination.page === pagination.totalPages}
                        onClick={() => setPagination(prev => ({ ...prev, page: prev.page + 1 }))}
                    >
                        Next <ChevronRight size={18} />
                    </button>
                </div>
            )}
        </div>
    );
};

export default AuditLogs;

import { useState, useEffect, useCallback } from 'react';
import { toast } from 'react-hot-toast';
import { useAuth } from '../../context/AuthContext';
import { adService, type Ad } from '../../services/ads';
import { Card } from '../../components/common/Card';
import { Button } from '../../components/common/Button';
import { Check, X, ExternalLink, Loader2, Target } from 'lucide-react';
import SecureImage from '../../components/common/SecureImage';

export const ManageAds = () => {
    const { session } = useAuth();
    const [ads, setAds] = useState<Ad[]>([]);
    const [loading, setLoading] = useState(true);
    const [actionLoading, setActionLoading] = useState<string | null>(null);
    const [activeTab, setActiveTab] = useState<'pending' | 'approved' | 'all'>('pending');

    const fetchAds = useCallback(async () => {
        if (!session?.access_token) return;
        setLoading(true);
        try {
            const statusFilter = activeTab === 'all' ? undefined : activeTab;
            const data = await adService.getAdminAds(statusFilter);
            setAds(data);
        } catch (error) {
            console.error('Failed to fetch ads:', error);
            toast.error('Failed to load ads');
        } finally {
            setLoading(false);
        }
    }, [activeTab, session?.access_token]);

    useEffect(() => {
        fetchAds();
    }, [fetchAds]);

    const handleAction = async (id: string, action: 'approved' | 'rejected') => {
        setActionLoading(id);
        try {
            await adService.updateAdStatus(id, action);
            toast.success(`Ad ${action} successfully`);

            // Optimistic update
            setAds(prev => prev.filter(ad => ad.id !== id));
        } catch (error) {
            console.error(error);
            toast.error('Failed to update status');
        } finally {
            setActionLoading(null);
        }
    };

    const getStatusColor = (status: string) => {
        switch (status) {
            case 'approved': return 'text-green-400 border-green-400/20 bg-green-400/10';
            case 'rejected': return 'text-red-400 border-red-400/20 bg-red-400/10';
            case 'pending': return 'text-yellow-400 border-yellow-400/20 bg-yellow-400/10';
            default: return 'text-gray-400 border-gray-400/20 bg-gray-400/10';
        }
    };

    return (
        <div className="space-y-6">
            <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4">
                <div>
                    <h1 className="text-2xl font-bold flex items-center gap-2">
                        <Target className="text-primary" />
                        Ad Moderation
                    </h1>
                    <p className="text-gray-400">Review and manage user-created advertisements</p>
                </div>

                <div className="flex bg-white/5 p-1 rounded-lg border border-white/10 overflow-x-auto no-scrollbar">
                    <button
                        onClick={() => setActiveTab('pending')}
                        className={`px-4 py-2 rounded-md text-sm font-medium transition-colors whitespace-nowrap ${activeTab === 'pending' ? 'bg-primary text-white' : 'text-gray-400 hover:text-white'}`}
                    >
                        Pending Review
                    </button>
                    <button
                        onClick={() => setActiveTab('approved')}
                        className={`px-4 py-2 rounded-md text-sm font-medium transition-colors whitespace-nowrap ${activeTab === 'approved' ? 'bg-primary text-white' : 'text-gray-400 hover:text-white'}`}
                    >
                        Live Ads
                    </button>
                    <button
                        onClick={() => setActiveTab('all')}
                        className={`px-4 py-2 rounded-md text-sm font-medium transition-colors whitespace-nowrap ${activeTab === 'all' ? 'bg-primary text-white' : 'text-gray-400 hover:text-white'}`}
                    >
                        All History
                    </button>
                </div>
            </div>

            {loading ? (
                <div className="flex justify-center py-20">
                    <Loader2 className="animate-spin text-primary" size={32} />
                </div>
            ) : (
                <div className="grid gap-6">
                    {ads.length === 0 ? (
                        <div className="text-center py-20 text-gray-500">
                            <Target size={48} className="mx-auto mb-4 opacity-20" />
                            <p>No advertisements found in this category.</p>
                        </div>
                    ) : (
                        ads.map((ad: any) => (
                            <Card key={ad.id} variant="glass" className="p-6">
                                <div className="flex flex-col md:flex-row gap-6">
                                    {/* Image Preview */}
                                    <div className="w-full md:w-48 h-32 bg-black/40 rounded-lg flex items-center justify-center overflow-hidden border border-white/10 shrink-0">
                                        {ad.image_url ? (
                                            <SecureImage src={ad.image_url} alt="Ad Preview" className="w-full h-full object-cover" fallbackType="card" />
                                        ) : (
                                            <span className="text-xs text-gray-500">No Image</span>
                                        )}
                                    </div>

                                    {/* Content */}
                                    <div className="flex-1 min-w-0 space-y-3">
                                        <div className="flex flex-col sm:flex-row sm:items-start justify-between gap-4">
                                            <div className="min-w-0">
                                                <h3 className="text-lg font-bold truncate">{ad.title}</h3>
                                                <div className="flex flex-wrap items-center gap-2 mt-1">
                                                    <span className={`text-xs px-2 py-0.5 rounded border ${getStatusColor(ad.status)} capitalize`}>
                                                        {ad.status}
                                                    </span>
                                                    <span className="text-xs text-gray-500 truncate">
                                                        by {ad.profiles?.full_name || ad.profiles?.email || 'Unknown User'}
                                                    </span>
                                                    <span className="text-xs text-gray-500 whitespace-nowrap">
                                                        • {new Date(ad.created_at).toLocaleDateString()}
                                                    </span>
                                                </div>
                                            </div>

                                            {/* Actions */}
                                            {ad.status === 'pending' && (
                                                <div className="flex gap-2">
                                                    <Button
                                                        size="sm"
                                                        className="bg-green-500/20 text-green-400 hover:bg-green-500/30 border-green-500/50 flex-1 sm:flex-none"
                                                        onClick={() => handleAction(ad.id, 'approved')}
                                                        disabled={actionLoading === ad.id}
                                                    >
                                                        {actionLoading === ad.id ? <Loader2 size={16} className="animate-spin mr-1" /> : <Check size={16} className="mr-1" />} Approve
                                                    </Button>
                                                    <Button
                                                        size="sm"
                                                        className="bg-red-500/20 text-red-400 hover:bg-red-500/30 border-red-500/50 flex-1 sm:flex-none"
                                                        onClick={() => handleAction(ad.id, 'rejected')}
                                                        disabled={actionLoading === ad.id}
                                                    >
                                                        {actionLoading === ad.id ? <Loader2 size={16} className="animate-spin mr-1" /> : <X size={16} className="mr-1" />} Reject
                                                    </Button>
                                                </div>
                                            )}
                                            {ad.status === 'approved' && (
                                                <Button
                                                    size="sm"
                                                    className="bg-red-500/20 text-red-400 hover:bg-red-500/30 border-red-500/50 w-full sm:w-auto"
                                                    onClick={() => handleAction(ad.id, 'rejected')}
                                                    disabled={actionLoading === ad.id}
                                                >
                                                    {actionLoading === ad.id ? <Loader2 size={16} className="animate-spin mr-2" /> : null} Revoke
                                                </Button>
                                            )}
                                        </div>

                                        <p className="text-gray-300 break-words">{ad.content}</p>

                                        {ad.link_url && (
                                            <a
                                                href={ad.link_url}
                                                target="_blank"
                                                rel="noopener noreferrer"
                                                className="inline-flex items-center gap-1 text-primary hover:text-primary/80 text-sm"
                                            >
                                                <ExternalLink size={14} /> {ad.link_url}
                                            </a>
                                        )}
                                    </div>
                                </div>
                            </Card>
                        ))
                    )}
                </div>
            )}
        </div>
    );
};

export default ManageAds;

import { useState, useEffect } from 'react';
import { Card } from '../../components/common/Card';
import { Button } from '../../components/common/Button';
import { 
  Users, 
  Copy, 
  Share2, 
  TrendingUp, 
  DollarSign, 
  Award,
  ArrowRight,
  ExternalLink,
  Info
} from 'lucide-react';
import { toast } from 'react-hot-toast';
import { supabase } from '../../lib/supabase';
import { API_URL } from '../../lib/api';

interface Referral {
  id: string;
  created_at: string;
  total_commission_earned: number;
  referred: {
    username: string;
    email: string;
  };
}

export const Affiliates = () => {
  const [loading, setLoading] = useState(true);
  const [referrals, setReferrals] = useState<Referral[]>([]);
  const [stats, setStats] = useState({
    totalEarned: 0,
    totalReferrals: 0,
    commissionRate: 0.1
  });
  const [user, setUser] = useState<any>(null);

  useEffect(() => {
    fetchData();

    if (!user?.id) return;

    // 1. Subscribe to real-time updates for affiliate referrals
    const referralsChannel = supabase
      .channel('affiliate_referrals_updates')
      .on(
        'postgres_changes',
        {
          event: '*',
          schema: 'public',
          table: 'affiliate_referrals',
          filter: `referrer_user_id=eq.${user.id}`
        },
        () => {
          fetchData();
        }
      )
      .subscribe();

    // 2. Subscribe to real-time updates for commission rate in admin_settings
    const settingsChannel = supabase
      .channel('affiliate_settings_updates')
      .on(
        'postgres_changes',
        {
          event: 'UPDATE',
          schema: 'public',
          table: 'admin_settings',
          filter: 'key=eq.affiliate_percentage'
        },
        () => {
          fetchData();
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(referralsChannel);
      supabase.removeChannel(settingsChannel);
    };
  }, [user?.id]);

  const fetchData = async () => {
    try {
      const { data: { user: authUser } } = await supabase.auth.getUser();
      setUser(authUser);

      const token = (await supabase.auth.getSession()).data.session?.access_token;
      
      const response = await fetch(`${API_URL}/api/wallet/affiliates/my-stats`, {
        headers: { 'Authorization': `Bearer ${token}` }
      });
      
      if (response.ok) {
        const data = await response.json();
        setReferrals(data.referrals || []);
        
        const total = (data.referrals || []).reduce((sum: number, r: Referral) => sum + (r.total_commission_earned || 0), 0);
        setStats({
          totalEarned: total,
          totalReferrals: data.referrals?.length || 0,
          commissionRate: data.commissionRate || 0.1
        });
      }
    } catch (err) {
      console.error('Error fetching affiliate data:', err);
    } finally {
      setLoading(false);
    }
  };

  const referralLink = `${import.meta.env.VITE_CLIENT_URL || window.origin}/signup?ref=${user?.id}`;

  const copyToClipboard = () => {
    navigator.clipboard.writeText(referralLink);
    toast.success('Referral link copied to clipboard!');
  };

  return (
    <div className="space-y-8 pb-12 w-full min-w-0">
      <div className="relative overflow-hidden rounded-3xl bg-gradient-to-br from-indigo-700 via-purple-700 to-pink-600 p-6 sm:p-10 md:p-16 shadow-2xl">
