                                />
                            </div>
                            <div className="mt-6 pt-4 border-t border-white/10 flex justify-end flex-wrap">
                                <Button onClick={handleSavePrivacy} loading={saving} disabled={!user} className="w-full sm:w-auto">
                                    <Save size={16} className="mr-2" />
