} from '../../lib/teamsApi';
import type { TeamWithUnreadCount, TeamMember } from '../../types/teams';
import {
  Users,
  Plus,
  MessageSquare,
  UserPlus,
  LogOut,
  Crown,
  Shield,
  Loader2,
  ArrowLeft,
  Camera,
  Trash2,
} from 'lucide-react';
